_REPORT_LAYOUT_SOURCE_BEGIN_TAG = "# >>> REPORT_LAYOUT_DEFAULTS_BEGIN"
_REPORT_LAYOUT_SOURCE_END_TAG = "# <<< REPORT_LAYOUT_DEFAULTS_END"


def _normalize_report_layout_dict(values: Optional[Dict[str, Any]] = None) -> Dict[str, Any]:
    out: Dict[str, Any] = {}
    default_map: Dict[str, Any] = dict(REPORT_LAYOUT_DEFAULTS)
    for k, v in default_map.items():
        out[str(k)] = v
    if isinstance(values, dict):
        for k, v in values.items():
            ks = str(k)
            if ks not in default_map:
                continue
            default_v = default_map.get(ks)
            if isinstance(default_v, (int, float)):
                try:
                    out[ks] = float(v)
                except Exception:
                    pass
            elif isinstance(default_v, str):
                sv = str(pick_first(v, "")).strip()
                if sv:
                    out[ks] = sv
    return out


def _persist_report_layout_defaults_to_source(values: Dict[str, Any]) -> Tuple[bool, str]:
    try:
        merged = _normalize_report_layout_dict(values)
        src_path = Path(__file__).resolve()
        raw = src_path.read_text(encoding="utf-8")
        pattern = re.compile(
            re.escape(_REPORT_LAYOUT_SOURCE_BEGIN_TAG) + r".*?" + re.escape(_REPORT_LAYOUT_SOURCE_END_TAG),
            re.DOTALL,
        )
        if pattern.search(raw) is None:
            return False, "未找到汇报模板默认参数标记块，无法写入源码。"
        dict_txt = json.dumps(merged, ensure_ascii=False, indent=4, sort_keys=True)
        new_block = (
            f"{_REPORT_LAYOUT_SOURCE_BEGIN_TAG}\n"
            f"REPORT_LAYOUT_DEFAULTS: Dict[str, Any] = {dict_txt}\n"
            f"{_REPORT_LAYOUT_SOURCE_END_TAG}"
        )
        updated = pattern.sub(new_block, raw, count=1)
        tmp_path = src_path.with_suffix(src_path.suffix + ".tmp")
        tmp_path.write_text(updated, encoding="utf-8")
        tmp_path.replace(src_path)
        return True, "已写入 app.py 默认参数；重启后仍保持当前设置。"
    except Exception as e:
        return False, f"写入源码失败：{e}"


