CLOSE_RISK_SUM_COLUMNS: List[str] = [
    "已生成",
    "剩余最小",
    "剩余最大",
    "敞口下界",
    "敞口上界",
    "已生成汇总",
    "剩余最小汇总",
    "剩余最大汇总",
    "敞口下界汇总",
    "敞口上界汇总",
]


def build_active_risk_bounds_view(
    b_base: pd.DataFrame,
    inactive_sid_block: set[str],
    rep_gid: Any,
    rep_und: Any,
) -> pd.DataFrame:
    b_struct_only = b_base[
        (b_base["层级"].astype(str) == "STRUCTURE")
        & (~b_base["结构ID"].astype(str).str.strip().isin(inactive_sid_block))
    ].copy()

    group_template = b_base[b_base["层级"].astype(str) == "GROUP"].head(1)
    if not group_template.empty:
        group_row = group_template.iloc[0].to_dict()
    else:
        group_row = {c: "" for c in b_base.columns}
    group_row["层级"] = "GROUP"
    if "策略组编号" in group_row:
        group_row["策略组编号"] = str(rep_gid)
    if "结构ID" in group_row:
        group_row["结构ID"] = "GROUP_SUM"
    if "结构" in group_row:
        group_row["结构"] = "GROUP_SUM"
    if "风险子" in group_row:
        group_row["风险子"] = ""
    if "品种" in group_row:
        group_row["品种"] = "全部品种" if is_all_underlying_scope(rep_und) else str(rep_und)
    if "方向" in group_row:
        group_row["方向"] = "净额"
    if "策略类型" in group_row:
        group_row["策略类型"] = "汇总"
    for c in ["总交易日", "已观察交易日", "剩余交易日"]:
        if c in group_row:
            group_row[c] = "-"

    for c in CLOSE_RISK_SUM_COLUMNS:
        if c in b_struct_only.columns and c in group_row:
            group_row[c] = float(pd.to_numeric(b_struct_only[c], errors="coerce").fillna(0.0).sum())

    if {"已生成", "方向"}.issubset(set(b_struct_only.columns)) and "已生成" in group_row:
        group_row["已生成"] = float(
            b_struct_only.apply(
                lambda rr: float(pick_first(to_float(signed_value_by_direction(rr.get("已生成"), rr.get("方向"))), 0.0) or 0.0),
                axis=1,
            ).sum()
        )
    if {"剩余最小", "剩余最大"}.issubset(set(group_row)):
        rem_lo = float(pick_first(to_float(group_row.get("剩余最小")), 0.0) or 0.0)
        rem_hi = float(pick_first(to_float(group_row.get("剩余最大")), 0.0) or 0.0)
        group_row["剩余最小"] = min(rem_lo, rem_hi)
        group_row["剩余最大"] = max(rem_lo, rem_hi)
    if {"敞口下界", "敞口上界"}.issubset(set(group_row)):
        exp_lo = float(pick_first(to_float(group_row.get("敞口下界")), 0.0) or 0.0)
        exp_hi = float(pick_first(to_float(group_row.get("敞口上界")), 0.0) or 0.0)
        group_row["敞口下界"] = min(exp_lo, exp_hi)
        group_row["敞口上界"] = max(exp_lo, exp_hi)
    for base_col, sum_col in [
        ("已生成", "已生成汇总"),
        ("剩余最小", "剩余最小汇总"),
        ("剩余最大", "剩余最大汇总"),
        ("敞口下界", "敞口下界汇总"),
        ("敞口上界", "敞口上界汇总"),
    ]:
        if base_col in group_row and sum_col in group_row:
            group_row[sum_col] = group_row[base_col]

    return pd.concat([b_struct_only, pd.DataFrame([group_row])], ignore_index=True)


def _fmt_signed_cell(v: Any) -> Any:
    try:
        if v is None or pd.isna(v):
            return ""
    except Exception:
        pass
    if isinstance(v, str):
        sv = v.strip()
        if sv in {"", "-"}:
            return sv
    try:
        return f"{float(v):+,.2f}"
    except Exception:
        return v


def _fmt_int_cell(v: Any) -> Any:
    try:
        if v is None or pd.isna(v):
            return ""
    except Exception:
        pass
    if isinstance(v, str):
        sv = v.strip()
        if sv in {"", "-"}:
            return sv
    try:
        return str(int(round(float(v))))
    except Exception:
        return v


def build_structure_price_maps(structs_df: pd.DataFrame) -> Tuple[Dict[str, float], Dict[str, float]]:
    entry_map: Dict[str, float] = {}
    strike_map: Dict[str, float] = {}
    if structs_df.empty:
        return entry_map, strike_map
    for _, rr in structs_df.iterrows():
        sid_rr = str(rr.get("structure_id", "")).strip()
        if not sid_rr:
            continue
        entry_map[sid_rr] = float(
            pick_first(to_float(rr.get("entry_price")), to_float(rr.get("gen_price")), 0.0)
        )
        strike_map[sid_rr] = float(pick_first(to_float(rr.get("strike_price")), 0.0))
    return entry_map, strike_map


def build_structure_barrier_in_map(structs_df: pd.DataFrame) -> Dict[str, Optional[float]]:
    barrier_map: Dict[str, Optional[float]] = {}
    if structs_df.empty:
        return barrier_map
    for _, rr in structs_df.iterrows():
        sid_rr = str(rr.get("structure_id", "")).strip()
        if not sid_rr:
            continue
        barrier_map[sid_rr] = to_float(rr.get("barrier_in"))
    return barrier_map


def build_structure_barrier_out_map(structs_df: pd.DataFrame) -> Dict[str, Optional[float]]:
    barrier_map: Dict[str, Optional[float]] = {}
    if structs_df.empty:
        return barrier_map
    for _, rr in structs_df.iterrows():
        sid_rr = str(rr.get("structure_id", "")).strip()
        if not sid_rr:
            continue
        barrier_map[sid_rr] = to_float(pick_first(rr.get("barrier_out"), rr.get("barrier_price")))
    return barrier_map


def direction_sign(direction_val: Any) -> Optional[int]:
    d_raw = str(direction_val).strip()
    d_up = d_raw.upper()
    if d_raw in {"累购", "看涨", "多单"} or d_up in {"ACC", "LONG", "BUY"}:
        return 1
    if d_raw in {"累沽", "看跌", "空单"} or d_up in {"DEC", "SHORT", "SELL"}:
        return -1
    return None


def signed_value_by_direction(raw_val: Any, direction_val: Any) -> Any:
    v = to_float(raw_val)
    if v is None:
        return raw_val
    if abs(float(v)) <= 1e-12:
        return 0.0
    sign = direction_sign(direction_val)
    if sign is None:
        return float(v)
    if sign > 0:
        return abs(float(v))
    if sign < 0:
        return -abs(float(v))
    return float(v)


def apply_signed_direction_columns(
    df: pd.DataFrame,
    cols: List[str],
    *,
    direction_col: str = "方向",
    level_col: Optional[str] = None,
    structure_level: str = "STRUCTURE",
) -> pd.DataFrame:
    out = df.copy()
    if out.empty or direction_col not in out.columns:
        return out
    for col in cols:
        if col not in out.columns:
            continue
        if level_col and level_col in out.columns:
            out[col] = out.apply(
                lambda rr, c=col: (
                    float(v) if (v := to_float(rr.get(c))) is not None else rr.get(c)
                )
                if str(rr.get(level_col, "")).upper() != str(structure_level).upper()
                else signed_value_by_direction(rr.get(c), rr.get(direction_col, "")),
                axis=1,
            )
        else:
            out[col] = out.apply(
                lambda rr, c=col: signed_value_by_direction(rr.get(c), rr.get(direction_col, "")),
                axis=1,
            )
    return out


def apply_signed_direction_range_pairs(
    df: pd.DataFrame,
    pairs: List[Tuple[str, str]],
    *,
    direction_col: str = "方向",
    level_col: Optional[str] = None,
    structure_level: str = "STRUCTURE",
) -> pd.DataFrame:
    out = df.copy()
    if out.empty:
        return out

    for lo_col, hi_col in pairs:
        if lo_col not in out.columns or hi_col not in out.columns:
            continue

        def _convert_row(rr: pd.Series, lo_name: str = lo_col, hi_name: str = hi_col) -> pd.Series:
            lo_raw = to_float(rr.get(lo_name))
            hi_raw = to_float(rr.get(hi_name))
            if lo_raw is None and hi_raw is None:
                return pd.Series([rr.get(lo_name), rr.get(hi_name)])

            lo_v = float(lo_raw) if lo_raw is not None else 0.0
            hi_v = float(hi_raw) if hi_raw is not None else 0.0
            # 仅保证区间顺序，避免“最小/最大”倒置。
            return pd.Series([min(lo_v, hi_v), max(lo_v, hi_v)])

        pair_vals = out.apply(_convert_row, axis=1, result_type="expand")
        if isinstance(pair_vals, pd.DataFrame) and pair_vals.shape[1] >= 2:
            out[lo_col] = pair_vals.iloc[:, 0]
            out[hi_col] = pair_vals.iloc[:, 1]

    return out


def direction_display_cn(v: Any) -> str:
    t = str(v).strip()
    if t in {"ACC", "累购", "看涨"}:
        return "看涨"
    if t in {"DEC", "累沽", "看跌"}:
        return "看跌"
    return t


def apply_direction_display_mapping(df: pd.DataFrame, direction_col: str = "方向") -> pd.DataFrame:
    out = df.copy()
    if out.empty or direction_col not in out.columns:
        return out
    out[direction_col] = out[direction_col].map(direction_display_cn).fillna(out[direction_col])
    return out


