def apply_quick_active_structure_filter(
    df: pd.DataFrame,
    quick_mode: str,
    inactive_sid_block: set[str],
    *,
    sid_col: str,
) -> pd.DataFrame:
    base = df.copy()
    if quick_mode == "仅存续结构" and not base.empty:
        base = filter_out_inactive_structures(base, inactive_sid_block, sid_col=sid_col)
    return base


def apply_tab3_active_dates_filter(
    g_df: pd.DataFrame,
    s_df: pd.DataFrame,
    quick_mode: str,
    inactive_sid_block: set[str],
) -> pd.DataFrame:
    out = g_df.copy()
    if quick_mode != "仅存续结构" or out.empty:
        return out
    s_active = filter_out_inactive_structures(s_df, inactive_sid_block, sid_col="结构ID")
    active_dates = set(s_active["日期"].astype(str).dropna().tolist())
    return out[out["日期"].astype(str).isin(active_dates)].copy()


def build_structure_filter_options(s_base: pd.DataFrame) -> List[str]:
    opts = ["全部"]
    if s_base.empty:
        return opts
    if "策略类型" in s_base.columns:
        trs_mask = s_base["策略类型"].astype(str).str.strip().eq("TRS头寸")
        if bool(trs_mask.any()):
            opts.append(TRS_STRUCTURE_FILTER_LABEL)
        detail_src = s_base.loc[~trs_mask, ["结构ID", "结构"]].copy()
    else:
        detail_src = s_base[["结构ID", "结构"]].copy()
    if not detail_src.empty:
        opts += (
            detail_src
            .drop_duplicates()
            .sort_values(["结构ID"])["结构"]
            .astype(str)
            .tolist()
        )
    return opts


def build_underlying_quick_options(df: pd.DataFrame, col: str = "品种") -> List[str]:
    if df.empty or col not in df.columns:
        return []
    vals = (
        df[col]
        .astype(str)
        .str.strip()
        .replace({"None": "", "nan": "", "null": ""})
    )
    return sorted(v for v in vals.dropna().unique().tolist() if str(v).strip())


def sync_multiselect_choices(session_key: str, valid_options: List[str]) -> None:
    if session_key not in st.session_state:
        return
    valid_set = {str(x) for x in valid_options}
    kept = [str(x) for x in st.session_state[session_key] if str(x) in valid_set]
    st.session_state[session_key] = kept


def apply_underlying_quick_filter(df: pd.DataFrame, selected_underlyings: List[str], col: str = "品种") -> pd.DataFrame:
    if df.empty or col not in df.columns:
        return df.copy()
    picks = [str(x).strip() for x in selected_underlyings if str(x).strip()]
    if not picks:
        return df.copy()
    return df[df[col].astype(str).isin(picks)].copy()


def apply_structure_filter_by_label(s_base: pd.DataFrame, selected_label: str) -> pd.DataFrame:
    if selected_label == "全部":
        return s_base.copy()
    if selected_label == TRS_STRUCTURE_FILTER_LABEL:
        if "策略类型" not in s_base.columns:
            return pd.DataFrame(columns=s_base.columns)
        return s_base[s_base["策略类型"].astype(str).str.strip().eq("TRS头寸")].copy()
    sel_sid = str(selected_label).split("-", 1)[0]
    return s_base[s_base["结构ID"].astype(str) == str(sel_sid)].copy()


