def build_row_map(df: pd.DataFrame, key_col: str) -> Dict[str, Dict[str, Any]]:
    """将 DataFrame 按指定主键列映射为 {key: row_dict}。"""
    if df is None or df.empty or key_col not in df.columns:
        return {}
    out: Dict[str, Dict[str, Any]] = {}
    for _, r in df.iterrows():
        out[str(r.get(key_col))] = dict(r)
    return out


def build_structure_id_maps(structs_df: pd.DataFrame, fields: List[str]) -> Dict[str, Dict[str, Any]]:
    """按 structure_id 构建多字段映射字典，缺列自动返回空映射。"""
    out: Dict[str, Dict[str, Any]] = {str(f): {} for f in fields}
    if structs_df is None or structs_df.empty or "structure_id" not in structs_df.columns:
        return out
    sid_series = structs_df["structure_id"].astype(str)
    sid_vals = sid_series.tolist()
    for f in fields:
        f_s = str(f)
        if f_s not in structs_df.columns:
            continue
        col_vals = structs_df[f_s].tolist()
        out[f_s] = {str(sid): v for sid, v in zip(sid_vals, col_vals)}
    return out


def is_all_underlying_scope(v: Any) -> bool:
    s = str(pick_first(v, "")).strip()
    return s in {"全部", "ALL", "全品种", "*"}


def build_close_detail_maps(structs_df: pd.DataFrame, groups_df: pd.DataFrame) -> Dict[str, Dict[str, Any]]:
    sid_maps = build_structure_id_maps(
        structs_df,
        ["name", "risk_party", "kind", "underlying", "strike_price", "barrier_in", "barrier_out", "strategy_code", "strategy"],
    )
    struct_name_map = sid_maps.get("name", {})
    struct_risk_map = sid_maps.get("risk_party", {})
    struct_kind_map = sid_maps.get("kind", {})
    struct_und_map = sid_maps.get("underlying", {})
    struct_strike_map = sid_maps.get("strike_price", {})
    struct_barrier_in_map = sid_maps.get("barrier_in", {})
    struct_barrier_out_map = sid_maps.get("barrier_out", {})
    struct_strategy_code_map = sid_maps.get("strategy_code", {})
    struct_strategy_raw_map = sid_maps.get("strategy", {})
    group_und_map = groups_df.set_index("group_id")["underlying"].to_dict() if not groups_df.empty else {}
    struct_open_px_map: Dict[str, float] = {}
    if not structs_df.empty:
        for _, r in structs_df.iterrows():
            sid = str(r.get("structure_id"))
            struct_open_px_map[sid] = float(pick_first(to_float(r.get("entry_price")), to_float(r.get("gen_price")), 0.0))
    return {
        "struct_name_map": struct_name_map,
        "struct_risk_map": struct_risk_map,
        "struct_kind_map": struct_kind_map,
        "struct_und_map": struct_und_map,
        "struct_strike_map": struct_strike_map,
        "struct_barrier_in_map": struct_barrier_in_map,
        "struct_barrier_out_map": struct_barrier_out_map,
        "struct_strategy_code_map": struct_strategy_code_map,
        "struct_strategy_raw_map": struct_strategy_raw_map,
        "struct_open_px_map": struct_open_px_map,
        "group_und_map": group_und_map,
    }


def build_structure_close_detail_frame(
    close2_df: pd.DataFrame,
    rep_gid: Any,
    rep_und: Any,
    cutoff_d: Optional[date],
    group_name_map: Dict[str, str],
    maps: Dict[str, Dict[str, Any]],
) -> pd.DataFrame:
    if close2_df.empty:
        return pd.DataFrame(columns=CLOSE_DETAIL_COLUMNS)
    struct_name_map = maps.get("struct_name_map", {})
    struct_risk_map = maps.get("struct_risk_map", {})
    struct_kind_map = maps.get("struct_kind_map", {})
    struct_und_map = maps.get("struct_und_map", {})
    struct_strike_map = maps.get("struct_strike_map", {})
    struct_barrier_in_map = maps.get("struct_barrier_in_map", {})
    struct_barrier_out_map = maps.get("struct_barrier_out_map", {})
    struct_strategy_code_map = maps.get("struct_strategy_code_map", {})
    struct_strategy_raw_map = maps.get("struct_strategy_raw_map", {})
    struct_open_px_map = maps.get("struct_open_px_map", {})

    tmp = close2_df.copy()
    tmp = tmp[tmp["group_id"].astype(str) == str(rep_gid)].copy()
    if not is_all_underlying_scope(rep_und):
        tmp = tmp[tmp["underlying"].astype(str) == str(rep_und)].copy()
    if cutoff_d is not None:
        dt_s = pd.to_datetime(tmp["dt"], errors="coerce").dt.date
        tmp = tmp[dt_s <= cutoff_d].copy()
    if tmp.empty:
        return pd.DataFrame(columns=CLOSE_DETAIL_COLUMNS)

    tmp["策略组"] = tmp["group_id"].map(lambda x: f"{x} - {group_name_map.get(x, '')}")
    tmp["结构"] = tmp["structure_id"].map(
        lambda x: (
            "外部-外部平仓"
            if str(x) == "外部"
            else structure_verbose_label(
                x,
                struct_name_map.get(x, ""),
                struct_risk_map.get(x, ""),
                struct_kind_map.get(x, ""),
                struct_und_map.get(x, ""),
                struct_open_px_map.get(str(x), None),
                to_float(struct_strike_map.get(x, None)),
                strategy_value=pick_first(struct_strategy_code_map.get(x, ""), struct_strategy_raw_map.get(x, "")),
                knock_in_price=to_float(struct_barrier_in_map.get(x, None)),
                barrier_price=resolve_display_barrier_price(
                    pick_first(struct_strategy_code_map.get(x, ""), struct_strategy_raw_map.get(x, "")),
                    barrier_out=to_float(struct_barrier_out_map.get(x, None)),
                    barrier_in=to_float(struct_barrier_in_map.get(x, None)),
                    strike_price=to_float(struct_strike_map.get(x, None)),
                ),
            )
        )
    )
    if "close_category" in tmp.columns:
        tmp["平仓类别"] = tmp["close_category"].fillna(STRUCT_CLOSE_CATEGORY).astype(str).str.strip()
        tmp.loc[tmp["平仓类别"] == "", "平仓类别"] = STRUCT_CLOSE_CATEGORY
    else:
        tmp["平仓类别"] = STRUCT_CLOSE_CATEGORY
    manual_closed_structs = set(tmp[tmp["平仓类别"].astype(str) == MANUAL_STRUCT_CLOSE_CATEGORY]["structure_id"].astype(str).tolist())
    tmp["结构状态"] = tmp["structure_id"].astype(str).apply(
        lambda x: "已手动平仓" if (str(x) in manual_closed_structs and str(x) != "外部") else ""
    )
    tmp["方向"] = tmp["side"].map({"BUY": close_side_to_cn("BUY"), "SELL": close_side_to_cn("SELL"), "平仓": "平仓"}).fillna(tmp["side"])
    if "underlying" not in tmp.columns:
        tmp["underlying"] = ""
    tmp["品种"] = tmp["underlying"].astype(str)
    tmp["头寸价格"] = pd.to_numeric(tmp.get("open_price"), errors="coerce")
    tmp["头寸价格"] = tmp["头寸价格"].fillna(tmp["structure_id"].astype(str).map(struct_open_px_map))
    tmp["换月盈亏"] = pd.to_numeric(tmp.get("roll_spread_pnl"), errors="coerce")
    if "quick_batch_id" in tmp.columns:
        roll_mask = tmp["quick_batch_id"].fillna("").astype(str).str.startswith("TRS_ROLL_")
        tmp.loc[~roll_mask, "换月盈亏"] = np.nan
    else:
        tmp["换月盈亏"] = np.nan
    tmp = tmp.rename(columns={"dt": "日期", "qty": "数量", "close_price": "平仓价", "pnl": "平仓盈亏"})
    tmp["现货盈亏"] = 0.0
    tmp["合计盈亏"] = numeric_col(tmp, "平仓盈亏")
    tmp["平仓批次号"] = tmp.get("quick_batch_id", "").fillna("").astype(str)
    tmp["记录类型"] = "结构记录"
    return tmp[CLOSE_DETAIL_COLUMNS].copy()


def build_spot_close_detail_frame(
    spot_match_df: pd.DataFrame,
    rep_gid: Any,
    rep_und: Any,
    cutoff_d: Optional[date],
    group_name_map: Dict[str, str],
    maps: Dict[str, Dict[str, Any]],
) -> pd.DataFrame:
    if spot_match_df.empty:
        return pd.DataFrame(columns=CLOSE_DETAIL_COLUMNS)
    struct_name_map = maps.get("struct_name_map", {})
    struct_risk_map = maps.get("struct_risk_map", {})
    struct_kind_map = maps.get("struct_kind_map", {})
    struct_und_map = maps.get("struct_und_map", {})
    struct_strike_map = maps.get("struct_strike_map", {})
    struct_barrier_in_map = maps.get("struct_barrier_in_map", {})
    struct_barrier_out_map = maps.get("struct_barrier_out_map", {})
    struct_strategy_code_map = maps.get("struct_strategy_code_map", {})
    struct_strategy_raw_map = maps.get("struct_strategy_raw_map", {})
    struct_open_px_map = maps.get("struct_open_px_map", {})
    group_und_map = maps.get("group_und_map", {})

    sm = spot_match_df.copy()
    sm = sm[sm["group_id"].astype(str) == str(rep_gid)].copy()
    if cutoff_d is not None:
        sm_dt = pd.to_datetime(sm.get("match_dt"), errors="coerce").dt.date
        sm = sm[sm_dt <= cutoff_d].copy()
    if sm.empty:
        return pd.DataFrame(columns=CLOSE_DETAIL_COLUMNS)

    if "structure_id" not in sm.columns:
        sm["structure_id"] = ""
    sid_sm = sm["structure_id"].fillna("").astype(str).str.strip()
    sid_und = sid_sm.map(lambda x: str(pick_first(struct_und_map.get(str(x)), ""))).astype(str)
    gid_und = sm["group_id"].astype(str).map(lambda x: str(pick_first(group_und_map.get(str(x)), ""))).astype(str)
    if not is_all_underlying_scope(rep_und):
        mask_rep_und = ((sid_sm != "") & (sid_und == str(rep_und))) | ((sid_sm == "") & (gid_und == str(rep_und)))
        sm = sm[mask_rep_und].copy()
    if sm.empty:
        return pd.DataFrame(columns=CLOSE_DETAIL_COLUMNS)

    sm["策略组"] = sm["group_id"].map(lambda x: f"{x} - {group_name_map.get(x, '')}")

    def _spot_struct_label(sid_val: Any, spot_name_val: Any) -> str:
        sid_s = str(pick_first(sid_val, "")).strip()
        spot_name_s = str(pick_first(spot_name_val, "")).strip()
        if not sid_s:
            return f"现货:{spot_name_s}" if spot_name_s else "纯现货"
        struct_label = structure_verbose_label(
            sid_s,
            struct_name_map.get(sid_s, sid_s),
            struct_risk_map.get(sid_s, ""),
            struct_kind_map.get(sid_s, ""),
            struct_und_map.get(sid_s, ""),
            struct_open_px_map.get(sid_s, None),
            to_float(struct_strike_map.get(sid_s, None)),
            strategy_value=pick_first(struct_strategy_code_map.get(sid_s, ""), struct_strategy_raw_map.get(sid_s, "")),
            knock_in_price=to_float(struct_barrier_in_map.get(sid_s, None)),
            barrier_price=resolve_display_barrier_price(
                pick_first(struct_strategy_code_map.get(sid_s, ""), struct_strategy_raw_map.get(sid_s, "")),
                barrier_out=to_float(struct_barrier_out_map.get(sid_s, None)),
                barrier_in=to_float(struct_barrier_in_map.get(sid_s, None)),
                strike_price=to_float(struct_strike_map.get(sid_s, None)),
            ),
        )
        return f"{spot_name_s}-{struct_label}" if spot_name_s else struct_label

    sm["结构"] = sm.apply(lambda r: _spot_struct_label(r.get("structure_id", ""), r.get("spot_name", "")), axis=1)
    sm["结构状态"] = ""
    sm["平仓类别"] = SPOT_HEDGE_CLOSE_CATEGORY
    sid_sm2 = sm["structure_id"].fillna("").astype(str).str.strip()
    sm["品种"] = sid_sm2.map(lambda x: str(pick_first(struct_und_map.get(str(x)), ""))).astype(str)
    sm.loc[sm["品种"].astype(str).str.strip() == "", "品种"] = sm["group_id"].astype(str).map(
        lambda x: str(pick_first(group_und_map.get(str(x)), ""))
    )
    sm["方向"] = "现货平仓"
    if "match_dt" not in sm.columns:
        sm["match_dt"] = ""
    sm["日期"] = sm["match_dt"].fillna("").astype(str)
    sm["数量"] = numeric_col(sm, "matched_qty")
    sm["头寸价格"] = numeric_col(sm, "spot_buy_avg_price")
    sm["平仓价"] = numeric_col(sm, "spot_sell_price")
    sm["换月盈亏"] = np.nan
    sm["平仓盈亏"] = 0.0
    sm["现货盈亏"] = numeric_col(sm, "spot_pnl")
    sm["合计盈亏"] = sm["现货盈亏"]
    if "close_batch_id" not in sm.columns:
        sm["close_batch_id"] = ""
    sm["平仓批次号"] = sm["close_batch_id"].fillna("").astype(str)
    sm["记录类型"] = "现货记录"
    return sm[CLOSE_DETAIL_COLUMNS].copy()


def build_close_detail_table(
    close2_df: pd.DataFrame,
    spot_match_df: pd.DataFrame,
    rep_gid: Any,
    rep_und: Any,
    rep_date: Any,
    group_name_map: Dict[str, str],
    structs_df: pd.DataFrame,
    groups_df: pd.DataFrame,
) -> pd.DataFrame:
    maps = build_close_detail_maps(structs_df, groups_df)
    try:
        cutoff_d = datetime.strptime(str(rep_date), DATE_FMT).date()
    except Exception:
        cutoff_d = None

    close_frames: List[pd.DataFrame] = []
    struct_frame = build_structure_close_detail_frame(close2_df, rep_gid, rep_und, cutoff_d, group_name_map, maps)
    if not struct_frame.empty:
        close_frames.append(struct_frame)
    spot_frame = build_spot_close_detail_frame(spot_match_df, rep_gid, rep_und, cutoff_d, group_name_map, maps)
    if not spot_frame.empty:
        close_frames.append(spot_frame)
    if close_frames:
        return pd.concat(close_frames, ignore_index=True)
    return pd.DataFrame(columns=CLOSE_DETAIL_COLUMNS)


def pick_first(*vals: Any) -> Any:
    for v in vals:
        if v is None:
            continue
        try:
            if pd.isna(v):
                continue
        except Exception:
            pass
        return v
    return None


def kind_to_signed(kind: str, qty: float) -> float:
    k = str(kind).upper()
    if k == "ACC":
        return +qty
    if k == "DEC":
        return -qty
    raise ValueError(f"Unknown kind: {kind}")


def close_to_signed(side: str, qty: float) -> float:
    s = str(side).upper()
    if s == "BUY":
        return +qty
    if s == "SELL":
        return -qty
    raise ValueError("side must be BUY/SELL")


CLOSE_SIDE_CODE_TO_CN: Dict[str, str] = {"SELL": "卖平仓", "BUY": "买平仓"}
CLOSE_SIDE_CN_TO_CODE: Dict[str, str] = {v: k for k, v in CLOSE_SIDE_CODE_TO_CN.items()}


def default_close_side_code(kind: Any) -> str:
    k = str(kind).upper()
    if k == "ACC":
        return "SELL"
    if k == "DEC":
        return "BUY"
    return "SELL"


def normalize_close_side_code(side_val: Any, default: str = "SELL") -> str:
    dft = str(default).upper()
    if dft not in CLOSE_SIDE_CODE_TO_CN:
        dft = "SELL"
    s = str(side_val or "").strip()
    s_up = s.upper()
    if s_up in CLOSE_SIDE_CODE_TO_CN:
        return s_up
    if s in CLOSE_SIDE_CN_TO_CODE:
        return CLOSE_SIDE_CN_TO_CODE[s]
    return dft


def close_side_to_cn(side_val: Any, default: str = "SELL") -> str:
    code = normalize_close_side_code(side_val, default=default)
    return CLOSE_SIDE_CODE_TO_CN.get(code, CLOSE_SIDE_CODE_TO_CN["SELL"])


def structure_day_pnl(kind: str, qty: float, gen_price: float, settle: float) -> float:
    k = str(kind).upper()
    if k == "ACC":
        return qty * (settle - gen_price)
    if k == "DEC":
        return qty * (gen_price - settle)
    raise ValueError(f"Unknown kind: {kind}")


def calc_close_pnl(kind: str, side: str, qty: float, open_price: float, close_price: float) -> float:
    """
    结构内平仓盈亏计算：
    - ACC（累购）默认平多（SELL）
    - DEC（累沽）默认平空（BUY）
    允许用户手工选反向交易，按对应方向计算。
    """
    k = str(kind).upper()
    s = str(side).upper()
    q = float(qty)
    op = float(open_price)
    cp = float(close_price)
    if k == "ACC":
        return q * (cp - op) if s == "SELL" else q * (op - cp)
    if k == "DEC":
        return q * (op - cp) if s == "BUY" else q * (cp - op)
    raise ValueError(f"Unknown kind: {kind}")


def calc_roll_spread_pnl(kind: str, qty: float, near_price: float, far_price: float) -> float:
    """
    换月价差盈亏口径：
    - 看涨（多头）= 平近开远后的换月成本 = 近月价格 - 远月价格；
    - 看跌（空头）= 平近开远后的换月收益/成本 = 远月价格 - 近月价格。
    """
    k = str(kind).upper()
    q = float(pick_first(to_float(qty), 0.0) or 0.0)
    near_v = float(pick_first(to_float(near_price), 0.0) or 0.0)
    far_v = float(pick_first(to_float(far_price), 0.0) or 0.0)
    if q <= 1e-12:
        return 0.0
    if k == "ACC":
        return q * (near_v - far_v)
    if k == "DEC":
        return q * (far_v - near_v)
    return 0.0


def insert_close_rows(conn: sqlite3.Connection, rows: List[Dict[str, Any]]) -> None:
    if not rows:
        return
    vals = [
        (
            str(r.get("close_id", "")),
            str(r.get("dt", "")),
            str(r.get("group_id", "")),
            str(r.get("structure_id", "")),
            str(r.get("underlying", "")),
            str(r.get("side", "")),
            float(pick_first(r.get("qty"), 0.0)),
            float(pick_first(r.get("open_price"), 0.0)),
            float(pick_first(r.get("close_price"), 0.0)),
            float(pick_first(r.get("pnl"), 0.0)),
            str(pick_first(r.get("roll_target_underlying"), "")),
            pick_first(to_float(r.get("roll_target_price")), None),
            float(pick_first(r.get("roll_spread_pnl"), 0.0)),
            str(pick_first(r.get("close_category"), STRUCT_CLOSE_CATEGORY)),
            str(pick_first(r.get("quick_batch_id"), "")),
            str(pick_first(r.get("source_gen_date"), "")),
            int(pick_first(r.get("is_external"), 0)),
        )
        for r in rows
    ]
    conn.executemany(
        """
        INSERT INTO close_trade2(
            close_id, dt, group_id, structure_id, underlying, side, qty, open_price, close_price, pnl,
            roll_target_underlying, roll_target_price, roll_spread_pnl,
            close_category, quick_batch_id, source_gen_date, is_external
        ) VALUES(?,?,?,?,?,?,?,?,?,?,?,?,?,?,?,?,?)
        """,
        vals,
    )


@st.dialog("批量快速平仓")
def quick_close_dialog(conn: sqlite3.Connection) -> None:
    payload = st.session_state.get("quick_close_payload", [])
    gid = str(st.session_state.get("quick_close_gid", ""))
    open_token = str(st.session_state.get("quick_close_open_token", "0"))
    if not payload or not gid:
        st.info("没有可平仓的选择记录。")
        if st.button("关闭"):
            st.session_state["quick_close_open"] = False
            st.rerun()
        return

    # 对话框级会话键
    dt_key = f"quick_close_dt_text_{gid}_{open_token}"
    edit_state_key = f"quick_close_df_state_{gid}_{open_token}"
    editor_rev_key = f"quick_close_editor_rev_{gid}_{open_token}"
    autofill_key = f"quick_close_autofill_done_{gid}_{open_token}"
    default_px_key = f"quick_close_default_px_{gid}_{open_token}"
    use_uniform_key = f"quick_close_use_uniform_{gid}_{open_token}"
    default_qty_key = f"quick_close_default_qty_{gid}_{open_token}"
    default_qty_applied_key = f"quick_close_default_qty_applied_{gid}_{open_token}"
    pending_confirm_key = f"quick_close_pending_confirm_{gid}_{open_token}"

    def _close_quick_close_dialog() -> None:
        st.session_state["quick_close_open"] = False
        st.session_state.pop("quick_close_payload", None)
        st.session_state.pop("quick_close_open_token", None)
        st.session_state.pop("quick_close_default_dt", None)
        st.session_state.pop(autofill_key, None)
        st.session_state.pop(default_px_key, None)
        st.session_state.pop(use_uniform_key, None)
        st.session_state.pop(default_qty_key, None)
        st.session_state.pop(default_qty_applied_key, None)
        st.session_state.pop(edit_state_key, None)
        st.session_state.pop(editor_rev_key, None)
        st.session_state.pop(dt_key, None)
        st.session_state.pop(pending_confirm_key, None)

    df = pd.DataFrame(payload)
    if not df.empty:
        if "结构" not in df.columns:
            df = add_structure_label_column(
                df,
                id_col="结构ID",
                name_col="结构名称",
                risk_col="风险子",
                out_col="结构",
                kind_col="方向",
            )
    st.caption(f"已选择 {len(df)} 条结构聚合记录")

    # 每次新开批量平仓都使用新的 key，默认回到“当前操作日（今天）”
    dt_key = f"quick_close_dt_text_{gid}_{open_token}"
    if dt_key not in st.session_state:
        default_dt = parse_date_maybe(st.session_state.get("quick_close_default_dt"))
        base_dt = default_dt if default_dt is not None else date.today()
        st.session_state[dt_key] = base_dt.strftime("%Y/%m/%d")
    close_dt_raw = str(st.session_state.get(dt_key, "") or "").strip()
    close_dt_text_in = st.text_input("平仓日期（YYYY/MM/DD）", key=dt_key)
    close_dt_obj_preview = parse_date_maybe(close_dt_text_in)
    if close_dt_obj_preview is not None:
        st.caption(f"解析日期：{cn_date_text(close_dt_obj_preview)}")
    elif close_dt_raw:
        st.caption("日期格式示例：2026/02/26 或 2026-02-26")

    # 用会话态保存编辑中的批量平仓表，避免 data_editor 缓存导致价格/数量回弹。
    edit_state_key = f"quick_close_df_state_{gid}_{open_token}"
    editor_rev_key = f"quick_close_editor_rev_{gid}_{open_token}"
    cols_order = [
        "方向",
        "平仓价格",
        "平仓数量",
        "平仓方向",
        "结构",
        "结构ID",
        "风险子",
        "品种",
        "在库均价",
        "可平数量",
    ]

    def _normalize_quick_close_df(src_df: pd.DataFrame) -> pd.DataFrame:
        if isinstance(src_df, pd.DataFrame):
            work = src_df.copy()
        else:
            work = pd.DataFrame(src_df).copy()
        if "平仓数量" not in work.columns:
            base_qty = work["可平数量"] if "可平数量" in work.columns else pd.Series(0.0, index=work.index)
            work["平仓数量"] = pd.to_numeric(base_qty, errors="coerce").fillna(0.0)
        if "平仓价格" not in work.columns:
            base_px = work["在库均价"] if "在库均价" in work.columns else pd.Series(0.0, index=work.index)
            work["平仓价格"] = pd.to_numeric(base_px, errors="coerce").fillna(0.0)
        if "平仓方向" not in work.columns:
            work["平仓方向"] = ""
        for c in cols_order:
            if c not in work.columns:
                work[c] = ""
        work["平仓价格"] = pd.to_numeric(work["平仓价格"], errors="coerce").fillna(
            pd.to_numeric(work["在库均价"], errors="coerce").fillna(0.0)
        )
        work["平仓数量"] = pd.to_numeric(work["平仓数量"], errors="coerce").fillna(0.0)
        work["可平数量"] = pd.to_numeric(work["可平数量"], errors="coerce").fillna(0.0)
        work["平仓方向"] = work.apply(
            lambda rr: close_side_to_cn(
                rr.get("平仓方向"),
                default=("BUY" if str(rr.get("方向", "")).strip() in {"累沽", "看跌"} else "SELL"),
            ),
            axis=1,
        )
        return work[cols_order].copy()

    edit_df = _normalize_quick_close_df(st.session_state.get(edit_state_key, df))

    if edit_state_key not in st.session_state:
        st.session_state[edit_state_key] = edit_df.copy()
    if editor_rev_key not in st.session_state:
        st.session_state[editor_rev_key] = 0

    # 快速平仓默认价：首行价格自动带出，可选择“保存时统一覆盖”。
    if not st.session_state.get(autofill_key, False):
        if not edit_df.empty:
            first_px = float(pd.to_numeric(edit_df["平仓价格"], errors="coerce").fillna(0.0).iloc[0])
            edit_df["平仓价格"] = first_px
            st.session_state[default_px_key] = first_px
            st.session_state[edit_state_key] = edit_df.copy()
        st.session_state[autofill_key] = True
    if default_px_key not in st.session_state:
        st.session_state[default_px_key] = float(pd.to_numeric(edit_df["平仓价格"], errors="coerce").fillna(0.0).iloc[0]) if not edit_df.empty else 0.0
    default_px = st.number_input("统一平仓价（先改这里，后续行默认联动，可单行覆盖）", key=default_px_key)
    if use_uniform_key not in st.session_state:
        st.session_state[use_uniform_key] = True
    use_uniform = st.checkbox("保存时使用统一平仓价覆盖全部行（推荐）", key=use_uniform_key)
    if use_uniform and not edit_df.empty:
        cur_px = pd.to_numeric(edit_df["平仓价格"], errors="coerce").fillna(0.0)
        if (cur_px - float(default_px)).abs().max() > 1e-12:
            edit_df["平仓价格"] = float(default_px)
            st.session_state[edit_state_key] = edit_df.copy()
            st.session_state[editor_rev_key] = int(st.session_state.get(editor_rev_key, 0)) + 1

    if default_qty_key not in st.session_state:
        if not edit_df.empty:
            st.session_state[default_qty_key] = float(pd.to_numeric(edit_df["平仓数量"], errors="coerce").fillna(0.0).iloc[0])
        else:
            st.session_state[default_qty_key] = 0.0
    uniform_qty = st.number_input(
        "统一平仓数量（首次填充后可分行修改）",
        min_value=0.0,
        step=100.0,
        key=default_qty_key,
    )
    if default_qty_applied_key not in st.session_state:
        st.session_state[default_qty_applied_key] = float(uniform_qty)
    last_applied_uq = float(pick_first(to_float(st.session_state.get(default_qty_applied_key)), 0.0))
    cur_uq = float(uniform_qty)
    if not edit_df.empty and abs(cur_uq - last_applied_uq) > 1e-12:
        fill_df = _normalize_quick_close_df(st.session_state.get(edit_state_key, edit_df))
        uq = float(cur_uq)
        fill_df["平仓数量"] = fill_df["可平数量"].apply(
            lambda x: min(max(0.0, uq), float(pick_first(to_float(x), 0.0)))
        )
        st.session_state[edit_state_key] = fill_df.copy()
        st.session_state[default_qty_applied_key] = float(cur_uq)
        st.session_state[editor_rev_key] = int(st.session_state.get(editor_rev_key, 0)) + 1
        st.rerun()

    editor_key = f"quick_close_editor_{gid}_{open_token}_{int(st.session_state.get(editor_rev_key, 0))}"
    edited = st.data_editor(
        _normalize_quick_close_df(st.session_state.get(edit_state_key, edit_df)),
        hide_index=True,
        width="stretch",
        num_rows="fixed",
        column_config={
            "平仓价格": st.column_config.NumberColumn("平仓价格", format="%.4f"),
            "平仓数量": st.column_config.NumberColumn("平仓数量", format="%.2f"),
            "平仓方向": st.column_config.SelectboxColumn("平仓方向", options=list(CLOSE_SIDE_CN_TO_CODE.keys())),
            "方向": st.column_config.TextColumn("方向", disabled=True),
            "结构": st.column_config.TextColumn("结构详情", disabled=True),
            "结构ID": st.column_config.TextColumn("结构ID", disabled=True),
            "风险子": st.column_config.TextColumn("风险子", disabled=True),
            "品种": st.column_config.TextColumn("品种", disabled=True),
            "在库均价": st.column_config.NumberColumn("在库均价", format="%.4f", disabled=True),
            "可平数量": st.column_config.NumberColumn("可平数量", format="%.2f", disabled=True),
        },
        key=editor_key,
    )
    st.session_state[edit_state_key] = _normalize_quick_close_df(edited)

    flash_key = f"close_flash_msg_{gid}"
    flash_level_key = f"{flash_key}__level"

    b1, b2 = st.columns([1, 1])
    with b1:
        do_save = st.button("保存批量平仓", key=f"quick_close_save_{gid}_{open_token}")
    with b2:
        do_cancel = st.button("取消", key=f"quick_close_cancel_{gid}_{open_token}")

    if do_cancel:
        _close_quick_close_dialog()
        st.rerun()

    if do_save:
        close_dt_obj = parse_date_maybe(close_dt_text_in)
        if close_dt_obj is None:
            st.error("平仓日期格式错误，应为 YYYY/MM/DD 或 YYYY-MM-DD")
            return
        close_dt_text = close_dt_obj.strftime(DATE_FMT)
        if not is_trading_day(close_dt_obj):
            st.error("平仓日期不是交易日")
            return

        # 截止平仓日回算可平仓在库（结构内 FIFO）。
        try:
            struct_chk, _, _ = compute_ledgers_cached(conn, as_of_date=close_dt_text)
            struct_chk = struct_chk[struct_chk["group_id"].astype(str) == str(gid)].copy()
            closes_chk = fetch_closes2(conn)
            closes_chk = closes_chk[
                (closes_chk["group_id"].astype(str) == str(gid))
                & (closes_chk["dt"].astype(str) <= str(close_dt_text))
            ].copy()
            open_chk = build_open_lot_rows(struct_chk, closes_chk, close_dt_text)
        except Exception as e:
            st.error(f"回算可平仓在库失败：{e}")
            return

        batch_id = f"BATCH_{datetime.now().strftime('%Y%m%d%H%M%S')}_{uuid4().hex[:8]}"
        saved_rows = 0
        saved_structs = 0
        saved_qty = 0.0
        saved_pnl = 0.0
        errs: List[str] = []
        pending_insert_rows: List[Dict[str, Any]] = []
        touched_sids: set[str] = set()
        save_df = _normalize_quick_close_df(st.session_state.get(edit_state_key, edited))
        for _, r in save_df.iterrows():
            sid = str(r.get("结构ID", "")).strip()
            row_label = str(r.get("结构", "")).strip() or sid or "未知结构"
            und = str(r.get("品种", "")).strip()
            kind_cn = str(r.get("方向", "")).strip()
            kind_code = KIND_FROM_CN.get(kind_cn, "ACC")
            side = normalize_close_side_code(r.get("平仓方向"), default=default_close_side_code(kind_code))
            can_qty = float(pick_first(to_float(r.get("可平数量")), 0.0))
            qty = float(pick_first(to_float(r.get("平仓数量")), 0.0))
            row_px = float(pick_first(to_float(r.get("平仓价格")), 0.0))
            close_px = float(default_px) if use_uniform else row_px
            if not sid:
                errs.append(f"{row_label} 结构ID为空")
                continue
            if qty <= 0:
                errs.append(f"{row_label} 平仓数量需大于0")
                continue
            if close_px <= 0:
                errs.append(f"{row_label} 平仓价格需大于0")
                continue
            touched_sids.add(sid)
            if can_qty > 0 and qty - can_qty > 1e-12:
                errs.append(f"{row_label} 平仓数量超过可平数量（输入 {qty:.2f}，可平 {can_qty:.2f}）")
                continue
            if open_chk.empty:
                errs.append(f"{row_label} 当前无可平仓在库")
                continue
            sid_lots = open_chk[open_chk["structure_id"].astype(str) == sid].copy()
            sid_lots = sid_lots.sort_values(["date"]).copy()
            if sid_lots.empty:
                errs.append(f"{row_label} 当前无可平仓在库")
                continue
            can_now = float(pd.to_numeric(sid_lots.get("open_qty"), errors="coerce").fillna(0.0).sum())
            reduce_need = structure_close_reduce_qty(kind_code, side, qty)
            if reduce_need <= 1e-12:
                errs.append(f"{row_label} 平仓方向与结构方向不匹配（会加仓）")
                continue
            if reduce_need - can_now > 1e-12:
                errs.append(f"{row_label} 可平不足（输入 {reduce_need:.2f}，当前可平 {can_now:.2f}）")
                continue

            rem = reduce_need
            this_rows = 0
            this_qty = 0.0
            this_pnl = 0.0
            for _, lot in sid_lots.iterrows():
                if rem <= 1e-12:
                    break
                lot_open = float(pd.to_numeric(lot.get("gen_price"), errors="coerce") or 0.0)
                lot_qty = float(pd.to_numeric(lot.get("open_qty"), errors="coerce") or 0.0)
                if lot_qty <= 1e-12:
                    continue
                take = min(rem, lot_qty)
                try:
                    lot_pnl = calc_close_pnl(kind_code, side, take, lot_open, close_px)
                except Exception:
                    errs.append(f"{row_label} 盈亏计算失败")
                    this_rows = 0
                    break
                source_gen_date = str(lot.get("date", "")).strip()
                pending_insert_rows.append(
                    {
                        "close_id": uuid4().hex,
                        "dt": close_dt_text,
                        "group_id": gid,
                        "structure_id": sid,
                        "underlying": und,
                        "side": side,
                        "qty": float(take),
                        "open_price": float(lot_open),
                        "close_price": float(close_px),
                        "pnl": float(lot_pnl),
                        "close_category": STRUCT_CLOSE_CATEGORY,
                        "quick_batch_id": batch_id,
                        "source_gen_date": source_gen_date,
                        "is_external": 0,
                    }
                )
                rem -= take
                this_rows += 1
                this_qty += float(take)
                this_pnl += float(lot_pnl)

            if this_rows > 0 and rem <= 1e-8:
                saved_rows += this_rows
                saved_structs += 1
                saved_qty += this_qty
                saved_pnl += this_pnl
            else:
                errs.append(f"{row_label} 保存失败，请重试")

        if pending_insert_rows:
            ok_no_over, block_msg = validate_no_worse_over_close(
                conn,
                touched_structure_ids=list(touched_sids),
                pending_inserts=pending_insert_rows,
            )
            if not ok_no_over:
                errs.append(block_msg)
                pending_insert_rows = []
                saved_rows = 0
                saved_structs = 0
                saved_qty = 0.0
                saved_pnl = 0.0

        uniq_errs = [str(x).strip() for x in dict.fromkeys(errs) if str(x).strip()]
        err_txt = "；".join(uniq_errs[:5])
        if pending_insert_rows:
            total_qty_for_px = float(sum(float(pick_first(r.get("qty"), 0.0)) for r in pending_insert_rows))
            if use_uniform:
                price_note = f"统一价 {float(default_px):.4f}"
            else:
                close_val = float(
                    sum(float(pick_first(r.get("qty"), 0.0)) * float(pick_first(r.get("close_price"), 0.0)) for r in pending_insert_rows)
                )
                close_wavg = (close_val / total_qty_for_px) if total_qty_for_px > 1e-12 else 0.0
                price_note = f"分行价（加权均价 {close_wavg:.4f}）"
            st.session_state["quick_close_confirm_payload"] = {
                "group_id": str(gid),
                "close_dt": close_dt_text,
                "batch_id": batch_id,
                "rows": pending_insert_rows,
                "touched_structure_ids": sorted([str(x).strip() for x in touched_sids if str(x).strip()]),
                "edit_rows": save_df.to_dict("records"),
                "saved_rows": int(saved_rows),
                "saved_structs": int(saved_structs),
                "saved_qty": float(saved_qty),
                "saved_pnl": float(saved_pnl),
                "price_note": price_note,
                "err_txt": err_txt,
            }
            st.session_state["quick_close_confirm_open"] = True
            _close_quick_close_dialog()
            st.rerun()
        else:
            if err_txt:
                st.session_state[flash_key] = f"批量快速平仓未保存：{err_txt}"
            else:
                st.session_state[flash_key] = "批量快速平仓未保存：未发现有效平仓行（请检查数量、方向、平仓价）"
            st.session_state[flash_level_key] = "warning"
            _close_quick_close_dialog()
            st.rerun()


def _format_confirm_metric_value(val: Any, *, digits: int = 2) -> str:
    if isinstance(val, (int, float)) and not isinstance(val, bool):
        return f"{float(val):,.{digits}f}"
    return str(val)


def render_close_confirm_summary(
    *,
    warning_text: str,
    kv_rows: Optional[List[Tuple[str, Any]]] = None,
    metric_rows: Optional[List[Tuple[str, Any]]] = None,
    detail_df: Optional[pd.DataFrame] = None,
    detail_title: str = "明细预览",
    note_text: str = "",
) -> None:
    """统一平仓二次确认展示：字段值表 + 明细。"""
    st.warning(warning_text)
    rows: List[Dict[str, str]] = []
    if kv_rows:
        for k, v in kv_rows:
            rows.append({"字段": str(k), "值": str(v)})
    if metric_rows:
        for label, value in metric_rows:
            rows.append({"字段": str(label), "值": _format_confirm_metric_value(value)})
    if rows:
        st.dataframe(pd.DataFrame(rows), hide_index=True, width="stretch")
    if detail_df is not None and not detail_df.empty:
        st.caption(detail_title)
        st.dataframe(detail_df, hide_index=True, width="stretch")
    if str(note_text).strip():
        st.info(str(note_text).strip())


@st.dialog("确认批量快速平仓")
def quick_close_confirm_dialog(conn: sqlite3.Connection) -> None:
    payload = st.session_state.get("quick_close_confirm_payload")
    if not isinstance(payload, dict):
        st.info("暂无待确认的批量平仓。")
        if st.button("关闭", key="quick_close_confirm_close_no_payload"):
            st.session_state["quick_close_confirm_open"] = False
            st.rerun()
        return
    gid = str(pick_first(payload.get("group_id"), "")).strip()
    close_flash_key = f"close_flash_msg_{gid}" if gid else "close_flash_msg_"
    close_flash_level_key = f"{close_flash_key}__level"
    prev_df = pd.DataFrame()
    edit_rows = payload.get("edit_rows", [])
    if isinstance(edit_rows, list) and edit_rows:
        try:
            prev_df = pd.DataFrame(edit_rows).copy()
            keep_cols = [c for c in ["结构", "方向", "平仓方向", "平仓数量", "平仓价格"] if c in prev_df.columns]
            if keep_cols:
                prev_df = prev_df[keep_cols].copy()
                prev_df["平仓数量"] = pd.to_numeric(prev_df.get("平仓数量"), errors="coerce").fillna(0.0)
                prev_df["平仓价格"] = pd.to_numeric(prev_df.get("平仓价格"), errors="coerce").fillna(0.0)
            else:
                prev_df = pd.DataFrame()
        except Exception:
            prev_df = pd.DataFrame()

    err_txt_show = str(pick_first(payload.get("err_txt"), "")).strip()
    render_close_confirm_summary(
        warning_text="请确认本次批量平仓信息，确认后将写入系统。",
        kv_rows=[
            ("日期", str(pick_first(payload.get("close_dt"), ""))),
            ("批次", str(pick_first(payload.get("batch_id"), ""))),
        ],
        metric_rows=[
            ("结构数", int(pick_first(payload.get("saved_structs"), 0))),
            ("明细条数", int(pick_first(payload.get("saved_rows"), 0))),
            ("平仓总数量(吨)", float(pick_first(payload.get("saved_qty"), 0.0))),
            ("本次总平仓利润", float(pick_first(payload.get("saved_pnl"), 0.0))),
            ("价格方式", str(pick_first(payload.get("price_note"), "-"))),
        ],
        detail_df=prev_df,
        detail_title="本次批量平仓明细预览",
        note_text=(f"部分结构未纳入本次保存：{err_txt_show}" if err_txt_show else ""),
    )
    b1, b2, b3 = st.columns(3)
    do_confirm = b1.button("确认保存批量平仓", key="quick_close_confirm_save_btn")
    do_back = b2.button("返回继续修改", key="quick_close_confirm_back_btn")
    do_cancel = b3.button("取消并关闭", key="quick_close_confirm_cancel_btn")

    if do_back:
        edit_rows = payload.get("edit_rows")
        if isinstance(edit_rows, list) and gid:
            st.session_state["quick_close_payload"] = edit_rows
            st.session_state["quick_close_gid"] = gid
            st.session_state["quick_close_default_dt"] = str(pick_first(payload.get("close_dt"), ""))
            st.session_state["quick_close_open"] = True
            st.session_state["quick_close_open_token"] = uuid4().hex
        st.session_state["quick_close_confirm_open"] = False
        st.session_state.pop("quick_close_confirm_payload", None)
        st.rerun()
    if do_cancel:
        st.session_state["quick_close_confirm_open"] = False
        st.session_state.pop("quick_close_confirm_payload", None)
        st.rerun()
    if do_confirm:
        rows_to_save = payload.get("rows", [])
        touched_confirm = payload.get("touched_structure_ids", [])
        if not isinstance(rows_to_save, list) or not rows_to_save:
            st.error("待保存明细为空，请返回修改后重试。")
            return
        if not isinstance(touched_confirm, list):
            touched_confirm = []
        ok_no_over, block_msg = validate_no_worse_over_close(
            conn,
            touched_structure_ids=[str(x).strip() for x in touched_confirm if str(x).strip()],
            pending_inserts=rows_to_save,
        )
        if not ok_no_over:
            st.error(block_msg)
            return
        try:
            conn.execute("BEGIN IMMEDIATE")
            insert_close_rows(conn, rows_to_save)
            deleted_struct_ids = cleanup_flat_internal_closed_structures(
                conn,
                group_id=gid,
                structure_ids=[str(x).strip() for x in touched_confirm if str(x).strip()],
                as_of_date=str(pick_first(payload.get("close_dt"), "")).strip(),
                manage_tx=False,
            )
            conn.commit()
        except Exception as exc:
            conn.rollback()
            st.error(format_db_write_error("批量平仓保存", exc))
            return
        close_dt_saved = str(pick_first(payload.get("close_dt"), "")).strip()
        if close_dt_saved and gid:
            st.session_state[f"warehouse_asof_{gid}__pending"] = close_dt_saved
            st.session_state["monitor_gid_global"] = str(gid)
            st.session_state["monitor_date_global"] = close_dt_saved
        base_msg = (
            f"已保存 {int(pick_first(payload.get('saved_structs'), 0))} 个结构、"
            f"{int(pick_first(payload.get('saved_rows'), 0))} 条平仓明细（批次 {str(pick_first(payload.get('batch_id'), ''))}），"
            f"平仓数量 {float(pick_first(payload.get('saved_qty'), 0.0)):,.2f}，"
            f"平仓盈亏 {float(pick_first(payload.get('saved_pnl'), 0.0)):,.2f}"
        )
        if err_txt_show:
            st.session_state[close_flash_key] = (
                f"{base_msg}{format_auto_deleted_structure_suffix(deleted_struct_ids)}；未保存原因：{err_txt_show}"
            )
            st.session_state[close_flash_level_key] = "warning"
        else:
            st.session_state[close_flash_key] = f"{base_msg}{format_auto_deleted_structure_suffix(deleted_struct_ids)}"
            st.session_state[close_flash_level_key] = "success"
        st.session_state["quick_close_confirm_open"] = False
        st.session_state.pop("quick_close_confirm_payload", None)
        st.rerun()


@st.dialog("确认多空对称平仓")
def sym_close_confirm_dialog(
    conn: sqlite3.Connection,
    gid: str,
    pending_key: str,
    open_key: str,
    close_flash_key: str,
    close_flash_level_key: str,
) -> None:
    pending = st.session_state.get(pending_key)
    if not isinstance(pending, dict):
        st.info("暂无待确认的多空对称平仓。")
        if st.button("关闭", key=f"{open_key}_close_no_payload"):
            st.session_state[open_key] = False
            st.rerun()
        return
    render_close_confirm_summary(
        warning_text="请确认本次多空对称平仓信息，确认后将写入系统。",
        kv_rows=[
            ("日期", str(pick_first(pending.get("pair_dt"), ""))),
            ("数量(吨)", f"{float(pick_first(pending.get('pair_qty'), 0.0)):,.2f}"),
            ("价格", f"{float(pick_first(pending.get('pair_px'), 0.0)):,.4f}"),
            ("多头结构", str(pick_first(pending.get("long_label"), pending.get("long_sid"), ""))),
            ("空头结构", str(pick_first(pending.get("short_label"), pending.get("short_sid"), ""))),
        ],
        metric_rows=[
            ("多头平仓利润", float(pick_first(pending.get("pnl_long"), 0.0))),
            ("空头平仓利润", float(pick_first(pending.get("pnl_short"), 0.0))),
            ("本次总平仓利润", float(pick_first(pending.get("pnl_total"), 0.0))),
        ],
    )
    b1, b2, b3 = st.columns(3)
    do_confirm = b1.button("确认保存", key=f"{open_key}_confirm")
    do_back = b2.button("返回继续修改", key=f"{open_key}_back")
    do_cancel = b3.button("取消", key=f"{open_key}_cancel")
    if do_back or do_cancel:
        st.session_state[open_key] = False
        st.session_state.pop(pending_key, None)
        st.rerun()
    if do_confirm:
        rows_to_save = pending.get("rows", [])
        long_sid_p = str(pick_first(pending.get("long_sid"), "")).strip()
        short_sid_p = str(pick_first(pending.get("short_sid"), "")).strip()
        touched_sym = [x for x in [long_sid_p, short_sid_p] if x]
        if not isinstance(rows_to_save, list) or not rows_to_save:
            st.error("待保存明细为空，请返回修改后重试。")
            return
        ok_no_over2, block_msg2 = validate_no_worse_over_close(
            conn,
            touched_structure_ids=touched_sym,
            pending_inserts=rows_to_save,
        )
        if not ok_no_over2:
            st.error(block_msg2)
            return
        try:
            conn.execute("BEGIN IMMEDIATE")
            insert_close_rows(conn, rows_to_save)
            deleted_struct_ids = cleanup_flat_internal_closed_structures(
                conn,
                group_id=gid,
                structure_ids=touched_sym,
                as_of_date=str(pick_first(pending.get("pair_dt"), "")).strip(),
                manage_tx=False,
            )
            conn.commit()
        except Exception as exc:
            conn.rollback()
            st.error(format_db_write_error("多空对称平仓保存", exc))
            return
        pair_dt_saved = str(pick_first(pending.get("pair_dt"), ""))
        if pair_dt_saved:
            st.session_state[f"warehouse_asof_{gid}__pending"] = pair_dt_saved
            st.session_state["monitor_gid_global"] = str(gid)
            st.session_state["monitor_date_global"] = pair_dt_saved
        st.session_state[close_flash_key] = (
            f"已保存多空对称平仓（批次 {str(pick_first(pending.get('batch_id'), ''))}）："
            f"{long_sid_p} 卖平 {float(pick_first(pending.get('pair_qty'), 0.0)):,.2f} 吨，"
            f"{short_sid_p} 买平 {float(pick_first(pending.get('pair_qty'), 0.0)):,.2f} 吨，"
            f"本次总平仓利润 {float(pick_first(pending.get('pnl_total'), 0.0)):,.2f}"
            f"{format_auto_deleted_structure_suffix(deleted_struct_ids)}"
        )
        st.session_state[close_flash_level_key] = "success"
        st.session_state[open_key] = False
        st.session_state.pop(pending_key, None)
        st.rerun()


@st.dialog("确认现货对冲平仓")
def spot_hedge_confirm_dialog(
    conn: sqlite3.Connection,
    gid: str,
    pending_key: str,
    open_key: str,
    close_flash_key: str,
    close_flash_level_key: str,
) -> None:
    pending = st.session_state.get(pending_key)
    if not isinstance(pending, dict):
        st.info("暂无待确认的现货对冲平仓。")
        if st.button("关闭", key=f"{open_key}_close_no_payload"):
            st.session_state[open_key] = False
            st.rerun()
        return

    pure_spot_mode = bool(pending.get("pure_spot_mode"))
    pair_target_label = str(pick_first(pending.get("pair_target_label"), "纯现货")).strip() or "纯现货"
    qty_save = float(pick_first(pending.get("qty"), 0.0))
    spot_name = str(pick_first(pending.get("spot_name"), "")).strip()
    rows_to_save = pending.get("rows", [])
    if not isinstance(rows_to_save, list):
        rows_to_save = []

    detail_df = pd.DataFrame()
    if rows_to_save:
        try:
            detail_df = pd.DataFrame(rows_to_save).copy()
            keep_cols = [c for c in ["structure_id", "side", "qty", "open_price", "close_price", "pnl", "source_gen_date"] if c in detail_df.columns]
            if keep_cols:
                detail_df = detail_df[keep_cols].copy()
                detail_df = detail_df.rename(
                    columns={
                        "structure_id": "结构ID",
                        "side": "平仓方向",
                        "qty": "数量(吨)",
                        "open_price": "开仓价",
                        "close_price": "平仓价",
                        "pnl": "平仓盈亏",
                        "source_gen_date": "来源日期",
                    }
                )
            else:
                detail_df = pd.DataFrame()
        except Exception:
            detail_df = pd.DataFrame()

    render_close_confirm_summary(
        warning_text="请确认本次现货对冲平仓信息，确认后将写入系统。",
        kv_rows=[
            ("日期", str(pick_first(pending.get("dt"), ""))),
            ("操作人", str(pick_first(pending.get("operator"), ""))),
            ("现货头寸", spot_name),
            ("配对对象", pair_target_label),
            ("数量(吨)", f"{qty_save:,.2f}"),
            ("现货买入均价", f"{float(pick_first(pending.get('spot_buy_avg_price'), 0.0)):,.4f}"),
            ("现货卖出价", f"{float(pick_first(pending.get('spot_sell_price'), 0.0)):,.4f}"),
            ("头寸平仓价格", "纯现货模式不适用" if pure_spot_mode else f"{float(pick_first(pending.get('structure_close_price'), 0.0)):,.4f}"),
        ],
        metric_rows=[
            ("现货盈亏", float(pick_first(pending.get("spot_pnl"), 0.0))),
            ("结构盈亏", float(pick_first(pending.get("structure_pnl"), 0.0))),
            ("合计盈亏", float(pick_first(pending.get("total_pnl"), 0.0))),
        ],
        detail_df=detail_df,
        detail_title="结构平仓拆分明细预览",
        note_text=str(pick_first(pending.get("note"), "")),
    )
    b1, b2, b3 = st.columns(3)
    do_confirm = b1.button("确认保存", key=f"{open_key}_confirm")
    do_back = b2.button("返回继续修改", key=f"{open_key}_back")
    do_cancel = b3.button("取消", key=f"{open_key}_cancel")

    if do_back or do_cancel:
        st.session_state[open_key] = False
        st.session_state.pop(pending_key, None)
        st.rerun()

    if do_confirm:
        if not spot_name:
            st.error("现货名称为空，请返回重试。")
            return
        dt_save = str(pick_first(pending.get("dt"), "")).strip()
        if not dt_save:
            st.error("业务日期为空，请返回重试。")
            return
        spot_avail_chk, _ = get_spot_available_snapshot(conn, str(gid), spot_name)
        if qty_save - float(spot_avail_chk) > 1e-12:
            st.error(f"现货可用数量不足（输入 {qty_save:,.2f}，当前可用 {float(spot_avail_chk):,.2f}）")
            return

        structure_id = str(pick_first(pending.get("structure_id"), "")).strip()
        if rows_to_save:
            ok_no_over, block_msg = validate_no_worse_over_close(
                conn,
                touched_structure_ids=[structure_id] if structure_id else [],
                pending_inserts=rows_to_save,
            )
            if not ok_no_over:
                st.error(block_msg)
                return

        batch_id = str(pick_first(pending.get("batch_id"), "")).strip() or f"SPH_{datetime.now().strftime('%Y%m%d%H%M%S')}_{uuid4().hex[:8]}"
        try:
            conn.execute("BEGIN IMMEDIATE")
            if rows_to_save:
                insert_close_rows(conn, rows_to_save)
                deleted_struct_ids = cleanup_flat_internal_closed_structures(
                    conn,
                    group_id=gid,
                    structure_ids=[structure_id] if structure_id else [],
                    as_of_date=dt_save,
                    manage_tx=False,
                )
            else:
                deleted_struct_ids = []
            conn.execute(
                """
                INSERT INTO spot_hedge_match_log(
                    match_id, group_id, match_dt, matched_at, matched_by,
                    spot_name, spot_lot_id, structure_id, structure_kind, structure_side,
                    matched_qty, spot_buy_avg_price, spot_sell_price, spot_cost_amount,
                    spot_pnl, structure_close_price, structure_pnl, total_pnl, close_batch_id, note
                ) VALUES(?,?,?,?,?,?,?,?,?,?,?,?,?,?,?,?,?,?,?,?)
                """,
                (
                    str(pick_first(pending.get("match_id"), "")) or uuid4().hex,
                    str(gid),
                    dt_save,
                    datetime.now().strftime("%Y-%m-%d %H:%M:%S"),
                    str(pick_first(pending.get("operator"), "")).strip(),
                    spot_name,
                    "",
                    structure_id,
                    str(pick_first(pending.get("structure_kind"), "SPOT_ONLY")),
                    str(pick_first(pending.get("structure_side"), "")),
                    round_qty(qty_save),
                    round_price(float(pick_first(pending.get("spot_buy_avg_price"), 0.0))),
                    round_price(float(pick_first(pending.get("spot_sell_price"), 0.0))),
                    round_pnl(float(pick_first(pending.get("spot_cost_amount"), 0.0))),
                    round_pnl(float(pick_first(pending.get("spot_pnl"), 0.0))),
                    round_price(float(pick_first(pending.get("structure_close_price"), 0.0))),
                    round_pnl(float(pick_first(pending.get("structure_pnl"), 0.0))),
                    round_pnl(float(pick_first(pending.get("total_pnl"), 0.0))),
                    batch_id,
                    str(pick_first(pending.get("note"), "")),
                ),
            )
            conn.commit()
        except Exception as exc:
            conn.rollback()
            st.error(format_db_write_error("保存现货对冲平仓", exc))
            return

        st.session_state[f"warehouse_asof_{gid}__pending"] = dt_save
        st.session_state["monitor_gid_global"] = str(gid)
        st.session_state["monitor_date_global"] = dt_save
        st.session_state[close_flash_key] = (
            f"已保存现货对冲平仓（批次 {batch_id}）："
            f"{spot_name} 配对 {pair_target_label} {round_qty(qty_save):,.2f} 吨，"
            f"现货盈亏 {round_pnl(float(pick_first(pending.get('spot_pnl'), 0.0))):,.2f}，"
            f"结构盈亏 {round_pnl(float(pick_first(pending.get('structure_pnl'), 0.0))):,.2f}，"
            f"合计 {round_pnl(float(pick_first(pending.get('total_pnl'), 0.0))):,.2f}"
            f"{format_auto_deleted_structure_suffix(deleted_struct_ids)}"
        )
        st.session_state[close_flash_level_key] = "success"
        st.session_state[open_key] = False
        st.session_state.pop(pending_key, None)
        st.rerun()


@st.dialog("确认现货买入增仓")
def spot_buy_confirm_dialog(
    conn: sqlite3.Connection,
    gid: str,
    pending_key: str,
    open_key: str,
    flash_key: str,
    flash_level_key: str,
) -> None:
    pending = st.session_state.get(pending_key)
    if not isinstance(pending, dict):
        st.info("暂无待确认的现货买入。")
        if st.button("关闭", key=f"{open_key}_close_no_payload"):
            st.session_state[open_key] = False
            st.rerun()
        return

    buy_dt = str(pick_first(pending.get("buy_dt"), "")).strip()
    operator_s = str(pick_first(pending.get("operator"), "")).strip()
    spot_name_s = str(pick_first(pending.get("spot_name"), "")).strip()
    note_s = str(pick_first(pending.get("note"), "")).strip()
    qty_save = float(pick_first(pending.get("qty"), 0.0))
    buy_px_save = float(pick_first(pending.get("buy_price"), 0.0))
    amount_save = round_pnl(qty_save * buy_px_save)

    render_close_confirm_summary(
        warning_text="请确认本次现货买入信息，确认后将写入系统。",
        kv_rows=[
            ("买入日期", buy_dt),
            ("录入人", operator_s),
            ("现货名称", spot_name_s),
            ("备注", note_s),
        ],
        metric_rows=[
            ("数量(吨)", qty_save),
            ("现货买入价格", buy_px_save),
            ("买入总金额", amount_save),
        ],
    )
    b1, b2, b3 = st.columns(3)
    do_confirm = b1.button("确认保存", key=f"{open_key}_confirm")
    do_back = b2.button("返回继续修改", key=f"{open_key}_back")
    do_cancel = b3.button("取消", key=f"{open_key}_cancel")

    if do_back or do_cancel:
        st.session_state[open_key] = False
        st.session_state.pop(pending_key, None)
        st.rerun()

    if do_confirm:
        if not buy_dt:
            st.error("买入日期不能为空")
            return
        if not spot_name_s:
            st.error("现货名称不能为空")
            return
        if qty_save <= 0:
            st.error("数量需大于 0")
            return
        if buy_px_save <= 0:
            st.error("现货买入价格需大于 0")
            return
        now_s = datetime.now().strftime("%Y-%m-%d %H:%M:%S")
        try:
            conn.execute("BEGIN IMMEDIATE")
            conn.execute(
                """
                INSERT INTO spot_position_lot(
                    lot_id, group_id, spot_name, buy_dt, qty, buy_price, note, created_at, created_by
                ) VALUES(?,?,?,?,?,?,?,?,?)
                """,
                (
                    uuid4().hex,
                    str(gid),
                    spot_name_s,
                    buy_dt,
                    round_qty(qty_save),
                    round_price(buy_px_save),
                    note_s,
                    now_s,
                    operator_s,
                ),
            )
            conn.commit()
        except Exception as exc:
            conn.rollback()
            st.error(format_db_write_error("保存现货买入头寸", exc))
            return
        st.session_state[flash_key] = "现货买入头寸已保存"
        st.session_state[flash_level_key] = "success"
        st.session_state[open_key] = False
        st.session_state.pop(pending_key, None)
        st.rerun()


@st.dialog("确认删除现货买入头寸")
def spot_lot_delete_confirm_dialog(
    conn: sqlite3.Connection,
    gid: str,
    pending_key: str,
    open_key: str,
    flash_key: str,
    flash_level_key: str,
) -> None:
    pending = st.session_state.get(pending_key)
    if not isinstance(pending, dict):
        st.info("暂无待确认的删除记录。")
        if st.button("关闭", key=f"{open_key}_close_no_payload"):
            st.session_state[open_key] = False
            st.rerun()
        return

    del_ids_raw = pending.get("delete_ids", [])
    del_ids = [str(x).strip() for x in (del_ids_raw if isinstance(del_ids_raw, list) else []) if str(x).strip()]
    del_rows_raw = pending.get("delete_rows", [])
    del_rows = del_rows_raw if isinstance(del_rows_raw, list) else []
    if not del_ids:
        st.warning("未选择任何可删除头寸。")
        if st.button("返回", key=f"{open_key}_back_no_ids"):
            st.session_state[open_key] = False
            st.session_state.pop(pending_key, None)
            st.rerun()
        return

    del_df = pd.DataFrame(del_rows) if del_rows else pd.DataFrame()
    if not del_df.empty:
        for c in ["数量（吨）"]:
            if c in del_df.columns:
                del_df[c] = pd.to_numeric(del_df[c], errors="coerce").fillna(0.0).round(QTY_DECIMALS)
        for c in ["买入价格"]:
            if c in del_df.columns:
                del_df[c] = pd.to_numeric(del_df[c], errors="coerce").fillna(0.0).round(PRICE_DECIMALS)
    name_list = sorted(
        set(
            [
                str(r.get("现货名称", "")).strip()
                for r in del_rows
                if isinstance(r, dict) and str(r.get("现货名称", "")).strip()
            ]
        )
    )
    qty_sum = 0.0
    if not del_df.empty and "数量（吨）" in del_df.columns:
        qty_sum = float(pd.to_numeric(del_df["数量（吨）"], errors="coerce").fillna(0.0).sum())

    st.warning("请确认删除以下现货买入头寸，删除后不可恢复。")
    m1, m2, m3 = st.columns(3)
    with m1:
        st.metric("删除条数", f"{len(del_ids)}")
    with m2:
        st.metric("涉及现货名称", f"{len(name_list)}")
    with m3:
        st.metric("删除数量合计（吨）", f"{qty_sum:,.2f}")
    if name_list:
        st.caption("现货名称清单：" + "、".join(name_list))
    if not del_df.empty:
        show_cols = [c for c in ["头寸ID", "现货名称", "买入日期", "数量（吨）", "买入价格", "备注", "录入时间", "录入人"] if c in del_df.columns]
        if show_cols:
            st.dataframe(del_df[show_cols], hide_index=True, width="stretch")

    b1, b2, b3 = st.columns(3)
    do_confirm = b1.button("确认删除", key=f"{open_key}_confirm")
    do_back = b2.button("返回继续选择", key=f"{open_key}_back")
    do_cancel = b3.button("取消", key=f"{open_key}_cancel")
    if do_back or do_cancel:
        st.session_state[open_key] = False
        st.session_state.pop(pending_key, None)
        st.rerun()

    if do_confirm:
        lots_all = fetch_spot_lots(conn)
        logs_all = fetch_spot_hedge_logs(conn)
        lots_gid = lots_all[lots_all["group_id"].astype(str) == str(gid)].copy() if not lots_all.empty else pd.DataFrame()
        candidate_lots = lots_gid[~lots_gid["lot_id"].astype(str).isin(del_ids)].copy() if not lots_gid.empty else pd.DataFrame()
        ok_consistent, msg_consistent = validate_spot_lot_snapshot_consistency(
            candidate_lots,
            logs_all,
            group_id=str(gid),
        )
        if not ok_consistent:
            st.error(f"删除失败：{msg_consistent}")
            return
        try:
            conn.execute("BEGIN IMMEDIATE")
            ph = ",".join(["?"] * len(del_ids))
            conn.execute(
                f"DELETE FROM spot_position_lot WHERE group_id=? AND lot_id IN ({ph})",
                tuple([str(gid)] + [str(x) for x in del_ids]),
            )
            conn.commit()
        except Exception as exc:
            conn.rollback()
            st.error(format_db_write_error("删除现货头寸", exc))
            return

        st.session_state[flash_key] = f"已删除 {len(del_ids)} 条现货头寸"
        st.session_state[flash_level_key] = "success"
        st.session_state[open_key] = False
        st.session_state.pop(pending_key, None)
        st.rerun()


@st.dialog("确认按现货名称清零")
def spot_summary_clear_confirm_dialog(
    conn: sqlite3.Connection,
    gid: str,
    pending_key: str,
    open_key: str,
    flash_key: str,
    flash_level_key: str,
) -> None:
    pending = st.session_state.get(pending_key)
    if not isinstance(pending, dict):
        st.info("暂无待确认的清零记录。")
        if st.button("关闭", key=f"{open_key}_close_no_payload"):
            st.session_state[open_key] = False
            st.rerun()
        return

    rows_raw = pending.get("rows", [])
    rows = rows_raw if isinstance(rows_raw, list) else []
    hide_raw = pending.get("hide_spot_names", [])
    hide_spot_names = list(
        dict.fromkeys(
            [
                str(x).strip()
                for x in (hide_raw if isinstance(hide_raw, list) else [])
                if str(x).strip()
            ]
        )
    )
    operator_s = str(pick_first(pending.get("operator"), "")).strip()
    dt_s = str(pick_first(pending.get("dt"), "")).strip()
    note_s = str(pick_first(pending.get("note"), "")).strip()
    batch_id = str(pick_first(pending.get("batch_id"), "")).strip()
    if not batch_id:
        batch_id = f"SPH_{datetime.now().strftime('%Y%m%d%H%M%S')}_{uuid4().hex[:8]}"

    if not rows and not hide_spot_names:
        st.warning("未选择任何可执行记录。")
        if st.button("返回", key=f"{open_key}_back_no_rows"):
            st.session_state[open_key] = False
            st.session_state.pop(pending_key, None)
            st.rerun()
        return

    show_df = pd.DataFrame(rows)
    if not show_df.empty:
        for c in ["可清零数量（吨）"]:
            if c in show_df.columns:
                show_df[c] = pd.to_numeric(show_df[c], errors="coerce").fillna(0.0).round(QTY_DECIMALS)
        for c in ["可用均价", "手工平仓盈亏（默认0）"]:
            if c in show_df.columns:
                show_df[c] = pd.to_numeric(show_df[c], errors="coerce").fillna(0.0)
                if c == "可用均价":
                    show_df[c] = show_df[c].round(PRICE_DECIMALS)
                else:
                    show_df[c] = show_df[c].round(PNL_DECIMALS)
    else:
        show_df = pd.DataFrame(columns=["现货名称", "可清零数量（吨）", "可用均价", "手工平仓盈亏（默认0）"])

    qty_sum = float(pd.to_numeric(show_df.get("可清零数量（吨）"), errors="coerce").fillna(0.0).sum())
    pnl_sum = float(pd.to_numeric(show_df.get("手工平仓盈亏（默认0）"), errors="coerce").fillna(0.0).sum())
    all_name_cnt = len(
        set(show_df.get("现货名称", pd.Series([], dtype=str)).astype(str).str.strip().tolist()) | set(hide_spot_names)
    )

    st.warning("请确认按现货名称执行清零：系统会新增现货平仓流水，不会删除既有平仓记录。")
    st.caption(f"业务日期：{dt_s or '-'}；操作人：{operator_s or '-'}")
    if note_s:
        st.caption(f"备注：{note_s}")
    st.metric("现货名称数", f"{all_name_cnt}")
    st.metric("清零数量合计（吨）", f"{qty_sum:,.2f}")
    st.metric("移出展示（可用为0）", f"{len(hide_spot_names)}")
    st.caption(f"手工平仓盈亏合计：{pnl_sum:,.2f}")
    show_cols = [c for c in ["现货名称", "可清零数量（吨）", "可用均价", "手工平仓盈亏（默认0）"] if c in show_df.columns]
    if show_cols and not show_df.empty:
        st.dataframe(show_df[show_cols], hide_index=True, width="stretch")
    if hide_spot_names:
        st.caption("将从 A.现货头寸汇总移出的现货名称：" + "、".join(hide_spot_names))

    b1, b2, b3 = st.columns(3)
    do_confirm = b1.button("确认清零并记平仓", key=f"{open_key}_confirm")
    do_back = b2.button("返回继续修改", key=f"{open_key}_back")
    do_cancel = b3.button("取消", key=f"{open_key}_cancel")
    if do_back or do_cancel:
        st.session_state[open_key] = False
        st.session_state.pop(pending_key, None)
        st.rerun()

    if do_confirm:
        if not operator_s:
            st.error("操作人不能为空")
            return
        dt_obj = parse_date_maybe(dt_s)
        if dt_obj is None:
            st.error("业务日期格式错误")
            return

        insert_rows: List[Tuple[Any, ...]] = []
        err_msgs: List[str] = []
        now_s = datetime.now().strftime("%Y-%m-%d %H:%M:%S")

        for _, rr in show_df.iterrows():
            spot_name_s = str(pick_first(rr.get("现货名称"), "")).strip()
            qty_req = round_qty(float(pick_first(to_float(rr.get("可清零数量（吨）")), 0.0)))
            pnl_req = round_pnl(float(pick_first(to_float(rr.get("手工平仓盈亏（默认0）")), 0.0)))
            if not spot_name_s or qty_req <= 1e-12:
                continue
            avail_now, avg_now = get_spot_available_snapshot(conn, str(gid), spot_name_s)
            if qty_req - float(avail_now) > 1e-8:
                err_msgs.append(
                    f"{spot_name_s} 可清零数量已变化（请求 {qty_req:,.2f}，当前可用 {float(avail_now):,.2f}），请刷新后重试"
                )
                continue
            avg_now = round_price(float(avg_now))
            spot_cost_amount = round_pnl(float(avg_now) * float(qty_req))
            sell_px = round_price(float(avg_now) + (float(pnl_req) / float(qty_req) if qty_req > 1e-12 else 0.0))
            note_parts = ["A汇总清零"]
            if note_s:
                note_parts.append(note_s)
            row_note = " | ".join(note_parts)
            insert_rows.append(
                (
                    uuid4().hex,
                    str(gid),
                    dt_obj.strftime(DATE_FMT),
                    now_s,
                    operator_s,
                    spot_name_s,
                    "",
                    "",
                    "SPOT_CLEAR",
                    "",
                    float(qty_req),
                    float(avg_now),
                    float(sell_px),
                    float(spot_cost_amount),
                    float(pnl_req),
                    0.0,
                    0.0,
                    float(pnl_req),
                    batch_id,
                    row_note,
                )
            )

        if err_msgs:
            st.error("；".join(err_msgs[:3]))
            return
        hide_rows = [(str(gid), nm, now_s, operator_s, note_s) for nm in hide_spot_names]

        if not insert_rows and not hide_rows:
            st.warning("没有可执行的记录。")
            return

        try:
            conn.execute("BEGIN IMMEDIATE")
            if insert_rows:
                conn.executemany(
                    """
                    INSERT INTO spot_hedge_match_log(
                        match_id, group_id, match_dt, matched_at, matched_by,
                        spot_name, spot_lot_id, structure_id, structure_kind, structure_side,
                        matched_qty, spot_buy_avg_price, spot_sell_price, spot_cost_amount,
                        spot_pnl, structure_close_price, structure_pnl, total_pnl, close_batch_id, note
                    )
                    VALUES(?,?,?,?,?,?,?,?,?,?,?,?,?,?,?,?,?,?,?,?)
                    """,
                    insert_rows,
                )
            if hide_rows:
                conn.executemany(
                    """
                    INSERT OR REPLACE INTO spot_summary_hidden(group_id, spot_name, hidden_at, hidden_by, note)
                    VALUES(?,?,?,?,?)
                    """,
                    hide_rows,
                )
            conn.commit()
        except Exception as exc:
            conn.rollback()
            st.error(format_db_write_error("按现货名称清零", exc))
            return

        done_parts: List[str] = []
        if insert_rows:
            done_parts.append(f"清零 {len(insert_rows)} 条并生成现货平仓流水")
        if hide_rows:
            done_parts.append(f"移出展示 {len(hide_rows)} 个可用为0现货名称")
        st.session_state[flash_key] = "；".join(done_parts) if done_parts else "操作已完成"
        st.session_state[flash_level_key] = "success"
        st.session_state[open_key] = False
        st.session_state.pop(pending_key, None)
        st.rerun()


@st.dialog("确认结构平仓")
def single_close_confirm_dialog(
    conn: sqlite3.Connection,
    gid: str,
    pending_key: str,
    open_key: str,
    close_flash_key: str,
    close_flash_level_key: str,
) -> None:
    pending = st.session_state.get(pending_key)
