def archive_close_record_for_revert(
    conn: sqlite3.Connection,
    row_dict: Dict[str, Any],
    fallback_batch_id: str,
) -> None:
    """写入平仓撤回日志，供后续追溯。"""
    cid = str(pick_first(row_dict.get("close_id"), "")).strip()
    if not cid:
        return
    batch_id = str(pick_first(row_dict.get("quick_batch_id"), "")).strip() or fallback_batch_id
    now_s = datetime.now().strftime("%Y-%m-%d %H:%M:%S")
    payload = {}
    for k, v in row_dict.items():
        try:
            payload[k] = None if pd.isna(v) else v
        except Exception:
            payload[k] = v
    conn.execute(
        """
        INSERT INTO close_revert_log(log_id, reverted_at, batch_id, close_id, payload_json)
        VALUES(?,?,?,?,?)
        """,
        (
            uuid4().hex,
            now_s,
            batch_id,
            cid,
            json.dumps(payload, ensure_ascii=False),
        ),
    )


def structure_close_reduce_qty(kind: str, side: str, qty: float) -> float:
    """结构平仓对在库头寸的减少量（>0 表示减少，<0 表示反向增加）。"""
    k = str(kind).upper()
    s = str(side).upper()
    q = float(qty)
    if q <= 0:
        return 0.0
    if k == "ACC":
        if s == "SELL":
            return q
        if s == "BUY":
            return -q
        return 0.0
    if k == "DEC":
        if s == "BUY":
            return q
        if s == "SELL":
            return -q
        return 0.0
    return 0.0


def build_open_lot_rows(
    wh_cut: pd.DataFrame,
    closes2_group: pd.DataFrame,
    asof_date_s: str,
) -> pd.DataFrame:
    """
    将结构日度生成行（wh_cut）按平仓记录扣减后，得到“在库可平数量”。
    规则：
    - 仅 `generated_qty > 0` 进入仓库；
    - 优先扣减带 `source_gen_date` 的平仓（精准到来源日期）；
    - 其余按结构内 FIFO 扣减。
    """
    if wh_cut.empty:
        return pd.DataFrame()

    base = wh_cut.copy()
    base["generated_qty"] = pd.to_numeric(base["generated_qty"], errors="coerce").fillna(0.0)
    base["gen_price"] = pd.to_numeric(base["gen_price"], errors="coerce").fillna(0.0)
    base["date"] = base["date"].astype(str)

    lot = base[base["generated_qty"] > 1e-12].copy().sort_values(["date", "structure_id"]).reset_index(drop=True)
    if lot.empty:
        return lot
    lot["open_qty"] = lot["generated_qty"]

    sid_kind: Dict[str, str] = {}
    sid_all_idx: Dict[str, List[int]] = {}
    sid_date_idx: Dict[Tuple[str, str], List[int]] = {}
    for i, r in lot.iterrows():
        sid = str(r["structure_id"])
        dt_s = str(r["date"])
        sid_kind.setdefault(sid, str(r.get("kind", "ACC")).upper())
        sid_all_idx.setdefault(sid, []).append(i)
        sid_date_idx.setdefault((sid, dt_s), []).append(i)

    if closes2_group is None or closes2_group.empty:
        return lot

    c = closes2_group.copy()
    c = c[c["group_id"].astype(str) == str(lot.iloc[0]["group_id"])].copy()
    if c.empty:
        return lot
    c["dt"] = c["dt"].astype(str)
    c = c[c["dt"] <= str(asof_date_s)].copy()
    if c.empty:
        return lot

    # 仅“会减少结构在库头寸”的内部平仓类别参与仓库扣减
    if "close_category" in c.columns:
        c["close_category"] = c["close_category"].fillna(STRUCT_CLOSE_CATEGORY).astype(str).str.strip()
        c.loc[c["close_category"] == "", "close_category"] = STRUCT_CLOSE_CATEGORY
        c = c[c["close_category"].isin(INTERNAL_POSITION_CLOSE_CATEGORIES)].copy()
    if "is_external" in c.columns:
        c["is_external"] = pd.to_numeric(c["is_external"], errors="coerce").fillna(0).astype(int)
        c = c[c["is_external"] == 0].copy()
    c = c[c["structure_id"].astype(str) != "外部"].copy()
    c["qty"] = pd.to_numeric(c["qty"], errors="coerce").fillna(0.0)
    c["side"] = c["side"].astype(str).str.upper()
    c = c[(c["qty"] > 1e-12) & (c["side"].isin(["BUY", "SELL"]))].copy()
    if c.empty:
        return lot

    if "close_id" in c.columns:
        c = c.sort_values(["dt", "close_id"])
    else:
        c = c.sort_values(["dt"])

    fifo_need: Dict[str, float] = {}
    eps = 1e-12

    for _, r in c.iterrows():
        sid = str(r.get("structure_id", "")).strip()
        if sid not in sid_all_idx:
            continue
        kind = sid_kind.get(sid, "ACC")
        reduce_qty = structure_close_reduce_qty(kind, str(r.get("side", "")), float(r.get("qty", 0.0)))
        if reduce_qty <= eps:
            continue

        remain = reduce_qty
        src_dt = str(pick_first(r.get("source_gen_date"), "")).strip()
        if src_dt:
            try:
                src_dt = pd.to_datetime(src_dt).strftime(DATE_FMT)
            except Exception:
                src_dt = ""
        if src_dt:
            for i in sid_date_idx.get((sid, src_dt), []):
                if remain <= eps:
                    break
                avail = float(lot.at[i, "open_qty"])
                if avail <= eps:
                    continue
                take = min(avail, remain)
                lot.at[i, "open_qty"] = avail - take
                remain -= take

        if remain > eps:
            fifo_need[sid] = fifo_need.get(sid, 0.0) + remain

    # 未指向来源日期的平仓按 FIFO 扣减
    for sid, need in fifo_need.items():
        rem = float(need)
        if rem <= eps:
            continue
        for i in sid_all_idx.get(sid, []):
            if rem <= eps:
                break
            avail = float(lot.at[i, "open_qty"])
            if avail <= eps:
                continue
            take = min(avail, rem)
            lot.at[i, "open_qty"] = avail - take
            rem -= take

    lot["open_qty"] = pd.to_numeric(lot["open_qty"], errors="coerce").fillna(0.0).clip(lower=0.0)
    # 仓库仅保留“当前仍在库”的记录
    lot = lot[lot["open_qty"] > 1e-12].copy()
    return lot


def filter_internal_position_close_rows(
    close2_df: pd.DataFrame,
    *,
    group_id: Any = None,
    structure_ids: Optional[List[str]] = None,
    as_of_date: Any = None,
) -> pd.DataFrame:
    if close2_df is None or close2_df.empty:
        return pd.DataFrame(columns=["group_id", "structure_id", "dt", "qty", "side", "close_category", "is_external"])

    out = close2_df.copy()
    if group_id is not None and str(group_id).strip():
        out = out[out["group_id"].astype(str) == str(group_id).strip()].copy()
    if structure_ids:
        sid_set = {str(x).strip() for x in structure_ids if str(x).strip()}
        if sid_set:
            out = out[out["structure_id"].astype(str).isin(sid_set)].copy()
    if out.empty:
        return out

    as_of_d = parse_date_maybe(as_of_date)
    if as_of_d is not None and "dt" in out.columns:
        dser = pd.to_datetime(out["dt"], errors="coerce").dt.date
        out = out[dser <= as_of_d].copy()
    if out.empty:
        return out

    if "close_category" in out.columns:
        out["close_category"] = out["close_category"].fillna(STRUCT_CLOSE_CATEGORY).astype(str).str.strip()
        out.loc[out["close_category"] == "", "close_category"] = STRUCT_CLOSE_CATEGORY
    else:
        out["close_category"] = STRUCT_CLOSE_CATEGORY
    out = out[out["close_category"].isin(INTERNAL_POSITION_CLOSE_CATEGORIES)].copy()
    if out.empty:
        return out

    if "is_external" in out.columns:
        out["is_external"] = pd.to_numeric(out["is_external"], errors="coerce").fillna(0).astype(int)
        out = out[out["is_external"] == 0].copy()
    out["structure_id"] = out["structure_id"].fillna("").astype(str).str.strip()
    out = out[out["structure_id"].ne("") & out["structure_id"].ne("外部")].copy()
    if out.empty:
        return out

    out["qty"] = pd.to_numeric(out.get("qty"), errors="coerce").fillna(0.0)
    out = out[out["qty"] > 1e-12].copy()
    return out


def find_flat_internal_closed_structure_ids(
    conn: sqlite3.Connection,
    *,
    group_id: Any = None,
    structure_ids: Optional[List[str]] = None,
    as_of_date: Any = None,
) -> List[str]:
    structs_df = fetch_structures(conn)
    if structs_df.empty:
        return []

    if group_id is not None and str(group_id).strip():
        structs_df = structs_df[structs_df["group_id"].astype(str) == str(group_id).strip()].copy()
    if structure_ids:
        sid_set = {str(x).strip() for x in structure_ids if str(x).strip()}
        if sid_set:
            structs_df = structs_df[structs_df["structure_id"].astype(str).isin(sid_set)].copy()
    if structs_df.empty:
        return []

    close2_df = filter_internal_position_close_rows(
        fetch_closes2(conn),
        group_id=group_id,
        structure_ids=structure_ids,
        as_of_date=as_of_date,
    )
    if close2_df.empty:
        return []

    candidate_sid_set = set(close2_df["structure_id"].astype(str).tolist())
    if not candidate_sid_set:
        return []
    structs_df = structs_df[structs_df["structure_id"].astype(str).isin(candidate_sid_set)].copy()
    if structs_df.empty:
        return []

    as_of_d = parse_date_maybe(as_of_date)
    if as_of_d is None:
        as_of_d = infer_effective_asof_date(fetch_prices(conn), fetch_closes2(conn))
    as_of_s = as_of_d.strftime(DATE_FMT)

    struct_df_asof, _, _ = compute_ledgers_cached(conn, as_of_date=as_of_s)
    if struct_df_asof.empty:
        return []
    if group_id is not None and str(group_id).strip():
        struct_df_asof = struct_df_asof[struct_df_asof["group_id"].astype(str) == str(group_id).strip()].copy()
    struct_df_asof = struct_df_asof[struct_df_asof["structure_id"].astype(str).isin(candidate_sid_set)].copy()
    if struct_df_asof.empty:
        return []

    open_lots = build_open_lot_rows(struct_df_asof, close2_df, as_of_s)
    open_qty_map: Dict[str, float] = {}
    if not open_lots.empty:
        open_qty_map = (
            open_lots.groupby(open_lots["structure_id"].astype(str))["open_qty"]
            .sum()
            .astype(float)
            .to_dict()
        )

    return sorted(
        sid
        for sid in candidate_sid_set
        if float(pick_first(to_float(open_qty_map.get(str(sid))), 0.0) or 0.0) <= 1e-12
    )


def hard_delete_structures_with_related_records(
    conn: sqlite3.Connection,
    *,
    structure_ids: List[str],
    group_id: Any = None,
    manage_tx: bool = False,
) -> List[str]:
    del_ids = [str(x).strip() for x in structure_ids if str(x).strip()]
    if not del_ids:
        return []
    del_ids = list(dict.fromkeys(del_ids))

    gid_s = str(group_id).strip() if group_id is not None and str(group_id).strip() else ""
    try:
        if manage_tx:
            conn.execute("BEGIN IMMEDIATE")

        close_ids: List[str] = []
        for chunk in _chunk_values(del_ids, size=300):
            ph = ",".join(["?"] * len(chunk))
            if gid_s:
                rows = conn.execute(
                    f"SELECT close_id FROM close_trade2 WHERE group_id=? AND structure_id IN ({ph})",
                    tuple([gid_s] + list(chunk)),
                ).fetchall()
            else:
                rows = conn.execute(
                    f"SELECT close_id FROM close_trade2 WHERE structure_id IN ({ph})",
                    tuple(chunk),
                ).fetchall()
            close_ids.extend(str(r[0]).strip() for r in rows if r and str(r[0]).strip())

        close_ids = list(dict.fromkeys(close_ids))
        for chunk in _chunk_values(close_ids, size=300):
            ph = ",".join(["?"] * len(chunk))
            conn.execute(f"DELETE FROM close_revert_log WHERE close_id IN ({ph})", tuple(chunk))

        for chunk in _chunk_values(del_ids, size=300):
            ph = ",".join(["?"] * len(chunk))
            if gid_s:
                conn.execute(
                    f"DELETE FROM spot_hedge_match_log WHERE group_id=? AND structure_id IN ({ph})",
                    tuple([gid_s] + list(chunk)),
                )
                conn.execute(
                    f"DELETE FROM close_trade2 WHERE group_id=? AND structure_id IN ({ph})",
                    tuple([gid_s] + list(chunk)),
                )
                conn.execute(
                    f"DELETE FROM structure WHERE group_id=? AND structure_id IN ({ph})",
                    tuple([gid_s] + list(chunk)),
                )
            else:
                conn.execute(
                    f"DELETE FROM spot_hedge_match_log WHERE structure_id IN ({ph})",
                    tuple(chunk),
                )
                conn.execute(
                    f"DELETE FROM close_trade2 WHERE structure_id IN ({ph})",
                    tuple(chunk),
                )
                conn.execute(
                    f"DELETE FROM structure WHERE structure_id IN ({ph})",
                    tuple(chunk),
                )

        if manage_tx:
            conn.commit()
    except Exception:
        if manage_tx:
            conn.rollback()
        raise
    return del_ids


def cleanup_orphan_structure_link_records(
    conn: sqlite3.Connection,
    *,
    manage_tx: bool = False,
) -> Dict[str, int]:
    result = {
        "close_trade2_deleted": 0,
        "spot_match_deleted": 0,
        "close_revert_deleted": 0,
    }
    structs_df = fetch_structures(conn)
    live_sid_set = (
        set(structs_df["structure_id"].astype(str).str.strip().tolist())
        if (not structs_df.empty and "structure_id" in structs_df.columns)
        else set()
    )

    close2_df = fetch_closes2(conn)
    orphan_close_ids: List[str] = []
    if not close2_df.empty and "structure_id" in close2_df.columns:
        sid_s = close2_df["structure_id"].fillna("").astype(str).str.strip()
        orphan_mask = sid_s.ne("") & sid_s.ne("外部") & (~sid_s.isin(live_sid_set))
        if bool(orphan_mask.any()):
            orphan_close_ids = (
                close2_df.loc[orphan_mask, "close_id"]
                .fillna("")
                .astype(str)
                .str.strip()
                .tolist()
            )
            orphan_close_ids = [x for x in dict.fromkeys(orphan_close_ids) if x]

    spot_match_df = fetch_spot_hedge_logs(conn)
    orphan_match_ids: List[str] = []
    if not spot_match_df.empty and "structure_id" in spot_match_df.columns:
        sid_s = spot_match_df["structure_id"].fillna("").astype(str).str.strip()
        orphan_mask = sid_s.ne("") & sid_s.ne("外部") & (~sid_s.isin(live_sid_set))
        if bool(orphan_mask.any()):
            orphan_match_ids = (
                spot_match_df.loc[orphan_mask, "match_id"]
                .fillna("")
                .astype(str)
                .str.strip()
                .tolist()
            )
            orphan_match_ids = [x for x in dict.fromkeys(orphan_match_ids) if x]

    if not orphan_close_ids and not orphan_match_ids:
        return result

    try:
        if manage_tx:
            conn.execute("BEGIN IMMEDIATE")

        for chunk in _chunk_values(orphan_close_ids, size=300):
            ph = ",".join(["?"] * len(chunk))
            cur = conn.execute(f"DELETE FROM close_revert_log WHERE close_id IN ({ph})", tuple(chunk))
            result["close_revert_deleted"] += int(pick_first(cur.rowcount, 0) or 0)
            cur = conn.execute(f"DELETE FROM close_trade2 WHERE close_id IN ({ph})", tuple(chunk))
            result["close_trade2_deleted"] += int(pick_first(cur.rowcount, 0) or 0)

        for chunk in _chunk_values(orphan_match_ids, size=300):
            ph = ",".join(["?"] * len(chunk))
            cur = conn.execute(f"DELETE FROM spot_hedge_match_log WHERE match_id IN ({ph})", tuple(chunk))
            result["spot_match_deleted"] += int(pick_first(cur.rowcount, 0) or 0)

        if manage_tx:
            conn.commit()
    except Exception:
        if manage_tx:
            conn.rollback()
        raise
    return result


def cleanup_flat_internal_closed_structures(
    conn: sqlite3.Connection,
    *,
    group_id: Any = None,
    structure_ids: Optional[List[str]] = None,
    as_of_date: Any = None,
    manage_tx: bool = False,
) -> List[str]:
    del_ids = find_flat_internal_closed_structure_ids(
        conn,
        group_id=group_id,
        structure_ids=structure_ids,
        as_of_date=as_of_date,
    )
    if not del_ids:
        return []
    return hard_delete_structures_with_related_records(
        conn,
        structure_ids=del_ids,
        group_id=group_id,
        manage_tx=manage_tx,
    )


def format_auto_deleted_structure_suffix(structure_ids: List[str]) -> str:
    ids = [str(x).strip() for x in structure_ids if str(x).strip()]
    if not ids:
        return ""
    if len(ids) <= 3:
        return f"；已自动删除空结构：{', '.join(ids)}"
    preview = ", ".join(ids[:3])
    return f"；已自动删除空结构 {len(ids)} 个（{preview} 等）"


def format_auto_deleted_structure_notice(structure_ids: List[str]) -> str:
    ids = [str(x).strip() for x in structure_ids if str(x).strip()]
    if not ids:
        return ""
    if len(ids) <= 3:
        return f"已自动清理空结构：{', '.join(ids)}"
    preview = ", ".join(ids[:3])
    return f"已自动清理空结构 {len(ids)} 个（{preview} 等）"


