def parse_date_maybe(v: Any) -> Optional[date]:
    if v is None:
        return None
    try:
        return datetime.strptime(str(v), DATE_FMT).date()
    except Exception:
        pass
    try:
        ts = pd.to_datetime(v, errors="coerce")
        if pd.isna(ts):
            return None
        return ts.date()
    except Exception:
        return None


def remaining_natural_days_excl_today(
    as_of_date_v: Any,
    end_date_v: Any,
    *,
    start_date_v: Any = None,
) -> int:
    """剩余自然日口径：不包含 as_of 当天。"""
    as_of_d = parse_date_maybe(as_of_date_v)
    end_d = parse_date_maybe(end_date_v)
    if as_of_d is None or end_d is None:
        return 0
    begin_d = as_of_d + timedelta(days=1)
    start_d = parse_date_maybe(start_date_v)
    if start_d is not None and begin_d < start_d:
        begin_d = start_d
    if end_d < begin_d:
        return 0
    return int((end_d - begin_d).days) + 1


def total_natural_days_inclusive(
    start_date_v: Any,
    end_date_v: Any,
) -> int:
    """总结构自然日口径：起止日都包含在内。"""
    start_d = parse_date_maybe(start_date_v)
    end_d = parse_date_maybe(end_date_v)
    if start_d is None or end_d is None or end_d < start_d:
        return 0
    return int((end_d - start_d).days) + 1


def format_remaining_days_ratio(
    remaining_days_v: Any,
    total_days_v: Any,
) -> str:
    rem_days = to_float(remaining_days_v)
    if rem_days is None or pd.isna(rem_days):
        return "-"
    rem_days_i = max(0, int(round(float(rem_days))))
    total_days = to_float(total_days_v)
    if total_days is None or pd.isna(total_days):
        return str(rem_days_i)
    total_days_i = max(0, int(round(float(total_days))))
    if total_days_i > 0:
        return f"{rem_days_i}/{total_days_i}"
    return str(rem_days_i)


def remaining_trading_days_excl_today(
    as_of_date_v: Any,
    end_date_v: Any,
    *,
    start_date_v: Any = None,
) -> int:
    """剩余交易日口径：不包含 as_of 当天。"""
    as_of_d = parse_date_maybe(as_of_date_v)
    end_d = parse_date_maybe(end_date_v)
    if as_of_d is None or end_d is None:
        return 0
    begin_d = as_of_d + timedelta(days=1)
    start_d = parse_date_maybe(start_date_v)
    if start_d is not None and begin_d < start_d:
        begin_d = start_d
    if end_d < begin_d:
        return 0
    return int(len(trading_days_between(begin_d, end_d)))


def build_manual_close_date_map(
    closes2: Optional[pd.DataFrame],
    *,
    group_id: Optional[str] = None,
    as_of_date: Optional[date] = None,
) -> Dict[str, date]:
    out: Dict[str, date] = {}
    if closes2 is None or closes2.empty or "close_category" not in closes2.columns:
        return out
    cat_s = closes2["close_category"].astype(str).str.strip()
    df = closes2[cat_s == MANUAL_STRUCT_CLOSE_CATEGORY].copy()
    if df.empty:
        return out
    if group_id is not None and "group_id" in df.columns:
        df = df[df["group_id"].astype(str) == str(group_id)].copy()
    if df.empty:
        return out
    if as_of_date is not None and "dt" in df.columns:
        dser = pd.to_datetime(df["dt"], errors="coerce").dt.date
        df = df[dser <= as_of_date].copy()
    for _, r in df.iterrows():
        sid = str(r.get("structure_id", "")).strip()
        if not sid or sid == "外部":
            continue
        d = parse_date_maybe(r.get("dt"))
        if d is None:
            continue
        prev = out.get(sid)
        if prev is None or d < prev:
            out[sid] = d
    return out


def build_melt_date_map(
    struct_rows: Optional[pd.DataFrame],
    *,
    group_id: Optional[str] = None,
    as_of_date: Optional[date] = None,
) -> Dict[str, date]:
    out: Dict[str, date] = {}
    if struct_rows is None or struct_rows.empty:
        return out
    need_cols = {"structure_id", "status", "date"}
    if not need_cols.issubset(set(struct_rows.columns)):
        return out
    df = struct_rows.copy()
    if group_id is not None and "group_id" in df.columns:
        df = df[df["group_id"].astype(str) == str(group_id)].copy()
    if df.empty:
        return out
    if as_of_date is not None:
        dser = pd.to_datetime(df["date"], errors="coerce").dt.date
        df = df[dser <= as_of_date].copy()
    if df.empty:
        return out
    # 安全气囊敲入转线性、雪球敲出/折价转期货均按“终止结构”处理。
    df = df[df["status"].astype(str).str.contains("敲出熔断|敲入转线性|雪球敲出|雪球折价转期货", na=False)].copy()
    for _, r in df.iterrows():
        sid = str(r.get("structure_id", "")).strip()
        if not sid:
            continue
        d = parse_date_maybe(r.get("date"))
        if d is None:
            continue
        prev = out.get(sid)
        if prev is None or d < prev:
            out[sid] = d
    return out


def get_termination_state_date(
    sid: str,
    manual_map: Dict[str, date],
    melt_map: Dict[str, date],
) -> Tuple[str, str]:
    sid_s = str(sid).strip()
    manual_d = manual_map.get(sid_s)
    melt_d = melt_map.get(sid_s)
    if manual_d is not None and melt_d is not None:
        if manual_d <= melt_d:
            return "已手动终结", manual_d.strftime(DATE_FMT)
        return "敲出熔断终止", melt_d.strftime(DATE_FMT)
    if manual_d is not None:
        return "已手动终结", manual_d.strftime(DATE_FMT)
    if melt_d is not None:
        return "敲出熔断终止", melt_d.strftime(DATE_FMT)
    return "", ""


def infer_effective_asof_date(
    prices: Optional[pd.DataFrame] = None,
    closes2: Optional[pd.DataFrame] = None,
    fallback: Optional[date] = None,
) -> date:
    dts: List[date] = []
    if fallback is not None:
        dts.append(fallback)
    if prices is not None and not prices.empty and "dt" in prices.columns:
        for v in pd.to_datetime(prices["dt"], errors="coerce").dt.date.tolist():
            if isinstance(v, date):
                dts.append(v)
    if closes2 is not None and not closes2.empty and "dt" in closes2.columns:
        for v in pd.to_datetime(closes2["dt"], errors="coerce").dt.date.tolist():
            if isinstance(v, date):
                dts.append(v)
    if dts:
        return max(dts)
    return date.today()


def normalize_close2_frame(df: Optional[pd.DataFrame]) -> pd.DataFrame:
    defaults: Dict[str, Any] = {
        "close_id": "",
        "dt": "",
        "group_id": "",
        "structure_id": "",
        "underlying": "",
        "side": "",
        "qty": 0.0,
        "open_price": 0.0,
        "close_price": 0.0,
        "pnl": 0.0,
        "roll_target_underlying": "",
        "roll_target_price": None,
        "roll_spread_pnl": 0.0,
        "close_category": STRUCT_CLOSE_CATEGORY,
        "quick_batch_id": "",
        "source_gen_date": "",
        "is_external": 0,
    }
    out = pd.DataFrame() if df is None else df.copy()
    for c, d in defaults.items():
        if c not in out.columns:
            out[c] = d
    for c in [
        "close_id",
        "dt",
        "group_id",
        "structure_id",
        "underlying",
        "side",
        "roll_target_underlying",
        "close_category",
        "quick_batch_id",
        "source_gen_date",
    ]:
        out[c] = out[c].astype(str)
    for c in ["qty", "open_price", "close_price", "pnl", "roll_spread_pnl"]:
        out[c] = pd.to_numeric(out[c], errors="coerce").fillna(0.0)
    out["roll_target_price"] = pd.to_numeric(out["roll_target_price"], errors="coerce")
    out["is_external"] = pd.to_numeric(out["is_external"], errors="coerce").fillna(0).astype(int)
    return out[list(defaults.keys())].copy()


def build_close2_candidate_frame(
    conn: sqlite3.Connection,
    *,
    pending_inserts: Optional[List[Dict[str, Any]]] = None,
    pending_updates: Optional[List[Dict[str, Any]]] = None,
    pending_delete_ids: Optional[List[str]] = None,
) -> pd.DataFrame:
    base = normalize_close2_frame(fetch_closes2(conn))
    delete_set = {str(x).strip() for x in (pending_delete_ids or []) if str(x).strip()}
    if delete_set:
        base = base[~base["close_id"].astype(str).isin(delete_set)].copy()

    if pending_updates:
        base = base.set_index("close_id", drop=False)
        for upd in pending_updates:
            cid = str(pick_first(upd.get("close_id"), "")).strip()
            if not cid:
                continue
            if cid not in base.index:
                row = {k: v for k, v in upd.items()}
                row["close_id"] = cid
                row_df = normalize_close2_frame(pd.DataFrame([row])).set_index("close_id", drop=False)
                base = pd.concat([base, row_df], axis=0)
                continue
            for k, v in upd.items():
                if k == "close_id" or k not in base.columns:
                    continue
                base.at[cid, k] = v
        base = base.reset_index(drop=True)

    if pending_inserts:
        ins_df = normalize_close2_frame(pd.DataFrame(pending_inserts))
        if not ins_df.empty:
            base = pd.concat([base, ins_df], axis=0, ignore_index=True)

    base = normalize_close2_frame(base)
    # close_id 冲突时保留最后一条（视作用户最新操作）
    if not base.empty:
        base = base.drop_duplicates(subset=["close_id"], keep="last").copy()
    return base


def _compute_ledgers_with_candidate_close2(
    conn: sqlite3.Connection,
    close2_candidate: pd.DataFrame,
    as_of_date: str,
) -> pd.DataFrame:
    tmp = sqlite3.connect(":memory:")
    tmp.execute("PRAGMA foreign_keys = ON;")
    conn.backup(tmp)
    tmp.execute("DELETE FROM close_trade2")
    c = normalize_close2_frame(close2_candidate)
    if not c.empty and "structure_id" in c.columns:
        struct_defs = fetch_structures(conn)
        live_sid_set: set[str] = set()
        if not struct_defs.empty and "structure_id" in struct_defs.columns:
            live_sid_set = set(struct_defs["structure_id"].astype(str).str.strip().tolist())
        sid_s = c["structure_id"].astype(str).str.strip()
        valid_sid_mask = sid_s.isin(live_sid_set) | sid_s.eq("") | sid_s.eq("外部")
        c = c.loc[valid_sid_mask].copy()
    if not c.empty:
        vals: List[Tuple[Any, ...]] = []
        for _, r in c.iterrows():
            vals.append(
                (
                    str(r.get("close_id", "")),
                    str(r.get("dt", "")),
                    str(r.get("group_id", "")),
                    str(r.get("structure_id", "")),
                    str(r.get("underlying", "")),
                    str(r.get("side", "")),
                    float(pick_first(r.get("qty"), 0.0)),
                    float(pick_first(r.get("open_price"), 0.0)),
                    float(pick_first(r.get("close_price"), 0.0)),
                    float(pick_first(r.get("pnl"), 0.0)),
                    str(pick_first(r.get("close_category"), STRUCT_CLOSE_CATEGORY)),
                    str(pick_first(r.get("quick_batch_id"), "")),
                    str(pick_first(r.get("source_gen_date"), "")),
                    int(pick_first(r.get("is_external"), 0)),
                )
            )
        tmp.executemany(
            """
            INSERT INTO close_trade2(
                close_id, dt, group_id, structure_id, underlying, side, qty, open_price, close_price, pnl, close_category, quick_batch_id, source_gen_date, is_external
            ) VALUES(?,?,?,?,?,?,?,?,?,?,?,?,?,?)
            """,
            vals,
        )
    tmp.commit()
    s_df, _, _ = compute_ledgers(tmp, as_of_date=as_of_date)
    tmp.close()
    return s_df


def compute_over_close_metrics(
    struct_df: pd.DataFrame,
    close2_df: pd.DataFrame,
    structure_defs: pd.DataFrame,
) -> Dict[str, Dict[str, Any]]:
    eps = 1e-12
    out: Dict[str, Dict[str, Any]] = {}
    if close2_df is None or close2_df.empty or structure_defs is None or structure_defs.empty:
        return out

    kind_map = dict(
        zip(
            structure_defs["structure_id"].astype(str),
            structure_defs["kind"].astype(str).str.upper(),
        )
    )

    gen_map: Dict[str, pd.DataFrame] = {}
    if struct_df is not None and not struct_df.empty:
        gs = struct_df[["structure_id", "date", "cum_qty"]].copy()
        gs["structure_id"] = gs["structure_id"].astype(str)
        gs["date"] = gs["date"].astype(str)
        gs["cum_qty"] = pd.to_numeric(gs["cum_qty"], errors="coerce").fillna(0.0)
        gs = gs.sort_values(["structure_id", "date"])
        for sid, sub in gs.groupby("structure_id"):
            sub2 = sub.groupby("date", as_index=False)["cum_qty"].max().sort_values("date")
            gen_map[str(sid)] = sub2.rename(columns={"date": "d", "cum_qty": "gen_cum"})

    c = normalize_close2_frame(close2_df)
    close_cat = c["close_category"].fillna(STRUCT_CLOSE_CATEGORY).astype(str).str.strip()
    close_cat = close_cat.where(close_cat != "", STRUCT_CLOSE_CATEGORY)
    c = c[
        (close_cat.isin(INTERNAL_POSITION_CLOSE_CATEGORIES))
        & (c["is_external"].astype(int) == 0)
        & (c["structure_id"].astype(str) != "外部")
        & (c["qty"] > eps)
    ].copy()
    if c.empty:
        return out
    c["side"] = c["side"].astype(str).str.upper()
    c = c[c["side"].isin(["BUY", "SELL"])].copy()
    if c.empty:
        return out

    c["reduce_qty"] = c.apply(
        lambda r: max(
            0.0,
            float(
                structure_close_reduce_qty(
                    kind_map.get(str(r.get("structure_id", "")).strip(), ""),
                    str(r.get("side", "")),
                    float(pick_first(r.get("qty"), 0.0)),
                )
            ),
        ),
        axis=1,
    )
    c = c[c["reduce_qty"] > eps].copy()
    if c.empty:
        return out

    for sid, sub in c.groupby(c["structure_id"].astype(str)):
        sid_s = str(sid).strip()
        sub_red = sub.copy()
        sub_red["d"] = sub_red["dt"].astype(str)
        red = (
            sub_red.groupby("d", as_index=False)["reduce_qty"]
            .sum()
            .rename(columns={"reduce_qty": "red_day"})
            .sort_values("d")
        )
        red["red_cum"] = pd.to_numeric(red["red_day"], errors="coerce").fillna(0.0).cumsum()
        gen = gen_map.get(sid_s, pd.DataFrame(columns=["d", "gen_cum"]))

        all_days = pd.DataFrame({"d": sorted(set(red["d"].astype(str).tolist()) | set(gen.get("d", pd.Series(dtype=str)).astype(str).tolist()))})
        if all_days.empty:
            continue
        all_days = all_days.merge(gen, on="d", how="left").merge(red[["d", "red_cum"]], on="d", how="left")
        all_days["gen_cum"] = pd.to_numeric(all_days["gen_cum"], errors="coerce").ffill().fillna(0.0)
        all_days["red_cum"] = pd.to_numeric(all_days["red_cum"], errors="coerce").ffill().fillna(0.0)
        all_days["over_qty"] = all_days["red_cum"] - all_days["gen_cum"]

        max_over = float(all_days["over_qty"].max()) if not all_days.empty else 0.0
        final_over = float(all_days["over_qty"].iloc[-1]) if not all_days.empty else 0.0
        first_breach_date = ""
        breach = all_days[all_days["over_qty"] > eps]
        if not breach.empty:
            first_breach_date = str(breach.iloc[0]["d"])

        out[sid_s] = {
            "max_over_qty": max(max_over, 0.0),
            "final_over_qty": max(final_over, 0.0),
            "first_breach_date": first_breach_date,
            "final_generated_qty": float(all_days["gen_cum"].iloc[-1]) if not all_days.empty else 0.0,
            "final_reduce_qty": float(all_days["red_cum"].iloc[-1]) if not all_days.empty else 0.0,
        }
    return out


def validate_no_worse_over_close(
    conn: sqlite3.Connection,
    *,
    touched_structure_ids: List[str],
    pending_inserts: Optional[List[Dict[str, Any]]] = None,
    pending_updates: Optional[List[Dict[str, Any]]] = None,
    pending_delete_ids: Optional[List[str]] = None,
) -> Tuple[bool, str]:
    touched = {
        str(x).strip()
        for x in touched_structure_ids
        if str(x).strip() and str(x).strip() != "外部"
    }
    if not touched:
        return True, ""

    base_close2 = normalize_close2_frame(fetch_closes2(conn))
    candidate_close2 = build_close2_candidate_frame(
        conn,
        pending_inserts=pending_inserts,
        pending_updates=pending_updates,
        pending_delete_ids=pending_delete_ids,
    )
    prices = fetch_prices(conn)
    asof = infer_effective_asof_date(prices, candidate_close2, fallback=infer_effective_asof_date(prices, base_close2))
    asof_s = asof.strftime(DATE_FMT)

    struct_defs = fetch_structures(conn)
    if struct_defs.empty:
        return True, ""

    base_struct_df, _, _ = compute_ledgers_cached(conn, as_of_date=asof_s)
    cand_struct_df = _compute_ledgers_with_candidate_close2(conn, candidate_close2, as_of_date=asof_s)

    base_metrics = compute_over_close_metrics(base_struct_df, base_close2, struct_defs)
    cand_metrics = compute_over_close_metrics(cand_struct_df, candidate_close2, struct_defs)

    worsened: List[Dict[str, Any]] = []
    for sid in sorted(touched):
        before = float(pick_first(base_metrics.get(sid, {}).get("max_over_qty"), 0.0) or 0.0)
        after = float(pick_first(cand_metrics.get(sid, {}).get("max_over_qty"), 0.0) or 0.0)
        if after > before + 1e-9:
            cm = cand_metrics.get(sid, {})
            worsened.append(
                {
                    "sid": sid,
                    "before": before,
                    "after": after,
                    "first_breach_date": str(pick_first(cm.get("first_breach_date"), "")),
                    "final_generated_qty": float(pick_first(cm.get("final_generated_qty"), 0.0) or 0.0),
                    "final_reduce_qty": float(pick_first(cm.get("final_reduce_qty"), 0.0) or 0.0),
                }
            )
    if not worsened:
        return True, ""

    parts = []
    for x in worsened[:3]:
        p = (
            f"{x['sid']} 超平从 {x['before']:.2f} 增至 {x['after']:.2f}"
            f"（首次超平日 {x['first_breach_date'] or 'N/A'}，累计平仓 {x['final_reduce_qty']:.2f} > 累计生成 {x['final_generated_qty']:.2f}）"
        )
        parts.append(p)
    msg = "保存被拦截：本次操作会加重超平仓。请先修正数量/日期。"
    if parts:
        msg += " " + "；".join(parts)
    return False, msg


def compute_price_gap_table(
    structs: pd.DataFrame,
    prices: pd.DataFrame,
    closes2: Optional[pd.DataFrame] = None,
    *,
    as_of_date: Any = None,
    snowball_coupon_pct_map: Optional[Dict[str, float]] = None,
) -> pd.DataFrame:
    if structs.empty:
        return pd.DataFrame()
    price_day_by_und: Dict[str, set[date]] = {}
    if not prices.empty:
        for _, r in prices.iterrows():
            d = datetime.strptime(str(r["dt"]), DATE_FMT).date()
            if is_trading_day(d):
                price_day_by_und.setdefault(str(r["underlying"]), set()).add(d)
    as_of_d = parse_date_maybe(as_of_date)
    if as_of_d is None and not prices.empty:
        dt_ser = pd.to_datetime(prices.get("dt"), errors="coerce").dropna()
        if not dt_ser.empty:
            as_of_d = dt_ser.max().date()

    manual_close_date_map = build_manual_close_date_map(closes2)
    coupon_pct_map = snowball_coupon_pct_map if isinstance(snowball_coupon_pct_map, dict) else {}

    rows: List[Dict[str, Any]] = []
    for _, r in structs.iterrows():
        struct_resolved = resolve_structure_row(r)
        if str(struct_resolved.get("strategy_code", "")).upper() == "TRS":
            # TRS 不纳入价格完整性监控。
            continue
        sd = datetime.strptime(str(struct_resolved["start_date"]), DATE_FMT).date()
        ed = datetime.strptime(str(struct_resolved["end_date"]), DATE_FMT).date()
        sid = str(struct_resolved.get("structure_id", "")).strip()
        md = manual_close_date_map.get(sid)
        if md is not None:
            ed = min(ed, md - timedelta(days=1))
        und = str(struct_resolved["underlying"])
        td = trading_days_between(sd, ed) if ed >= sd else []
        got_days = sorted([d for d in td if d in price_day_by_und.get(und, set())])
        miss_days = [d for d in td if d not in price_day_by_und.get(und, set())]
        rem_days = len(miss_days)
        rem_natural_days = remaining_natural_days_excl_today(as_of_d, ed, start_date_v=sd) if as_of_d is not None else 0
        daily_obs_scale = max(float(pick_first(struct_resolved.get("base_qty_per_day"), 0.0) or 0.0), 0.0)
        strategy_code = resolve_strategy_code_for_display(
            pick_first(struct_resolved.get("strategy_code"), struct_resolved.get("strategy"), "")
        )
        kind_code = normalize_kind_code(pick_first(struct_resolved.get("kind"), ""))
        dir_sign = 1.0 if kind_code == "ACC" else -1.0 if kind_code == "DEC" else 0.0
        display_name = default_structure_name(strategy_code, kind_code, fallback_name=str(struct_resolved.get("name", "")))
        pos_scale = 0.0
        subsidy_scale = 0.0
        pos_scale_max_num = 0.0
        pos_scale_min_num = 0.0
        base_future_scale_signed = float(rem_days) * daily_obs_scale * dir_sign
        knock_in_mult = max(float(pick_first(struct_resolved.get("multiple"), 1.0) or 0.0), 0.0)
        # 震荡补贴结构（仅补贴不生成头寸）：展示“剩余补贴金额”
        if strategy_code in {"PREMIUM_SUBSIDY", "RANGE_SUBSIDY"}:
            subsidy_per_ton = max(float(pick_first(struct_resolved.get("subsidy_per_ton"), 0.0) or 0.0), 0.0)
            subsidy_scale = rem_days * daily_obs_scale * subsidy_per_ton
            # 最小场景：未来都为震荡/补贴日，不生成头寸；最大场景：未来都为敲入日。
            pos_scale_min_num = 0.0
            pos_scale_max_num = base_future_scale_signed * knock_in_mult
        elif strategy_code == "SNOWBALL":
            sid_key = str(struct_resolved.get("structure_id", "")).strip()
            sb_params = struct_resolved.get("params", {}) if isinstance(struct_resolved.get("params", {}), dict) else {}
            discount_enabled = bool(_bool_from_any(sb_params.get("sb_discount_enabled"), False))
            notional_amount = max(
                float(
                    pick_first(
                        to_float(sb_params.get("sb_notional_amount")),
                        (to_float(sb_params.get("sb_notional_wan")) or 0.0) * 10000.0,
                        0.0,
                    )
                    or 0.0
                ),
                0.0,
            )
            coupon_pct = float(pick_first(to_float(coupon_pct_map.get(sid_key)), 0.0) or 0.0)
            if coupon_pct <= 1e-12:
                if bool(_bool_from_any(sb_params.get("sb_early_mode"), False)):
                    coupon_pct = float(
                        pick_first(
                            to_float(sb_params.get("sb_coupon_b_pct")),
                            to_float(sb_params.get("sb_coupon_a_pct")),
                            0.0,
                        )
                        or 0.0
                    )
                else:
                    coupon_pct = float(pick_first(to_float(sb_params.get("sb_coupon_pct")), 0.0) or 0.0)
            daily_coupon_amt = notional_amount * max(coupon_pct, 0.0) / 100.0 / 365.0
            subsidy_scale = float(rem_natural_days) * daily_coupon_amt
            if discount_enabled:
                discount_price = max(float(pick_first(to_float(sb_params.get("sb_discount_price")), 0.0) or 0.0), 0.0)
                if discount_price > 1e-12 and notional_amount > 1e-12:
                    pos_scale = (notional_amount / discount_price) * dir_sign
                else:
                    pos_scale = None
            else:
                # 未启用折价：雪球不产生头寸规模。
                pos_scale = None
            pos_scale_sb = float(pick_first(to_float(pos_scale), 0.0) or 0.0)
            # 雪球不按“每日震荡/敲入”累计，保持当前一次性口径。
            pos_scale_min_num = pos_scale_sb
            pos_scale_max_num = pos_scale_sb
        elif strategy_code == "SAFETY_AIRBAG":
            # 安全气囊为一次性敲入结构：不按“每日震荡规模”累计，展示口径固定为 0。
            pos_scale = 0.0
            pos_scale_min_num = 0.0
            pos_scale_max_num = 0.0
        else:
            # 常规累计结构：
            # - 最大头寸：未来每天都敲入
            # - 最小头寸：未来每天都按震荡（1 倍）生成
            min_mult = 1.0
            meta_obj = struct_resolved.get("meta", {}) if isinstance(struct_resolved.get("meta", {}), dict) else {}
            if strategy_code == "BASIC_RANGE":
                legacy_mode = str(pick_first(meta_obj.get("_legacy_mode"), "")).upper()
                if legacy_mode == "FIXED_PART":
                    # 旧固定倍数口径：震荡场景同样按固定倍数。
                    min_mult = knock_in_mult
            max_mult = max(min_mult, knock_in_mult)
            pos_scale_min_num = base_future_scale_signed * min_mult
            pos_scale_max_num = base_future_scale_signed * max_mult

        pos_scale_num = float(pos_scale_max_num)
        subsidy_scale_num = float(pick_first(to_float(subsidy_scale), 0.0) or 0.0)
        rows.append(
            {
                "策略组编号": str(struct_resolved["group_id"]),
                "结构ID": str(struct_resolved["structure_id"]),
                "结构名称": str(display_name),
                "风险子": str(pick_first(struct_resolved.get("risk_party"), "")),
                "结构": structure_detail_label_unified(
                    structure_id=struct_resolved.get("structure_id", ""),
                    strategy_value=pick_first(struct_resolved.get("strategy_code"), struct_resolved.get("strategy")),
                    kind_value=pick_first(struct_resolved.get("kind"), ""),
                    fallback_name=display_name,
                    risk_party=pick_first(struct_resolved.get("risk_party"), ""),
                    entry_price=pick_first(to_float(struct_resolved.get("entry_price")), to_float(r.get("gen_price"))),
                    strike_price=to_float(struct_resolved.get("strike_price")),
                    knock_in_price=to_float(struct_resolved.get("barrier_in")),
                    barrier_price=resolve_display_barrier_price(
                        pick_first(struct_resolved.get("strategy_code"), struct_resolved.get("strategy")),
                        barrier_out=to_float(pick_first(struct_resolved.get("barrier_out"), struct_resolved.get("barrier_price"))),
                        barrier_in=to_float(struct_resolved.get("barrier_in")),
                        strike_price=to_float(struct_resolved.get("strike_price")),
                    ),
                ),
                "品种": und,
                "区间交易日总数": len(td),
                "已录价格交易日数": len(got_days),
                "剩余观察交易日": rem_days,
                "剩余震荡最大头寸规模": pos_scale_max_num,
                "剩余震荡最小头寸规模": pos_scale_min_num,
                "剩余震荡最大补贴规模": subsidy_scale_num,
                # 兼容旧列名：保留输出，不再作为主展示列。
                "剩余震荡最大规模": (
                    float(pos_scale_num)
                    if pos_scale_num is not None and abs(float(pos_scale_num)) > 1e-12
                    else subsidy_scale_num
                ),
                "缺失日期列表": ",".join([d.strftime(DATE_FMT) for d in miss_days]),
            }
        )
    return pd.DataFrame(rows)


def apply_table_filters(
    df: pd.DataFrame,
    key_prefix: str,
    *,
    keyword_cols: Optional[List[str]] = None,
    category_cols: Optional[List[str]] = None,
    date_cols: Optional[List[str]] = None,
    numeric_cols: Optional[List[str]] = None,
    title: str = "筛选条件",
    expanded: bool = False,
    quick_date: bool = True,
) -> pd.DataFrame:
    """通用表格筛选（紧凑版）：常用筛选外显，高级筛选折叠。"""
    if df.empty:
        return df

    def _sorted_nonempty_text_options(series: pd.Series) -> List[str]:
        if series is None or series.empty:
            return []
        s = series.dropna().astype(str).str.strip()
        if s.empty:
            return []
        s = s[s != ""]
        if s.empty:
            return []
        return sorted(pd.unique(s).tolist())

    view = df.copy()
    keyword_cols = [c for c in (keyword_cols or []) if c in view.columns]
    category_cols = [c for c in (category_cols or []) if c in view.columns]
    date_cols = [c for c in (date_cols or []) if c in view.columns]
    _ = numeric_cols  # 预留参数：按要求当前先关闭“数值区间筛选”

    with st.expander(title, expanded=expanded):
        c1, c2, c3 = st.columns([1, 1, 1])

        # 常用筛选：最多外显 2 个分类 + 1 个日期
        quick_cats = category_cols[:2]
        for i, col_name in enumerate(quick_cats):
            opts = _sorted_nonempty_text_options(view[col_name])
            if not opts:
                continue
            with [c1, c2][i]:
                selected = st.multiselect(col_name, options=opts, key=f"{key_prefix}_quick_cat_{col_name}")
            if selected:
                selected_vals = [str(x) for x in selected]
                view = view[view[col_name].astype(str).isin(selected_vals)].copy()

        if date_cols and quick_date:
            with c3:
                date_col = st.selectbox("日期字段", ["不筛选"] + date_cols, key=f"{key_prefix}_quick_date_col")
                if date_col != "不筛选":
                    dt_series = pd.to_datetime(view[date_col], errors="coerce").dt.date
                    valid_dates = sorted([d for d in dt_series.dropna().unique().tolist()])
                    if valid_dates:
                        d_opts = ["全部"] + [d.strftime(DATE_FMT) for d in valid_dates]
                        d_pick = st.selectbox("日期值", d_opts, key=f"{key_prefix}_quick_date_val")
                        if d_pick != "全部":
                            try:
                                d_sel = datetime.strptime(str(d_pick), DATE_FMT).date()
                                view = view[dt_series == d_sel].copy()
                            except Exception:
                                pass

        # 不常用筛选：全部放进高级筛选
        with st.expander("高级筛选", expanded=False):
            if keyword_cols:
                kw = st.text_input("关键词（模糊）", key=f"{key_prefix}_kw")
                if kw:
                    kw_l = str(kw).strip().lower()
                    if kw_l:
                        mask = pd.Series(False, index=view.index)
                        for c in keyword_cols:
                            mask = mask | view[c].astype(str).str.lower().str.contains(kw_l, na=False)
                        view = view[mask].copy()

            for col_name in category_cols[2:]:
                opts = _sorted_nonempty_text_options(view[col_name])
                if not opts:
                    continue
                selected = st.multiselect(col_name, options=opts, key=f"{key_prefix}_adv_cat_{col_name}")
                if selected:
                    selected_vals = [str(x) for x in selected]
                    view = view[view[col_name].astype(str).isin(selected_vals)].copy()

            if date_cols and not quick_date:
                date_col = st.selectbox("日期字段", ["不筛选"] + date_cols, key=f"{key_prefix}_adv_date_col")
                if date_col != "不筛选":
                    dt_series = pd.to_datetime(view[date_col], errors="coerce").dt.date
                    valid_dates = sorted([d for d in dt_series.dropna().unique().tolist()])
                    if valid_dates:
                        d_opts = ["全部"] + [d.strftime(DATE_FMT) for d in valid_dates]
                        d_pick = st.selectbox("日期值", d_opts, key=f"{key_prefix}_adv_date_val")
                        if d_pick != "全部":
                            try:
                                d_sel = datetime.strptime(str(d_pick), DATE_FMT).date()
                                view = view[dt_series == d_sel].copy()
                            except Exception:
                                pass

        st.caption(f"筛选结果：{len(view):,} 条")

    return view


def hide_empty_display_columns(df: pd.DataFrame, cols: List[str]) -> pd.DataFrame:
    """将指定列中“整列无展示值”的列隐藏。0 视为有效值，不会被当作空值。"""
    if df is None or df.empty:
        return df
    out = df.copy()
    keep_cols = [c for c in cols if c in out.columns]
    if not keep_cols:
        return out

    def _has_cell_value(v: Any) -> bool:
        if pd.isna(v):
            return False
        sv = str(v).strip()
        if not sv:
            return False
        return sv.lower() not in {"none", "nan", "null", "-"}

    drop_cols: List[str] = []
    for col in keep_cols:
        if not out[col].apply(_has_cell_value).any():
            drop_cols.append(col)
    if drop_cols:
        out = out.drop(columns=drop_cols)
    return out


def hide_zero_or_empty_display_columns(df: pd.DataFrame, cols: List[str], *, eps: float = 1e-12) -> pd.DataFrame:
    """将指定列中“整列均为0/空值”的列隐藏。"""
    if df is None or df.empty:
        return df
    out = df.copy()
    keep_cols = [c for c in cols if c in out.columns]
    if not keep_cols:
        return out

    def _is_zero_or_empty(v: Any) -> bool:
        if pd.isna(v):
            return True
        sv = str(v).strip()
        if not sv:
            return True
        if sv.lower() in {"none", "nan", "null", "-"}:
            return True
        num = to_float(v)
        if num is None:
            return False
        return abs(float(num)) <= float(eps)

    drop_cols: List[str] = []
    for col in keep_cols:
        if out[col].apply(_is_zero_or_empty).all():
            drop_cols.append(col)
    if drop_cols:
        out = out.drop(columns=drop_cols)
    return out


def render_metric_glossary(title: str, rows: List[Tuple[str, str]], *, expanded: bool = False) -> None:
    """统一术语/口径说明展示。"""
    valid_rows = [(str(k).strip(), str(v).strip()) for k, v in rows if str(k).strip() and str(v).strip()]
    if not valid_rows:
        return
    with st.expander(title, expanded=expanded):
        for k, v in valid_rows:
            st.markdown(f"- **{k}**：{v}")


def _column_config_for(df: pd.DataFrame, config: Dict[str, Any]) -> Dict[str, Any]:
    if df is None or df.empty:
        return {k: v for k, v in (config or {}).items() if k}
    return {k: v for k, v in (config or {}).items() if k in df.columns}


_MPL_CJK_FONT_NAME: str = ""


def _setup_matplotlib_cjk_font() -> None:
    """为图片渲染强制绑定可用中文字体，避免出现乱码/问号。"""
    global _MPL_CJK_FONT_NAME
    if not _MPL_CJK_FONT_NAME:
        font_candidates = [
            "/usr/share/fonts/opentype/noto/NotoSansCJK-Regular.ttc",
            "/usr/share/fonts/opentype/noto/NotoSansCJK-Bold.ttc",
            "/usr/share/fonts/opentype/noto/NotoSerifCJK-Regular.ttc",
            "/usr/share/fonts/truetype/noto/NotoSansCJK-Regular.ttc",
            "/usr/share/fonts/truetype/noto/NotoSansSC-Regular.otf",
            "/usr/share/fonts/truetype/wqy/wqy-zenhei.ttc",
            "/usr/share/fonts/truetype/arphic/ukai.ttc",
            "/usr/share/fonts/truetype/arphic/uming.ttc",
            r"C:\Windows\Fonts\msyh.ttc",
            r"C:\Windows\Fonts\msyhbd.ttc",
            r"C:\Windows\Fonts\simhei.ttf",
            r"C:\Windows\Fonts\simsun.ttc",
        ]
        for fp in font_candidates:
            p = Path(fp)
            if not p.exists():
                continue
            try:
                mpl_font_manager.fontManager.addfont(str(p))
            except Exception:
                pass
            try:
                resolved = mpl_font_manager.FontProperties(fname=str(p)).get_name()
                if str(resolved).strip():
                    _MPL_CJK_FONT_NAME = str(resolved).strip()
                    break
            except Exception:
                continue
        if not _MPL_CJK_FONT_NAME:
            _MPL_CJK_FONT_NAME = "DejaVu Sans"

    plt.rcParams["font.family"] = [_MPL_CJK_FONT_NAME]
    plt.rcParams["font.sans-serif"] = [
        _MPL_CJK_FONT_NAME,
        "Microsoft YaHei",
        "SimHei",
        "Arial Unicode MS",
        "DejaVu Sans",
    ]
    plt.rcParams["axes.unicode_minus"] = False


def render_report_image(summary: Dict[str, Any], out_path: str) -> bytes:
    _setup_matplotlib_cjk_font()

    def _to_num(v: Any, default: float = 0.0) -> float:
        try:
            return float(str(v).replace(",", "").strip())
        except Exception:
            return float(default)

    def _to_num_opt(v: Any) -> Optional[float]:
        try:
            s = str(v).replace(",", "").strip()
            if s == "":
                return None
            return float(s)
        except Exception:
            return None

    gen_total_qty = _to_num(summary.get("gen_total_qty", 0.0))
    net_gen_qty = _to_num(summary.get("net_gen_qty", 0.0))
    gen_long_qty = _to_num(summary.get("gen_long_qty", 0.0))
    gen_short_qty = _to_num(summary.get("gen_short_qty", 0.0))
    remaining_max_signed = _to_num(summary.get("remaining_max_signed", 0.0))
    gen_avg_price = _to_num_opt(summary.get("gen_avg_price"))
    today_long_avg = _to_num_opt(summary.get("today_long_avg"))
    today_short_avg = _to_num_opt(summary.get("today_short_avg"))
    day_close_price = _to_num_opt(summary.get("day_close_price"))
    day_close_price_map: Dict[str, float] = {}
    raw_close_map = summary.get("day_close_price_map", {})
    if isinstance(raw_close_map, dict):
        for k, v in raw_close_map.items():
            und_s = str(k).strip()
            vv = _to_num_opt(v)
            if und_s and (vv is not None):
                day_close_price_map[und_s] = float(vv)
    lock_qty = max(0.0, _to_num(summary.get("lock_qty", 0.0)))
    lock_pnl = _to_num(summary.get("lock_pnl", 0.0))

    _ensure_report_image_dir()
    out_file = Path(str(out_path))
    try:
        out_file.parent.mkdir(parents=True, exist_ok=True)
    except Exception:
        out_file = REPORT_IMAGE_DIR / out_file.name
        try:
            out_file.parent.mkdir(parents=True, exist_ok=True)
        except Exception:
            pass

    cumulative_items_all = list(summary.get("cumulative_rows", summary.get("top5_remaining", [])) or [])
    snowball_items_all = [
        x
        for x in list(summary.get("snowball_rows", []) or [])
        if bool(_bool_from_any(x.get("is_snowball"), False))
    ]
    airbag_items_all = [
        x
        for x in list(summary.get("airbag_rows", []) or [])
        if bool(_bool_from_any(x.get("is_airbag"), False))
    ]
    cumulative_items = list(cumulative_items_all)
    snowball_items = list(snowball_items_all)
    airbag_items = list(airbag_items_all)
    has_snowball_scope = bool(_bool_from_any(summary.get("has_snowball"), False)) or bool(snowball_items)
    if has_snowball_scope and not snowball_items:
        snowball_items = [x for x in cumulative_items if bool(_bool_from_any(x.get("is_snowball"), False))]
    has_airbag_scope = bool(_bool_from_any(summary.get("has_airbag"), False)) or bool(airbag_items)
    if has_airbag_scope and not airbag_items:
        airbag_items = [x for x in cumulative_items if bool(_bool_from_any(x.get("is_airbag"), False))]
    layout_input = summary.get("report_layout", {}) if isinstance(summary.get("report_layout", {}), dict) else {}
    layout_cfg = _normalize_report_layout_dict(layout_input)
    # 汇报图调试字默认关闭，避免在正式图中出现 DBG 标注。
    debug_draw = False

    def _clamp(v: float, lo: float, hi: float) -> float:
        return max(float(lo), min(float(hi), float(v)))

    def _cfg_float(key: str, default: float, lo: float, hi: float) -> float:
        vv = layout_cfg.get(key, default)
        try:
            return _clamp(float(vv), lo, hi)
        except Exception:
            return _clamp(float(default), lo, hi)

    def _cfg_color(key: str, default: str) -> str:
        raw = str(pick_first(layout_cfg.get(key, default), default)).strip()
        if re.match(r"^#[0-9a-fA-F]{6}$", raw):
            return raw
        if re.match(r"^#[0-9a-fA-F]{3}$", raw):
            return raw
        return default

    if cumulative_items_all:
        _detail_len_avg = sum(len(str(pick_first(r.get("structure"), ""))) for r in cumulative_items_all) / max(1, len(cumulative_items_all))
        _status_len_max = max([len(str(pick_first(r.get("status_cn"), ""))) for r in cumulative_items_all] + [8])
    else:
        _detail_len_avg = 34.0
        _status_len_max = 8

    auto_cum_detail_ratio = _clamp(0.54 + max(0.0, float(_detail_len_avg) - 34.0) * 0.0032, 0.50, 0.66)
    auto_cum_status_ratio = _clamp(0.10 + max(0.0, float(_status_len_max) - 8.0) * 0.0040, 0.09, 0.17)
    auto_cum_rem_ratio = 0.10
    cum_detail_ratio = _cfg_float("cum_detail_ratio", auto_cum_detail_ratio, 0.45, 0.72)
    cum_status_ratio = _cfg_float("cum_status_ratio", auto_cum_status_ratio, 0.07, 0.20)
    # 累计区优化：状态列适度放宽，避免右侧列头/内容拥挤。
    cum_detail_ratio = _clamp(cum_detail_ratio + 0.005, 0.46, 0.74)
    cum_status_ratio = _clamp(cum_status_ratio + 0.004, 0.09, 0.16)
    cum_rem_ratio = _cfg_float("cum_rem_ratio", auto_cum_rem_ratio, 0.07, 0.18)
    cum_rest = max(0.12, 1.0 - cum_detail_ratio - cum_status_ratio - cum_rem_ratio)
    cum_days_ratio = cum_rest / 3.0
    cum_today_ratio = cum_rest / 3.0
    cum_cum_ratio = 1.0 - cum_detail_ratio - cum_status_ratio - cum_rem_ratio - cum_days_ratio - cum_today_ratio
    cum_status_ratio = max(cum_status_ratio, 0.095)
    cum_rem_ratio = max(cum_rem_ratio, 0.11)
    cum_days_ratio = max(cum_days_ratio, 0.08)
    cum_today_ratio = max(cum_today_ratio, 0.09)
    cum_cum_ratio = max(cum_cum_ratio, 0.09)
    cum_other_sum = cum_status_ratio + cum_rem_ratio + cum_days_ratio + cum_today_ratio + cum_cum_ratio
    cum_other_cap = 0.58  # 预留至少 42% 给“结构详情”。
    if cum_other_sum > cum_other_cap:
        _cum_scale = cum_other_cap / max(cum_other_sum, 1e-9)
        cum_status_ratio *= _cum_scale
        cum_rem_ratio *= _cum_scale
        cum_days_ratio *= _cum_scale
        cum_today_ratio *= _cum_scale
        cum_cum_ratio *= _cum_scale
    cum_detail_ratio = max(0.32, 1.0 - (cum_status_ratio + cum_rem_ratio + cum_days_ratio + cum_today_ratio + cum_cum_ratio))
    cum_col_ratio = [cum_detail_ratio, cum_status_ratio, cum_rem_ratio, cum_days_ratio, cum_today_ratio, cum_cum_ratio]
    cum_detail_fs_scale = _cfg_float("cum_detail_fs_scale", 1.0, 0.70, 1.40)
    cum_status_fs_scale = _cfg_float("cum_status_fs_scale", 1.0, 0.70, 1.40)
    cum_num_fs_scale = _cfg_float("cum_num_fs_scale", 1.0, 0.70, 1.40)
    cum_row_h_min = _cfg_float("cum_row_h_min", 0.010, 0.006, 0.030)
    cum_row_h_scale = _cfg_float("cum_row_h_scale", 1.0, 0.60, 1.80)

    sb_detail_ratio = _cfg_float("sb_detail_ratio", 0.56, 0.42, 0.75)
    sb_status_ratio = _cfg_float("sb_status_ratio", 0.11, 0.07, 0.25)
    sb_dist_ratio = _cfg_float("sb_dist_ratio", 0.11, 0.07, 0.25)
    sb_coupon_ratio = _cfg_float("sb_coupon_ratio", 0.11, 0.07, 0.25)
    sb_detail_ratio = _clamp(sb_detail_ratio + 0.08, 0.50, 0.80)
    sb_status_ratio = _clamp(sb_status_ratio - 0.01, 0.07, 0.20)
    sb_dist_ratio = _clamp(sb_dist_ratio - 0.01, 0.07, 0.20)
    sb_coupon_ratio = _clamp(sb_coupon_ratio - 0.01, 0.07, 0.20)
    sb_days_min = 0.09
    sb_primary_sum = sb_detail_ratio + sb_status_ratio + sb_dist_ratio + sb_coupon_ratio
    if sb_primary_sum > 1.0 - sb_days_min:
        _scale_sb = (1.0 - sb_days_min) / max(sb_primary_sum, 1e-9)
        sb_detail_ratio *= _scale_sb
        sb_status_ratio *= _scale_sb
        sb_dist_ratio *= _scale_sb
        sb_coupon_ratio *= _scale_sb
        sb_days_ratio = sb_days_min
    else:
        sb_days_ratio = 1.0 - sb_primary_sum
    # 雪球区后四列设置可读下限，避免表头重叠。
    sb_status_ratio = max(sb_status_ratio, 0.11)
    sb_dist_ratio = max(sb_dist_ratio, 0.13)
    sb_coupon_ratio = max(sb_coupon_ratio, 0.16)
    sb_days_ratio = max(sb_days_ratio, 0.12)
    sb_other_sum = sb_status_ratio + sb_dist_ratio + sb_coupon_ratio + sb_days_ratio
    sb_other_cap = 0.60  # 预留至少 40% 给“结构详情”。
    if sb_other_sum > sb_other_cap:
        _sb_scale = sb_other_cap / max(sb_other_sum, 1e-9)
        sb_status_ratio *= _sb_scale
        sb_dist_ratio *= _sb_scale
        sb_coupon_ratio *= _sb_scale
        sb_days_ratio *= _sb_scale
    sb_detail_ratio = max(0.32, 1.0 - (sb_status_ratio + sb_dist_ratio + sb_coupon_ratio + sb_days_ratio))
    sb_col_ratio = [sb_detail_ratio, sb_status_ratio, sb_dist_ratio, sb_coupon_ratio, sb_days_ratio]
    sb_detail_fs_scale = _cfg_float("sb_detail_fs_scale", 1.0, 0.70, 1.40)
    sb_status_fs_scale = _cfg_float("sb_status_fs_scale", 1.0, 0.70, 1.40)
    sb_num_fs_scale = _cfg_float("sb_num_fs_scale", 1.0, 0.70, 1.40)
