    ab_detail_ratio = _cfg_float("ab_detail_ratio", 0.56, 0.42, 0.75)
    ab_status_ratio = _cfg_float("ab_status_ratio", 0.11, 0.07, 0.25)
    ab_qty_ratio = _cfg_float("ab_qty_ratio", 0.11, 0.07, 0.25)
    ab_dist_ratio = _cfg_float("ab_dist_ratio", 0.11, 0.07, 0.25)
