    ab_status_ratio = _clamp(ab_status_ratio - 0.005, 0.08, 0.20)
    ab_qty_ratio = _clamp(ab_qty_ratio - 0.005, 0.08, 0.20)
    ab_dist_ratio = _clamp(ab_dist_ratio - 0.005, 0.08, 0.20)
    ab_days_min = 0.10
    ab_primary_sum = ab_detail_ratio + ab_status_ratio + ab_qty_ratio + ab_dist_ratio
