StateMachineFn = Callable[[Dict[str, Any], float, Dict[str, Any], Dict[str, Any]], Dict[str, Any]]
BoundsFn = Callable[[Dict[str, Any], int, int, float, Dict[str, Any]], Dict[str, float]]


@dataclass
class StructureSpec:
    code: str
    cn_name: str
    required_fields: List[str]
    optional_fields: List[str]
    defaults: Dict[str, Any]
    ui_layout: List[str]
    state_machine: StateMachineFn
    bounds: BoundsFn


