def _bounds_safety_airbag(
    struct: Dict[str, Any],
    remaining_days: int,
    observed_days: int,
    observed_qty: float,
    st_state: Dict[str, Any],
) -> Dict[str, float]:
    if st_state.get("terminated", False) or st_state.get("knocked_out", False):
        return {"remaining_min_qty": 0.0, "remaining_max_qty": 0.0}
    base = float(struct["base_qty_per_day"])
    total_days = max(int(remaining_days + observed_days), 0)
    fixed_qty = max(base * total_days, 0.0)
    return {"remaining_min_qty": 0.0, "remaining_max_qty": fixed_qty}


def _bounds_snowball(
    struct: Dict[str, Any],
    remaining_days: int,
    observed_days: int,
    observed_qty: float,
    st_state: Dict[str, Any],
) -> Dict[str, float]:
    if bool(st_state.get("terminated", False)) or bool(st_state.get("sb_discount_triggered", False)):
        return {"remaining_min_qty": 0.0, "remaining_max_qty": 0.0}
    return {"remaining_min_qty": 0.0, "remaining_max_qty": 0.0}


