def probexp_is_accumulator_structure(struct_row: Mapping[str, Any]) -> bool:
    strategy_code = resolve_strategy_code_for_display(struct_row.get("strategy_code", ""))
    fallback_name = str(pick_first(struct_row.get("name"), "")).strip()
    name_norm = default_structure_name(strategy_code, struct_row.get("kind", ""), fallback_name=fallback_name)
    meta = struct_row.get("meta", {}) if isinstance(struct_row.get("meta", {}), dict) else {}
    meta_tags = [
        meta.get("tag"),
        meta.get("tags"),
        meta.get("label"),
        meta.get("structure_label"),
        struct_row.get("label"),
        struct_row.get("structure"),
    ]
    text_pool = " ".join(
        [
            str(strategy_code or ""),
            str(fallback_name or ""),
            str(name_norm or ""),
            str(STRATEGY_CODE_TO_CN.get(strategy_code, "") or ""),
            " ".join(str(x) for x in meta_tags if x is not None),
        ]
    )
    return (strategy_code in ACCUMULATOR_STRATEGY_CODES) or any(token in text_pool for token in ["累计", "累购", "累沽"])


def probexp_infer_initial_target_qty(struct_row: Mapping[str, Any], total_days: int) -> float:
    params = struct_row.get("params", {}) if isinstance(struct_row.get("params", {}), dict) else {}
    meta = struct_row.get("meta", {}) if isinstance(struct_row.get("meta", {}), dict) else {}
    total_cap = pick_first(
        to_float(struct_row.get("total_cap_qty")),
        to_float(params.get("total_cap_qty")),
        to_float(meta.get("total_cap_qty")),
    )
    if total_cap is not None and float(total_cap) > 1e-12:
        return float(total_cap)
    base_qty = max(float(pick_first(to_float(struct_row.get("base_qty_per_day")), 0.0) or 0.0), 0.0)
    return base_qty * max(int(total_days), 0)


def probexp_underlying_product_code(underlying: Any) -> str:
    txt = _normalize_underlying_symbol(underlying)
    if not txt:
        return ""
    txt = txt.split(".", 1)[0]
    m = re.match(r"^([A-Z]{1,4})", txt)
    return str(m.group(1)).upper() if m else txt.upper()


def probexp_underlying_series(underlying: Any) -> str:
    txt = _normalize_underlying_symbol(underlying)
    if not txt:
        return ""
    txt = txt.split(".", 1)[0]
    m = re.match(r"^([A-Z]{1,4}\d{3,4})", txt)
    return str(m.group(1)).upper() if m else txt.upper()


def probexp_extract_contract_series(contract_text: Any) -> str:
    txt = str(pick_first(contract_text, "") or "").strip().upper()
    if not txt:
        return ""
    m = re.search(r"([A-Z]{1,4}\d{3,4})", txt)
    return str(m.group(1)).upper() if m else ""


def probexp_extract_strike_from_contract(contract_text: Any) -> Optional[float]:
    txt = str(pick_first(contract_text, "") or "").strip().upper()
    if not txt:
        return None
    patterns = [
        r"[CP][\-_]?(\d+(?:\.\d+)?)$",
        r"-(\d+(?:\.\d+)?)$",
    ]
    for pattern in patterns:
        m = re.search(pattern, txt)
        if m:
            return to_float(m.group(1))
    return None


def probexp_underlying_exp_month(underlying: Any, rep_date: Any) -> str:
    series = probexp_underlying_series(underlying)
    product = probexp_underlying_product_code(underlying)
    if (not series) or (not product):
        return ""
    suffix = series[len(product) :]
    if (not suffix.isdigit()) or len(suffix) not in (3, 4):
        return ""
    if len(suffix) == 4:
        yy = int(suffix[:2])
        mm = int(suffix[2:])
        if 1 <= mm <= 12:
            return f"{2000 + yy:04d}{mm:02d}"
        return ""
    rep_date_obj = parse_date_maybe(rep_date)
    ref_year = rep_date_obj.year if isinstance(rep_date_obj, date) else date.today().year
    year_digit = int(suffix[0])
    mm = int(suffix[1:])
    if not 1 <= mm <= 12:
        return ""
    target_month = ref_year * 12 + (rep_date_obj.month if isinstance(rep_date_obj, date) else date.today().month)
    candidate_years = [yy for yy in range(ref_year - 5, ref_year + 6) if yy % 10 == year_digit]
    if not candidate_years:
        candidate_years = [ref_year]
    best_year = min(
        candidate_years,
        key=lambda yy: (
            abs((yy * 12 + mm) - target_month),
            0 if (yy * 12 + mm) >= target_month - 1 else 1,
            yy,
        ),
    )
    return f"{best_year:04d}{mm:02d}"


def probexp_fetch_json_via_http(url: str, *, timeout: float = 10.0) -> Any:
    req = urllib_request.Request(
        url,
        headers={
            "User-Agent": (
                "Mozilla/5.0 (Windows NT 10.0; Win64; x64) "
                "AppleWebKit/537.36 (KHTML, like Gecko) "
                "Chrome/135.0.0.0 Safari/537.36"
            ),
            "Accept": "application/json,text/plain,*/*",
        },
    )
    with urllib_request.urlopen(req, timeout=timeout) as resp:
        charset = resp.headers.get_content_charset() or "utf-8"
        raw = resp.read()
    return json.loads(raw.decode(charset, errors="replace"))


def probexp_extract_openvlab_dto_atm_iv(
    payload: Mapping[str, Any],
    *,
    underlying_series: str,
    current_close: float,
) -> Dict[str, Any]:
    out = {
        "ok": False,
        "atm_iv": None,
        "contract": "",
        "strike": None,
        "skew": None,
        "reason": "OpenVlab 期权链未返回可用 ATM IV",
    }
    result = payload.get("result") if isinstance(payload, Mapping) else None
    context = result.get("context") if isinstance(result, Mapping) else None
    chain_map = context.get("c") if isinstance(context, Mapping) else None
    if not isinstance(chain_map, Mapping) or not chain_map:
        return out
    series_key = str(underlying_series or "").upper().strip()
    chain = chain_map.get(series_key) if series_key else None
    if not isinstance(chain, Mapping):
        for key, value in chain_map.items():
            if str(key).upper().strip() == series_key:
                chain = value
                break
    if not isinstance(chain, Mapping):
        if len(chain_map) == 1:
            chain = next(iter(chain_map.values()))
        else:
            return out
    strikes_map = chain.get("s") if isinstance(chain, Mapping) else None
    if not isinstance(strikes_map, Mapping) or not strikes_map:
        return out
    rows: List[Dict[str, Any]] = []
    for strike_txt, pair in strikes_map.items():
        if not isinstance(pair, Mapping):
            continue
        strike = to_float(strike_txt)
        if strike is None:
            strike = to_float(pair.get("strike"))
        if strike is None:
            continue
        iv_list: List[float] = []
        contracts: List[str] = []
        oi_sum = 0.0
        vol_sum = 0.0
        for side_key in ["c", "p"]:
            leg = pair.get(side_key)
            if not isinstance(leg, Mapping):
                continue
            leg_iv = to_float(leg.get("iv"))
            if leg_iv is not None and float(leg_iv) > 1e-12:
                iv_list.append(float(leg_iv))
            leg_contract = str(pick_first(leg.get("cc"), "") or "").strip()
            if leg_contract:
                contracts.append(leg_contract)
            oi_sum += float(pick_first(to_float(leg.get("o")), 0.0) or 0.0)
            vol_sum += float(pick_first(to_float(leg.get("v")), 0.0) or 0.0)
        if not iv_list:
            continue
        rows.append(
            {
                "strike": float(strike),
                "atm_gap": abs(float(strike) - float(current_close)),
                "atm_iv": float(np.mean(iv_list)),
                "oi": float(oi_sum),
                "vol": float(vol_sum),
                "score": float(oi_sum + vol_sum),
                "contract": " / ".join(contracts[:2]),
            }
        )
    if not rows:
        return out
    work = pd.DataFrame(rows)
    min_gap = float(work["atm_gap"].min())
    atm_pool = work[np.isclose(work["atm_gap"], min_gap, atol=1e-9)].copy()
    if atm_pool.empty:
        atm_pool = work.sort_values(["atm_gap", "score", "oi", "vol"], ascending=[True, False, False, False]).head(1).copy()
    atm_pool = atm_pool.sort_values(["score", "oi", "vol"], ascending=[False, False, False]).copy()
    pick_row = atm_pool.iloc[0]
    atm_iv = float(pd.to_numeric(atm_pool.get("atm_iv"), errors="coerce").fillna(0.0).mean())
    if atm_iv <= 1e-12:
        return out
    return {
        "ok": True,
        "atm_iv": float(atm_iv),
        "contract": str(pick_first(pick_row.get("contract"), "") or "").strip(),
        "strike": float(pick_first(to_float(pick_row.get("strike")), 0.0) or 0.0),
        "skew": None,
        "reason": "",
    }


def probexp_fetch_openvlab_atm_iv(
    *,
    underlying: Any,
    rep_date: str,
    current_close: Any,
) -> Dict[str, Any]:
    empty = {
        "ok": False,
        "atm_iv": None,
        "source": "",
        "reason": "OpenVlab 自动 IV 暂不可用",
        "contract": "",
        "strike": None,
        "skew": None,
    }
    current_close_num = to_float(current_close)
    if current_close_num is None or float(current_close_num) <= 1e-12:
        out = dict(empty)
        out["reason"] = "缺少当前收盘价"
        return out
    product_code = probexp_underlying_product_code(underlying)
    exp_month = probexp_underlying_exp_month(underlying, rep_date)
    underlying_series = probexp_underlying_series(underlying)
    if (not product_code) or (not exp_month):
        out = dict(empty)
        out["reason"] = "OpenVlab 未能解析当前结构的合约月份"
        return out
    contract_code = f"{product_code}{exp_month[-4:]}"
    cache_key = (f"{product_code}|{exp_month}", str(rep_date))
    cached = _PROBEXP_OPENVLAB_IV_CACHE.get(cache_key)
    if isinstance(cached, dict):
        return dict(cached)
    indicator_url = f"{PROBEXP_OPENVLAB_BASE_URL}/api/get-indicators/{urllib_parse.quote(product_code)}/{urllib_parse.quote(exp_month)}"
    dto_url = f"{PROBEXP_OPENVLAB_BASE_URL}/api/dto/{urllib_parse.quote(product_code)}?{urllib_parse.urlencode({'exps': exp_month})}"
    last_reason = ""
    try:
        payload = probexp_fetch_json_via_http(indicator_url, timeout=10.0)
        result = payload.get("result") if isinstance(payload, Mapping) else None
        atm_iv = to_float(result.get("atmv")) if isinstance(result, Mapping) else None
        skew = to_float(result.get("skew")) if isinstance(result, Mapping) else None
        if atm_iv is not None and float(atm_iv) > 1e-12:
            out = {
                "ok": True,
                "atm_iv": float(atm_iv),
                "source": f"OpenVlab-{contract_code}",
                "reason": "",
                "contract": contract_code,
                "strike": None,
                "skew": float(skew) if skew is not None else None,
            }
            _PROBEXP_OPENVLAB_IV_CACHE[cache_key] = dict(out)
            return out
        last_reason = f"OpenVlab 指标接口未返回可用 ATM IV（{contract_code}）"
    except (urllib_error.URLError, TimeoutError, json.JSONDecodeError, ValueError) as exc:
        last_reason = f"OpenVlab 指标接口获取失败（{contract_code}）：{exc}"
    except Exception as exc:
        last_reason = f"OpenVlab 指标接口获取失败（{contract_code}）：{exc}"
    try:
        payload = probexp_fetch_json_via_http(dto_url, timeout=10.0)
        dto_rec = probexp_extract_openvlab_dto_atm_iv(
            payload,
            underlying_series=underlying_series or contract_code,
            current_close=float(current_close_num),
        )
        if bool(dto_rec.get("ok")):
            out = {
                "ok": True,
                "atm_iv": float(pick_first(to_float(dto_rec.get("atm_iv")), 0.0) or 0.0),
                "source": f"OpenVlab-{contract_code}",
                "reason": "",
                "contract": str(pick_first(dto_rec.get("contract"), contract_code) or contract_code),
                "strike": to_float(dto_rec.get("strike")),
                "skew": to_float(dto_rec.get("skew")),
            }
            _PROBEXP_OPENVLAB_IV_CACHE[cache_key] = dict(out)
            return out
        dto_reason = str(pick_first(dto_rec.get("reason"), "") or "").strip()
        if dto_reason:
            last_reason = dto_reason
    except (urllib_error.URLError, TimeoutError, json.JSONDecodeError, ValueError) as exc:
        if not last_reason:
            last_reason = f"OpenVlab 期权链接口获取失败（{contract_code}）：{exc}"
    except Exception as exc:
        if not last_reason:
            last_reason = f"OpenVlab 期权链接口获取失败（{contract_code}）：{exc}"
    out = dict(empty)
    out["reason"] = last_reason or f"OpenVlab 自动 IV 暂不可用（{contract_code}）"
    _PROBEXP_OPENVLAB_IV_CACHE[cache_key] = dict(out)
    return out


def probexp_format_position_tons(value: Any, *, zero_text: str = "空仓") -> str:
    num = float(pick_first(to_float(value), 0.0) or 0.0)
    if abs(num) <= 1e-12:
        return str(zero_text)
    side = "多头" if num > 0 else "空头"
    return f"{side} {abs(num):,.2f} 吨"


def probexp_humanize_auto_iv_reason(reason: Any, *, exchange: str = "", symbol: str = "") -> str:
    txt = str(pick_first(reason, "") or "").strip()
    ex = str(exchange or "").upper().strip()
    sym = str(symbol or "").strip()
    if not txt:
        return "自动 IV 源暂不可用"
    if "OpenVlab" in txt:
        return txt
    if ("Expecting value" in txt) or ("JSONDecodeError" in txt):
        if ex == "DCE":
            return f"{sym or '该品种'}自动 IV 源返回空响应或被交易所拦截，已回退到已保存值或默认值"
        return f"{sym or '该品种'}自动 IV 源返回空响应，已回退到已保存值或默认值"
    if ("412" in txt) or ("403" in txt):
        return f"{sym or '该品种'}自动 IV 源暂时拒绝访问，已回退到已保存值或默认值"
    if "已回退到已保存值或默认值" in txt:
        return txt
    if "缺少当前收盘价" in txt or "监控日期无效" in txt:
        return txt
    if "暂无" in txt or "未配置" in txt or "不可用" in txt:
        return txt
    if "期权行情为空" in txt or "缺少有效 IV 数据" in txt:
        return f"{sym or '该品种'}当日未取到可用 IV，已回退到已保存值或默认值"
    return f"{sym or '该品种'}自动 IV 获取失败，已回退到已保存值或默认值"


def probexp_build_gap_snapshot(
    *,
    struct_row_raw: Any,
    prices_df: pd.DataFrame,
    close2_df: pd.DataFrame,
    rep_date: str,
) -> Dict[str, Any]:
    empty = {
        "remaining_oscillation_scale": 0.0,
        "remaining_knockin_max_scale": 0.0,
        "remaining_subsidy_scale": 0.0,
        "remaining_observe_days": 0,
        "missing_dates": "",
    }
    if struct_row_raw is None:
        return empty
    try:
        sub_structs = pd.DataFrame([dict(struct_row_raw)])
    except Exception:
        return empty
    if sub_structs.empty:
        return empty
    prices_asof = prices_df.copy() if prices_df is not None else pd.DataFrame()
    rep_date_obj = parse_date_maybe(rep_date)
    if (not prices_asof.empty) and isinstance(rep_date_obj, date):
        dt_asof_series = pd.to_datetime(prices_asof["dt"], errors="coerce").dt.date
        prices_asof = prices_asof[dt_asof_series <= rep_date_obj].copy()
    try:
        gap_df = compute_price_gap_table(
            sub_structs,
            prices_asof,
            close2_df,
            as_of_date=rep_date_obj,
        )
    except Exception:
        return empty
    if gap_df.empty:
        return empty
    rr = gap_df.iloc[-1]
    return {
        "remaining_oscillation_scale": float(
            pick_first(to_float(rr.get("剩余震荡最小头寸规模")), 0.0) or 0.0
        ),
        "remaining_knockin_max_scale": float(
            pick_first(to_float(rr.get("剩余震荡最大头寸规模")), 0.0) or 0.0
        ),
        "remaining_subsidy_scale": float(
            pick_first(to_float(rr.get("剩余震荡最大补贴规模")), 0.0) or 0.0
        ),
        "remaining_observe_days": int(
            pick_first(_int_from_any(rr.get("剩余观察交易日"), 0), 0) or 0
        ),
        "missing_dates": str(pick_first(rr.get("缺失日期列表"), "") or "").strip(),
    }


def probexp_build_structure_stock_qty_map(
    *,
    struct_asof: pd.DataFrame,
    close2_df: pd.DataFrame,
    rep_gid: str,
    rep_date: str,
    rep_und: str,
    rep_und_all: bool,
) -> Dict[str, float]:
    if struct_asof is None or struct_asof.empty:
        return {}
    wh_cut = struct_asof.copy()
    if "date" in wh_cut.columns:
        dt_ser = pd.to_datetime(wh_cut["date"], errors="coerce").dt.date
        rep_date_obj = parse_date_maybe(rep_date)
        if isinstance(rep_date_obj, date):
            wh_cut = wh_cut[dt_ser.notna() & (dt_ser <= rep_date_obj)].copy()
    if wh_cut.empty:
        return {}

    c2_group = pd.DataFrame()
    if close2_df is not None and not close2_df.empty:
        c2_group = close2_df[close2_df["group_id"].astype(str) == str(rep_gid)].copy()
        if not rep_und_all and str(rep_und).strip():
            c2_group = c2_group[c2_group["underlying"].astype(str) == str(rep_und)].copy()
        if not c2_group.empty and "dt" in c2_group.columns:
            c2_group["dt"] = c2_group["dt"].astype(str)
            c2_group = c2_group[c2_group["dt"] <= str(rep_date)].copy()
    try:
        wh_open = build_open_lot_rows(wh_cut, c2_group, str(rep_date))
    except Exception:
        return {}
    if wh_open is None or wh_open.empty:
        return {}
    return (
        wh_open.groupby(wh_open["structure_id"].astype(str))["open_qty"]
        .sum()
        .astype(float)
        .to_dict()
    )


def probexp_fetch_auto_atm_iv(
    *,
    underlying: Any,
    rep_date: str,
    current_close: Any,
) -> Dict[str, Any]:
    empty = {
        "ok": False,
        "atm_iv": None,
        "source": "",
        "reason": "自动 IV 源暂不可用",
        "contract": "",
        "strike": None,
    }
    current_close_num = to_float(current_close)
    if current_close_num is None or float(current_close_num) <= 1e-12:
        out = dict(empty)
        out["reason"] = "缺少当前收盘价"
        return out
    rep_date_obj = parse_date_maybe(rep_date)
    if not isinstance(rep_date_obj, date):
        out = dict(empty)
        out["reason"] = "监控日期无效"
        return out
    und_norm = _normalize_underlying_symbol(underlying)
    product_code = probexp_underlying_product_code(und_norm)
    underlying_series = probexp_underlying_series(und_norm)
    openvlab_rec = probexp_fetch_openvlab_atm_iv(
        underlying=underlying,
        rep_date=rep_date,
        current_close=current_close,
    )
    if bool(openvlab_rec.get("ok")):
        return openvlab_rec
    openvlab_reason = str(pick_first(openvlab_rec.get("reason"), "") or "").strip()
    if ak is None:
        out = dict(empty)
        out["reason"] = openvlab_reason or "AKShare 不可用"
        return out
    meta = (
        PROBEXP_AK_OPTION_SYMBOL_MAP.get(und_norm)
        or PROBEXP_AK_OPTION_SYMBOL_MAP.get(product_code)
        or {}
    )
    if not meta:
        out = dict(empty)
        out["reason"] = openvlab_reason or f"暂未配置 {und_norm or product_code or '该品种'} 的 AKShare IV 映射"
        return out
    api_mode = str(meta.get("api", "hist") or "hist").strip().lower()
    exchange = str(meta.get("exchange", "")).upper().strip()
    symbol = str(meta.get("symbol", "")).strip()
    cache_key = (f"{exchange}|{api_mode}|{symbol}", rep_date_obj.strftime("%Y%m%d"))
    if cache_key in _PROBEXP_AK_IV_CACHE:
        table_rec = _PROBEXP_AK_IV_CACHE[cache_key]
    else:
        table_rec = {"ok": False, "df": pd.DataFrame(), "reason": "AKShare 未返回数据"}
        try:
            fetch_name = ""
            if exchange == "DCE":
                fetch_name = "option_hist_dce"
            elif exchange == "CZCE":
                fetch_name = "option_hist_czce"
            elif exchange == "GFEX":
                fetch_name = "option_hist_gfex" if api_mode == "hist" else "option_vol_gfex"
            elif exchange == "SHFE":
                fetch_name = "option_vol_shfe" if api_mode == "vol" else "option_hist_shfe"
            if fetch_name:
                fetch_fn = getattr(ak, fetch_name, None)
                if callable(fetch_fn):
                    try:
                        raw_df = fetch_fn(symbol=symbol, trade_date=rep_date_obj.strftime("%Y%m%d"))
                    except TypeError:
                        raw_df = fetch_fn(symbol, rep_date_obj.strftime("%Y%m%d"))
                    if isinstance(raw_df, pd.DataFrame) and not raw_df.empty:
                        table_rec = {"ok": True, "df": raw_df.copy(), "reason": "", "api": fetch_name}
                    else:
                        table_rec["reason"] = "AKShare 期权行情为空"
                else:
                    table_rec["reason"] = f"当前 AKShare 未提供 {fetch_name} 接口"
            else:
                table_rec["reason"] = f"暂未接入 {exchange or '未知交易所'} 的期权 IV 接口"
        except Exception as exc:
            table_rec["reason"] = probexp_humanize_auto_iv_reason(
                str(exc),
                exchange=exchange,
                symbol=symbol,
            )
        _PROBEXP_AK_IV_CACHE[cache_key] = table_rec

    if not bool(table_rec.get("ok")):
        out = dict(empty)
        ak_reason = probexp_humanize_auto_iv_reason(
            table_rec.get("reason"),
            exchange=exchange,
            symbol=symbol,
        )
        out["reason"] = openvlab_reason or ak_reason
        return out

    df = table_rec.get("df")
    if not isinstance(df, pd.DataFrame) or df.empty:
        out = dict(empty)
        out["reason"] = probexp_humanize_auto_iv_reason("AKShare 期权行情为空", exchange=exchange, symbol=symbol)
        return out

    work = df.copy()
    contract_col = _pick_ak_col(df, ["合约", "合约代码", "合约名称", "contract", "symbol", "期权合约代码", "合约系列"])
    iv_col = _pick_ak_col(df, ["隐含波动率(%)", "隐含波动率", "IV", "iv", "implied_volatility"])
    oi_col = _pick_ak_col(df, ["持仓量", "open_interest", "持仓"])
    vol_col = _pick_ak_col(df, ["成交量", "成交量(手)", "volume"])
    if not iv_col:
        out = dict(empty)
        out["reason"] = probexp_humanize_auto_iv_reason("AKShare 期权表缺少有效 IV 数据", exchange=exchange, symbol=symbol)
        return out
    work[iv_col] = pd.to_numeric(work[iv_col], errors="coerce")
    if oi_col:
        work[oi_col] = pd.to_numeric(work[oi_col], errors="coerce").fillna(0.0)
    else:
        work["__oi__"] = 0.0
        oi_col = "__oi__"
    if vol_col:
        work[vol_col] = pd.to_numeric(work[vol_col], errors="coerce").fillna(0.0)
    else:
        work["__vol__"] = 0.0
        vol_col = "__vol__"

    if contract_col:
        work["__contract__"] = work[contract_col].astype(str).fillna("")
        work["__series__"] = work["__contract__"].map(probexp_extract_contract_series)
    else:
        work["__contract__"] = ""
        work["__series__"] = ""

    if api_mode == "vol":
        work = work.dropna(subset=[iv_col]).copy()
        if work.empty:
            out = dict(empty)
            out["reason"] = probexp_humanize_auto_iv_reason("AKShare 期权表缺少有效 IV 数据", exchange=exchange, symbol=symbol)
            return out
        if underlying_series:
            exact_series = work[work["__series__"].astype(str).str.upper() == underlying_series].copy()
            if not exact_series.empty:
                work = exact_series
        work = work.sort_values([oi_col, vol_col], ascending=[False, False]).copy()
        pick_row = work.iloc[0]
        atm_iv = float(pd.to_numeric(pick_row.get(iv_col), errors="coerce"))
        if str(iv_col).strip() == "隐含波动率" and atm_iv <= 3.0:
            atm_iv *= 100.0
        if atm_iv <= 1e-12:
            out = dict(empty)
            out["reason"] = probexp_humanize_auto_iv_reason("AKShare 返回的 ATM IV 无效", exchange=exchange, symbol=symbol)
            return out
        contract_name = str(pick_first(pick_row.get(contract_col) if contract_col else None, pick_row.get("__series__"), "") or "").strip()
        return {
            "ok": True,
            "atm_iv": float(atm_iv),
            "source": f"AKShare-{symbol}",
            "reason": "",
            "contract": contract_name,
            "strike": None,
        }

    strike_col = _pick_ak_col(df, ["行权价", "执行价", "strike", "strike_price"])
    if strike_col:
        work[strike_col] = pd.to_numeric(work[strike_col], errors="coerce")
    else:
        work["__strike__"] = work["__contract__"].map(probexp_extract_strike_from_contract)
        strike_col = "__strike__"

    work = work.dropna(subset=[strike_col, iv_col]).copy()
    if work.empty:
        out = dict(empty)
        out["reason"] = probexp_humanize_auto_iv_reason("AKShare 期权表缺少有效 IV 数据", exchange=exchange, symbol=symbol)
        return out
    if underlying_series:
        same_series = work[work["__series__"].astype(str).str.upper() == underlying_series].copy()
        if not same_series.empty:
            work = same_series
    work["__atm_gap__"] = (pd.to_numeric(work[strike_col], errors="coerce") - float(current_close_num)).abs()
    work = work.dropna(subset=["__atm_gap__"]).copy()
    if work.empty:
        out = dict(empty)
        out["reason"] = probexp_humanize_auto_iv_reason("AKShare 期权表缺少有效 IV 数据", exchange=exchange, symbol=symbol)
        return out
    min_gap = float(work["__atm_gap__"].min())
    atm_pool = work[np.isclose(work["__atm_gap__"], min_gap, atol=1e-9)].copy()
    if atm_pool.empty:
        atm_pool = work.sort_values(["__atm_gap__", oi_col, vol_col], ascending=[True, False, False]).head(1).copy()
    best_series = ""
    if underlying_series and (atm_pool["__series__"].astype(str).str.upper() == underlying_series).any():
        best_series = underlying_series
    elif "__series__" in atm_pool.columns and (atm_pool["__series__"].astype(str).str.strip() != "").any():
        series_score = (
            atm_pool.assign(
                __score__=pd.to_numeric(atm_pool.get(oi_col), errors="coerce").fillna(0.0)
                + pd.to_numeric(atm_pool.get(vol_col), errors="coerce").fillna(0.0)
            )
            .groupby("__series__", as_index=False)["__score__"]
            .sum()
            .sort_values(["__score__", "__series__"], ascending=[False, True])
        )
        if not series_score.empty:
            best_series = str(series_score.iloc[0]["__series__"]).strip().upper()
    if best_series:
        atm_pool = atm_pool[atm_pool["__series__"].astype(str).str.upper() == best_series].copy()
    atm_pool = atm_pool.sort_values([oi_col, vol_col], ascending=[False, False]).copy()
    pick_row = atm_pool.iloc[0]
    atm_iv = float(pd.to_numeric(atm_pool.get(iv_col), errors="coerce").fillna(0.0).mean())
    if str(iv_col).strip() == "隐含波动率" and atm_iv <= 3.0:
        atm_iv *= 100.0
    if contract_col:
        contract_values = [str(x).strip() for x in atm_pool[contract_col].astype(str).dropna().tolist() if str(x).strip()]
        contract_name = " / ".join(contract_values[:2])
    else:
        contract_name = ""
    strike_used = to_float(pick_row.get(strike_col))
    if atm_iv <= 1e-12:
        out = dict(empty)
        out["reason"] = probexp_humanize_auto_iv_reason("AKShare 返回的 ATM IV 无效", exchange=exchange, symbol=symbol)
        return out
    return {
        "ok": True,
        "atm_iv": float(atm_iv),
        "source": f"AKShare-{symbol}",
        "reason": "",
        "contract": contract_name,
        "strike": strike_used,
    }


def probexp_effect_summary(struct_row: Mapping[str, Any]) -> Tuple[str, str]:
    strategy_code = resolve_strategy_code_for_display(struct_row.get("strategy_code", ""))
    kind_code = normalize_kind_code(struct_row.get("kind", ""))
    side_cn = "累购" if kind_code == "ACC" else "累沽" if kind_code == "DEC" else "累计"
    base_qty = max(float(pick_first(to_float(struct_row.get("base_qty_per_day")), 0.0) or 0.0), 0.0)
    multiple = max(float(pick_first(to_float(struct_row.get("multiple")), 3.0) or 0.0), 0.0)
    meta = struct_row.get("meta", {}) if isinstance(struct_row.get("meta", {}), dict) else {}
    legacy_mode = str(meta.get("_legacy_mode", "")).upper()
    if strategy_code == "BASIC_RANGE":
        if legacy_mode == "FIXED_PART":
            return (
                "旧固定倍数累计",
                f"未来每个观察日固定生成 {multiple:.2f} 倍日基准量，即 {base_qty * multiple:,.2f} 吨。",
            )
        return (
            "普通累计",
            f"{side_cn}结构按真实条款分为三段：震荡日生成 1 倍、敲入日生成 {multiple:.2f} 倍、敲出日生成 0 倍。"
            " 如果该笔结构启用了敲出终止，敲出后剩余观察日不再继续生成。",
        )
    if strategy_code == "NO_KO":
        return (
            "无敲出累计",
            f"{side_cn}结构只有震荡 1 倍和敲入 {multiple:.2f} 倍两种生成结果，不存在敲出终止。",
        )
    if strategy_code == "FLOAT_KO":
        return (
            "浮动熔断累计",
            f"{side_cn}结构有三种结果：震荡 1 倍、敲入 {multiple:.2f} 倍、敲出当日一次性补齐剩余基础量并终止观察。",
        )
    if strategy_code == "FIXED_SUBSIDY":
        return (
            "固赔熔断累计",
            f"{side_cn}结构保留震荡 1 倍和敲入 {multiple:.2f} 倍；敲出后期货生成终止，剩余部分只记补贴，不再算吨数。",
        )
    if strategy_code == "PREMIUM_SUBSIDY":
        return (
            "溢价累计",
            f"{side_cn}结构只有敲入日才生成 {multiple:.2f} 倍；不敲入日只给补贴，期货生成按 0 吨处理。",
        )
    if strategy_code == "RANGE_SUBSIDY":
        return (
            "区间补贴累计",
            f"{side_cn}结构敲入日生成 {multiple:.2f} 倍，中间区间只给补贴不生成吨数，敲出日也不生成但继续观察。",
        )
    return ("累计结构", "专项页仅跟踪累计类结构的未来生成吨数分布，不纳入现货与补贴盈亏。")


def probexp_format_tons(value: Any, *, signed: bool = False) -> str:
    num = float(pick_first(to_float(value), 0.0) or 0.0)
    fmt = f"{num:+,.2f}" if signed else f"{num:,.2f}"
    return f"{fmt} 吨"


def probexp_pick_close_price(prices_df: pd.DataFrame, underlying: Any, as_of_date: Any) -> Optional[float]:
    if prices_df is None or prices_df.empty:
        return None
    und_s = _normalize_underlying_symbol(underlying)
    as_of_d = parse_date_maybe(as_of_date)
    if not und_s or as_of_d is None:
        return None
    sub = prices_df[prices_df["underlying"].astype(str).map(_normalize_underlying_symbol) == und_s].copy()
    if sub.empty:
        return None
    sub["_dt"] = pd.to_datetime(sub["dt"], errors="coerce").dt.date
    sub = sub[sub["_dt"].notna() & (sub["_dt"] <= as_of_d)].copy()
    if sub.empty:
        return None
    sub = sub.sort_values(["_dt", "dt"])
    px = to_float(sub.iloc[-1].get("settle"))
    return float(px) if px is not None else None


def probexp_describe_adjustment(current_position: Any, target_position: Any) -> str:
    cur = float(pick_first(to_float(current_position), 0.0) or 0.0)
    tgt = float(pick_first(to_float(target_position), 0.0) or 0.0)
    if abs(tgt - cur) <= 1e-12:
        return "不调整"
    actions: List[str] = []
    if cur > 0:
        if tgt >= 0:
            delta = tgt - cur
            if delta > 1e-12:
                actions.append(f"开多 {abs(delta):,.2f} 吨")
            elif delta < -1e-12:
                actions.append(f"平多 {abs(delta):,.2f} 吨")
        else:
            actions.append(f"平多 {abs(cur):,.2f} 吨")
            actions.append(f"开空 {abs(tgt):,.2f} 吨")
    elif cur < 0:
        if tgt <= 0:
            delta = abs(tgt) - abs(cur)
            if delta > 1e-12:
                actions.append(f"开空 {abs(delta):,.2f} 吨")
            elif delta < -1e-12:
                actions.append(f"平空 {abs(delta):,.2f} 吨")
        else:
            actions.append(f"平空 {abs(cur):,.2f} 吨")
            actions.append(f"开多 {abs(tgt):,.2f} 吨")
    else:
        if tgt > 1e-12:
            actions.append(f"开多 {abs(tgt):,.2f} 吨")
        elif tgt < -1e-12:
            actions.append(f"开空 {abs(tgt):,.2f} 吨")
    return "，再".join(actions) if actions else "不调整"


def probexp_build_structure_candidates(
    *,
    structs_df: pd.DataFrame,
    struct_asof: pd.DataFrame,
    bounds_asof: pd.DataFrame,
    prices_df: pd.DataFrame,
    close2_df: pd.DataFrame,
    rep_gid: str,
    rep_date: str,
    rep_und: str,
    rep_und_all: bool,
) -> List[Dict[str, Any]]:
    if structs_df is None or structs_df.empty:
        return []
    rep_date_obj = parse_date_maybe(rep_date)
    sub = structs_df[structs_df["group_id"].astype(str) == str(rep_gid)].copy()
    if not rep_und_all:
        sub = sub[sub["underlying"].astype(str) == str(rep_und)].copy()
    if sub.empty:
        return []

    stock_qty_map = probexp_build_structure_stock_qty_map(
        struct_asof=struct_asof,
        close2_df=close2_df,
        rep_gid=str(rep_gid),
        rep_date=str(rep_date),
        rep_und=str(rep_und),
        rep_und_all=bool(rep_und_all),
    )

    detail_map: Dict[str, pd.Series] = {}
    if struct_asof is not None and not struct_asof.empty:
        latest = (
            struct_asof.sort_values(["date", "structure_id"])
            .groupby("structure_id", as_index=False)
            .tail(1)
            .copy()
        )
        for _, rr in latest.iterrows():
            sid = str(pick_first(rr.get("structure_id"), "")).strip()
            if sid:
                detail_map[sid] = rr

    bounds_map: Dict[str, pd.Series] = {}
    if bounds_asof is not None and not bounds_asof.empty:
        bsub = bounds_asof[bounds_asof["level"].astype(str).str.upper().eq("STRUCTURE")].copy()
        for _, rr in bsub.iterrows():
            sid = str(pick_first(rr.get("structure_id"), "")).strip()
            if sid:
                bounds_map[sid] = rr

    manual_close_map = build_manual_close_date_map(close2_df, group_id=str(rep_gid), as_of_date=rep_date_obj)
    melt_date_map = build_melt_date_map(struct_asof, group_id=str(rep_gid), as_of_date=rep_date_obj)
    rows: List[Dict[str, Any]] = []

    for _, raw in sub.iterrows():
        resolved = resolve_structure_row(raw)
        if not probexp_is_accumulator_structure(resolved):
            continue
        sid = str(resolved.get("structure_id", "")).strip()
        if not sid:
            continue
        sd = parse_date_maybe(resolved.get("start_date"))
        ed = parse_date_maybe(resolved.get("end_date"))
        if sd is None or ed is None:
            continue
        total_days = len(trading_days_between(sd, ed))
        latest = detail_map.get(sid)
        bounds_row = bounds_map.get(sid)
        observed_qty = float(pick_first(to_float(latest.get("cum_qty")) if latest is not None else None, 0.0) or 0.0)
        observed_days = int(
            pick_first(
                _int_from_any(latest.get("observed_trading_days"), 0) if latest is not None else 0,
                0,
            )
            or 0
        )
        remaining_days = int(
            pick_first(
                _int_from_any(bounds_row.get("remaining_trading_days"), 0) if bounds_row is not None else None,
                0,
            )
            or 0
        )
        if bounds_row is None:
            if rep_date_obj is None or rep_date_obj < sd:
                remaining_days = total_days
            elif rep_date_obj > ed:
                remaining_days = 0
            else:
                remaining_days = len(trading_days_between(max(rep_date_obj + timedelta(days=1), sd), ed))
        if sid in manual_close_map:
            status_cn = "已手动终结"
            remaining_days = 0
        elif sid in melt_date_map:
            status_cn = "敲出熔断"
            remaining_days = 0
        elif latest is not None:
            status_cn = status_to_cn(
                str(pick_first(latest.get("status"), "")),
                float(pick_first(to_float(latest.get("generated_qty")), 0.0) or 0.0),
                float(pick_first(to_float(latest.get("multiplier")), 0.0) or 0.0),
            )
        elif rep_date_obj is not None and rep_date_obj < sd:
            status_cn = "未开始"
        else:
            status_cn = "缺少价格"
        current_close = float(
            pick_first(
                to_float(latest.get("settle")) if latest is not None else None,
                probexp_pick_close_price(prices_df, resolved.get("underlying"), rep_date),
                0.0,
            )
            or 0.0
        )
        label = structure_detail_label_unified(
            structure_id=resolved.get("structure_id", ""),
            strategy_value=resolved.get("strategy_code", ""),
            kind_value=resolved.get("kind", ""),
            fallback_name=resolved.get("name", ""),
            risk_party=resolved.get("risk_party", ""),
            entry_price=resolved.get("entry_price"),
            strike_price=resolved.get("strike_price"),
            knock_in_price=resolved.get("barrier_in"),
            barrier_price=resolve_display_barrier_price(
                resolved.get("strategy_code", ""),
                barrier_out=resolved.get("barrier_out"),
                barrier_in=resolved.get("barrier_in"),
                strike_price=resolved.get("strike_price"),
            ),
        )
        direction_sign = 1.0 if str(resolved.get("kind", "")).upper() == "ACC" else -1.0
        open_qty_now = max(
            float(pick_first(to_float(latest.get("current_open_qty")) if latest is not None else None, 0.0) or 0.0),
            0.0,
        )
        stock_qty_now = float(
            pick_first(
                to_float(stock_qty_map.get(str(sid))),
                open_qty_now,
                0.0,
            )
            or 0.0
        )
        rows.append(
            {
                "structure_id": sid,
                "group_id": str(resolved.get("group_id", "")),
                "underlying": str(resolved.get("underlying", "")),
                "label": label,
                "status_cn": status_cn,
                "resolved": resolved,
                "observed_qty": observed_qty,
                "observed_days": observed_days,
                "remaining_days": max(int(remaining_days), 0),
                "current_close": current_close,
                "total_days": total_days,
                "nominal_target_qty": probexp_infer_initial_target_qty(resolved, total_days),
                "current_position_tons": stock_qty_now,
                "stock_position_qty": stock_qty_now,
                "generated_position_tons": direction_sign * open_qty_now,
                "is_active": bool(max(int(remaining_days), 0) > 0),
                "detail_row": latest,
                "raw_row": raw.to_dict(),
            }
        )

    rows.sort(
        key=lambda x: (
            0 if bool(x.get("is_active", False)) else 1,
            -int(pick_first(x.get("remaining_days"), 0) or 0),
            str(x.get("structure_id", "")),
        )
    )
    return rows


def probexp_build_structure_snapshot(
    *,
    candidate: Dict[str, Any],
    struct_asof: pd.DataFrame,
    prices_df: pd.DataFrame,
    close2_df: pd.DataFrame,
    rep_date: str,
) -> Dict[str, Any]:
    resolved = candidate.get("resolved", {}) if isinstance(candidate.get("resolved", {}), dict) else {}
    sid = str(candidate.get("structure_id", "")).strip()
    rep_date_obj = parse_date_maybe(rep_date)
    detail_df = pd.DataFrame()
    if struct_asof is not None and not struct_asof.empty:
        detail_df = struct_asof[struct_asof["structure_id"].astype(str) == sid].copy()
        if not detail_df.empty:
            detail_df["date"] = pd.to_datetime(detail_df["date"], errors="coerce").dt.date
            detail_df = detail_df[detail_df["date"].notna()].copy()
            if rep_date_obj is not None:
                detail_df = detail_df[detail_df["date"] <= rep_date_obj].copy()
            detail_df = detail_df.sort_values(["date"])

    price_hist = pd.DataFrame(columns=["date", "settle", "generated_qty"])
    if prices_df is not None and not prices_df.empty:
        price_hist = prices_df[
            prices_df["underlying"].astype(str).map(_normalize_underlying_symbol)
            == _normalize_underlying_symbol(resolved.get("underlying"))
        ].copy()
        if not price_hist.empty:
            price_hist["date"] = pd.to_datetime(price_hist["dt"], errors="coerce").dt.date
            price_hist = price_hist[price_hist["date"].notna()].copy()
            sd = parse_date_maybe(resolved.get("start_date"))
            if sd is not None:
                price_hist = price_hist[price_hist["date"] >= sd].copy()
            if rep_date_obj is not None:
                price_hist = price_hist[price_hist["date"] <= rep_date_obj].copy()
            price_hist = price_hist.sort_values(["date"])
            gen_map = (
                detail_df.set_index("date")["generated_qty"].to_dict()
                if not detail_df.empty and {"date", "generated_qty"}.issubset(set(detail_df.columns))
                else {}
            )
            price_hist["generated_qty"] = price_hist["date"].map(lambda d: float(pick_first(to_float(gen_map.get(d)), 0.0) or 0.0))
            price_hist = price_hist[["date", "settle", "generated_qty"]].copy()

    latest_detail = detail_df.iloc[-1] if not detail_df.empty else None
    today_qty = 0.0
    if latest_detail is not None and rep_date_obj is not None and latest_detail.get("date") == rep_date_obj:
        today_qty = float(pick_first(to_float(latest_detail.get("generated_qty")), 0.0) or 0.0)
    effect_title, effect_text = probexp_effect_summary(resolved)
    gap_snapshot = probexp_build_gap_snapshot(
        struct_row_raw=candidate.get("raw_row"),
        prices_df=prices_df,
        close2_df=close2_df,
        rep_date=rep_date,
    )
    remaining_days_display = int(
        pick_first(
            _int_from_any(gap_snapshot.get("remaining_observe_days"), 0),
            candidate.get("remaining_days"),
            0,
        )
        or 0
    )
    return {
        "structure_id": sid,
        "detail_df": detail_df,
        "price_hist": price_hist,
        "latest_detail": latest_detail,
        "today_qty": today_qty,
        "observed_qty": float(pick_first(candidate.get("observed_qty"), 0.0) or 0.0),
        "remaining_days": remaining_days_display,
        "current_close": float(pick_first(candidate.get("current_close"), 0.0) or 0.0),
        "direction_sign": 1.0 if str(resolved.get("kind", "")).upper() == "ACC" else -1.0,
        "direction_cn": direction_display_cn(str(resolved.get("kind", "")).upper()),
        "current_position_tons": float(pick_first(candidate.get("current_position_tons"), 0.0) or 0.0),
        "stock_position_qty": float(pick_first(candidate.get("stock_position_qty"), candidate.get("current_position_tons"), 0.0) or 0.0),
        "total_days": int(pick_first(candidate.get("total_days"), 0) or 0),
        "nominal_target_qty": float(pick_first(candidate.get("nominal_target_qty"), 0.0) or 0.0),
        "gap_snapshot": gap_snapshot,
        "entry_price": to_float(resolved.get("entry_price")),
        "strike_price": to_float(resolved.get("strike_price")),
        "barrier_out": to_float(resolved.get("barrier_out")),
        "knock_out_price": to_float(resolved.get("knock_out_price")),
        "effect_title": effect_title,
        "effect_text": effect_text,
    }


def probexp_simulate_future_qty(
    struct_row: Mapping[str, Any],
    *,
    start_price: float,
    remaining_days: int,
    atm_iv_pct: float,
    skew: float,
    paths: int,
    seed_hint: str = "",
) -> Dict[str, Any]:
    n_days = max(int(remaining_days), 0)
    path_count = int(_int_from_any(paths, PROBEXP_MC_PATHS_DEFAULT, min_value=2000, max_value=PROBEXP_MC_PATHS_MAX))
    zero_paths = np.zeros(path_count, dtype=float)
    if n_days <= 0 or start_price <= 1e-12:
        return {
            "future_qty_paths": zero_paths,
            "quantiles": {label: 0.0 for label, _, _, _ in PROBEXP_QUANTILE_META},
            "mean_future_qty": 0.0,
            "std_future_qty": 0.0,
            "seed": 0,
            "path_count": path_count,
        }

    sigma_atm = max(float(atm_iv_pct) / 100.0, 1e-8)
    skew_val = float(pick_first(to_float(skew), 0.0) or 0.0)
    if abs(skew_val) > 5.0:
        skew_val = skew_val / 100.0
    skew_val = float(np.clip(skew_val, -2.5, 2.5))
    skew_tilt = float(np.tanh(skew_val))
    seed_src = "|".join(
        [
            str(seed_hint or ""),
            str(struct_row.get("structure_id", "")),
            f"{float(start_price):.8f}",
            f"{sigma_atm:.8f}",
            f"{skew_tilt:.8f}",
            str(path_count),
            str(n_days),
        ]
    )
    seed = int(hashlib.sha256(seed_src.encode("utf-8")).hexdigest()[:16], 16) % (2**32 - 1)
    rng = np.random.default_rng(seed)

    code = resolve_strategy_code_for_display(struct_row.get("strategy_code", ""))
    kind = normalize_kind_code(struct_row.get("kind", ""))
    is_acc = kind == "ACC"
    base_qty = max(float(pick_first(to_float(struct_row.get("base_qty_per_day")), 0.0) or 0.0), 0.0)
    strike = float(pick_first(to_float(struct_row.get("strike_price")), to_float(struct_row.get("entry_price")), start_price) or start_price)
    barrier_out = to_float(struct_row.get("barrier_out"))
    knock_out_price = to_float(struct_row.get("knock_out_price"))
    multiple = max(float(pick_first(to_float(struct_row.get("multiple")), 3.0) or 0.0), 0.0)
    meta = struct_row.get("meta", {}) if isinstance(struct_row.get("meta", {}), dict) else {}
    legacy_mode = str(meta.get("_legacy_mode", "")).upper()
    ko_terminate = bool(meta.get("ko_terminate", False))

    dt = 1.0 / 252.0
    sqrt_dt = float(np.sqrt(dt))
    sigma_up = sigma_atm * float(np.exp(0.35 * skew_tilt))
    sigma_dn = sigma_atm * float(np.exp(-0.35 * skew_tilt))

    cur_px = np.full(path_count, float(start_price), dtype=float)
    future_qty = np.zeros(path_count, dtype=float)
    active = np.ones(path_count, dtype=bool)

    for step in range(n_days):
        active_idx = np.where(active)[0]
        if active_idx.size == 0:
            break
        half_n = (int(active_idx.size) + 1) // 2
        z_half = rng.standard_normal(half_n)
        z = np.concatenate([z_half, -z_half])[: int(active_idx.size)]
        sigma_vec = np.where(z >= 0.0, sigma_up, sigma_dn)
        log_ret = (-0.5 * np.square(sigma_vec) * dt) + sigma_vec * sqrt_dt * z
        px_next = np.maximum(cur_px[active_idx] * np.exp(log_ret), 1e-8)
        qty = np.zeros(int(active_idx.size), dtype=float)
        deactivate_mask = np.zeros(int(active_idx.size), dtype=bool)

        if code == "BASIC_RANGE" and legacy_mode == "FIXED_PART":
            qty[:] = base_qty * multiple
        elif code == "BASIC_RANGE" and legacy_mode == "BASIC_MULT":
            if is_acc:
                ko_hit = (knock_out_price is not None) and (px_next >= float(knock_out_price))
                ki_hit = px_next <= strike
                qty[ko_hit] = 0.0
                qty[(~ko_hit) & ki_hit] = base_qty * multiple
                qty[(~ko_hit) & (~ki_hit)] = base_qty
            else:
                ko_hit = px_next <= strike
                ki_hit = (knock_out_price is not None) and (px_next >= float(knock_out_price))
                qty[ko_hit] = 0.0
                qty[(~ko_hit) & ki_hit] = base_qty * multiple
                qty[(~ko_hit) & (~ki_hit)] = base_qty
        elif code == "NO_KO":
            ki_hit = px_next <= strike if is_acc else px_next >= strike
            qty[ki_hit] = base_qty * multiple
            qty[~ki_hit] = base_qty
        elif code == "FLOAT_KO":
            ki_level = barrier_out if barrier_out is not None else strike
            ko_level = knock_out_price if knock_out_price is not None else barrier_out
            if ko_level is None:
                ko_level = barrier_out
            ko_hit = np.zeros(int(active_idx.size), dtype=bool)
            if ko_level is not None:
                ko_hit = px_next >= float(ko_level) if is_acc else px_next <= float(ko_level)
            ki_hit = px_next <= float(ki_level) if is_acc else px_next >= float(ki_level)
            qty[ko_hit] = base_qty * float(max(n_days - step, 0))
            deactivate_mask = ko_hit.copy()
            qty[(~ko_hit) & ki_hit] = base_qty * multiple
            qty[(~ko_hit) & (~ki_hit)] = base_qty
        elif code == "FIXED_SUBSIDY":
            ko_level = barrier_out if barrier_out is not None else knock_out_price
            ko_hit = np.zeros(int(active_idx.size), dtype=bool)
            if ko_level is not None:
                ko_hit = px_next >= float(ko_level) if is_acc else px_next <= float(ko_level)
            ki_hit = px_next <= strike if is_acc else px_next >= strike
            deactivate_mask = ko_hit.copy()
            qty[(~ko_hit) & ki_hit] = base_qty * multiple
            qty[(~ko_hit) & (~ki_hit)] = base_qty
        elif code == "PREMIUM_SUBSIDY":
            ki_hit = px_next <= strike if is_acc else px_next >= strike
            qty[ki_hit] = base_qty * multiple
        elif code == "RANGE_SUBSIDY":
            if barrier_out is None:
                ki_hit = px_next <= strike if is_acc else px_next >= strike
                qty[ki_hit] = base_qty * multiple
            else:
                ki_hit = px_next <= strike if is_acc else px_next >= strike
                ko_hit = px_next >= float(barrier_out) if is_acc else px_next <= float(barrier_out)
                qty[(~ko_hit) & ki_hit] = base_qty * multiple
        else:
            ko_hit = np.zeros(int(active_idx.size), dtype=bool)
            if knock_out_price is not None:
                ko_hit = px_next >= float(knock_out_price) if is_acc else px_next <= float(knock_out_price)
            ki_hit = px_next <= strike if is_acc else px_next >= strike
            qty[ko_hit] = 0.0
            qty[(~ko_hit) & ki_hit] = base_qty * multiple
            qty[(~ko_hit) & (~ki_hit)] = base_qty
            if ko_terminate:
                deactivate_mask = ko_hit.copy()

        future_qty[active_idx] += qty
        cur_px[active_idx] = px_next
        if bool(deactivate_mask.any()):
            active[active_idx[deactivate_mask]] = False

    quantiles = {label: float(np.quantile(future_qty, q)) for label, q, _, _ in PROBEXP_QUANTILE_META}
    return {
        "future_qty_paths": future_qty,
        "quantiles": quantiles,
        "mean_future_qty": float(np.mean(future_qty)),
        "std_future_qty": float(np.std(future_qty)),
        "seed": seed,
        "path_count": path_count,
    }


def probexp_render_price_chart(snapshot: Dict[str, Any], *, figure_size: Tuple[float, float] = (11.8, 4.4)) -> None:
    _setup_matplotlib_cjk_font()
    price_hist = snapshot.get("price_hist")
    if not isinstance(price_hist, pd.DataFrame) or price_hist.empty:
        st.caption("暂无历史价格图：所选区间内缺少收盘价。")
        return
    price_hist = price_hist.copy()
    price_hist["date"] = pd.to_datetime(price_hist["date"], errors="coerce")
    price_hist = price_hist[price_hist["date"].notna()].copy()
    if price_hist.empty:
        st.caption("暂无历史价格图：价格日期无法识别。")
        return
    price_hist = price_hist.sort_values(["date"]).reset_index(drop=True)
    fig, ax = plt.subplots(figsize=figure_size, dpi=135)
    fig.patch.set_facecolor("#071a34")
    ax.set_facecolor("#0c274c")
    x_vals = np.arange(len(price_hist), dtype=float)
    y_vals = pd.to_numeric(price_hist["settle"], errors="coerce").fillna(0.0)
    ax.plot(x_vals, y_vals, color="#86c7ff", linewidth=2.0, label="收盘价")
    trigger_lines = [
        ("入场价", snapshot.get("entry_price"), "#cfd8e3"),
        ("行权价", snapshot.get("strike_price"), "#f5c969"),
        ("障碍价", snapshot.get("barrier_out"), "#7fd48b"),
        ("敲出/熔断价", snapshot.get("knock_out_price"), "#ff7f79"),
    ]
    used_values: List[float] = []
    for label, raw_val, color in trigger_lines:
        val = to_float(raw_val)
        if val is None:
            continue
        if any(abs(float(val) - vv) <= 1e-12 for vv in used_values):
            continue
        used_values.append(float(val))
        ax.axhline(float(val), linestyle="--", linewidth=1.1, color=color, alpha=0.9, label=label)
    ax.set_title("价格路径与触发线", loc="left", color="#ecf4ff", fontsize=12.6, fontweight="bold", pad=10)
    tick_step = max(1, len(price_hist) // 8)
    tick_idx = list(range(0, len(price_hist), tick_step))
    if tick_idx[-1] != len(price_hist) - 1:
        tick_idx.append(len(price_hist) - 1)
    tick_labels = [price_hist.iloc[i]["date"].strftime("%m-%d") for i in tick_idx]
    ax.set_xticks(tick_idx)
    ax.set_xticklabels(tick_labels, rotation=25, ha="right", color="#bfd3ec")
    ax.tick_params(axis="x", colors="#bfd3ec")
    ax.tick_params(axis="y", colors="#bfd3ec")
    ax.yaxis.set_major_formatter(FuncFormatter(lambda v, _: f"{v:,.0f}"))
    for spine in ax.spines.values():
        spine.set_color("#2a4365")
    ax.grid(axis="y", color="#2b4769", alpha=0.35, linewidth=0.8)
    gen_vals = pd.to_numeric(price_hist.get("generated_qty"), errors="coerce").fillna(0.0)
    leg1 = ax.get_legend_handles_labels()
    handles = list(leg1[0])
    labels = list(leg1[1])
    if float(gen_vals.max()) > 1e-12:
        ax2 = ax.twinx()
        ax2.bar(x_vals, gen_vals, width=0.72, color="#67d67d", alpha=0.18, label="当日生成量")
        ax2.set_ylabel("当日生成量(吨)", color="#9fbbda", fontsize=9.5)
        ax2.tick_params(axis="y", colors="#9fbbda")
        ax2.yaxis.set_major_formatter(FuncFormatter(lambda v, _: f"{v:,.0f}"))
        ax2.set_ylim(0.0, max(float(gen_vals.max()) * 1.18, 1.0))
        leg2 = ax2.get_legend_handles_labels()
        handles.extend(list(leg2[0]))
        labels.extend(list(leg2[1]))
    ax.set_xlim(-0.5, max(len(price_hist) - 0.5, 0.5))
    if handles:
        ax.legend(handles, labels, loc="upper left", frameon=False, labelcolor="#d7e9ff", fontsize=8.8)
    fig.tight_layout()
    st.pyplot(fig, width="stretch")
    plt.close(fig)


def probexp_render_distribution_chart(mc_result: Dict[str, Any], *, figure_size: Tuple[float, float] = (11.8, 4.4)) -> None:
    _setup_matplotlib_cjk_font()
    qty_paths = mc_result.get("future_qty_paths")
    if not isinstance(qty_paths, np.ndarray) or qty_paths.size == 0:
        st.caption("暂无分布图：缺少 Monte Carlo 结果。")
        return
    qty_paths = np.asarray(qty_paths, dtype=float)
    qty_paths = qty_paths[np.isfinite(qty_paths)]
    if qty_paths.size == 0:
        st.caption("暂无分布图：Monte Carlo 结果无有效值。")
        return
    fig, ax = plt.subplots(figsize=figure_size, dpi=135)
    fig.patch.set_facecolor("#071a34")
    ax.set_facecolor("#0c274c")
    spread = float(np.max(qty_paths) - np.min(qty_paths)) if qty_paths.size > 0 else 0.0
    bins = 1 if spread <= 1e-9 else max(24, min(64, int(np.sqrt(max(int(qty_paths.size), 1)) / 2.2)))
    ax.hist(qty_paths, bins=bins, color="#5fb7ff", alpha=0.72, edgecolor="#d7ebff", linewidth=0.65)
    quantiles = mc_result.get("quantiles", {}) if isinstance(mc_result.get("quantiles", {}), dict) else {}
    colors = {
        "P10": "#7fd48b",
        "P20": "#5cc8a1",
        "P50": "#f5c969",
        "P80": "#ff9f68",
        "P95": "#ff7f79",
        "P97.5": "#ff4d4f",
    }
    for label, _, _, _ in PROBEXP_QUANTILE_META:
        qv = to_float(quantiles.get(label))
        if qv is None:
            continue
        ax.axvline(float(qv), color=colors.get(label, "#ffffff"), linestyle="--", linewidth=1.15, label=label)
    ax.set_title("剩余生成量分布", loc="left", color="#ecf4ff", fontsize=12.6, fontweight="bold", pad=10)
    ax.set_xlabel("未来还会生成的吨数", color="#bfd3ec", fontsize=10)
    ax.set_ylabel("路径数", color="#bfd3ec", fontsize=10)
    ax.tick_params(axis="x", colors="#bfd3ec")
    ax.tick_params(axis="y", colors="#bfd3ec")
    ax.xaxis.set_major_formatter(FuncFormatter(lambda v, _: f"{v:,.0f}"))
    ax.yaxis.set_major_formatter(FuncFormatter(lambda v, _: f"{v:,.0f}"))
    for spine in ax.spines.values():
        spine.set_color("#2a4365")
    ax.grid(axis="y", color="#2b4769", alpha=0.35, linewidth=0.8)
    ax.legend(loc="upper right", frameon=False, labelcolor="#d7e9ff", fontsize=8.6, ncol=3)
    fig.tight_layout()
    st.pyplot(fig, width="stretch")
    plt.close(fig)


def probexp_render_target_chart(
    target_rows: pd.DataFrame,
    current_position: float,
    decision_label: str,
    *,
    figure_size: Tuple[float, float] = (11.8, 4.4),
) -> None:
    _setup_matplotlib_cjk_font()
    if target_rows is None or target_rows.empty:
        st.caption("暂无目标持仓图。")
        return
    fig, ax = plt.subplots(figsize=figure_size, dpi=135)
    fig.patch.set_facecolor("#071a34")
    ax.set_facecolor("#0c274c")
    x = np.arange(len(target_rows))
    bar_colors = ["#4da3ff" if str(lbl) != str(decision_label) else "#f5c969" for lbl in target_rows["分位数"].astype(str)]
    ax.bar(x, pd.to_numeric(target_rows["目标持仓(吨)"], errors="coerce").fillna(0.0), color=bar_colors, alpha=0.82, width=0.62)
    ax.axhline(float(current_position), color="#ff7f79", linestyle="--", linewidth=1.4, label="当前持仓")
    ax.set_xticks(x)
    ax.set_xticklabels(target_rows["分位数"].astype(str).tolist(), color="#bfd3ec")
    ax.tick_params(axis="y", colors="#bfd3ec")
    ax.yaxis.set_major_formatter(FuncFormatter(lambda v, _: f"{v:,.0f}"))
    ax.set_ylabel("目标持仓(吨，带方向)", color="#bfd3ec", fontsize=10)
    ax.set_title("不同分位数下的目标持仓", loc="left", color="#ecf4ff", fontsize=12.6, fontweight="bold", pad=10)
    ax.grid(axis="y", color="#2b4769", alpha=0.35, linewidth=0.8)
    ax.axhline(0.0, color="#5a7ca6", linestyle="-", linewidth=0.9, alpha=0.7)
    for spine in ax.spines.values():
        spine.set_color("#2a4365")
    ax.legend(loc="upper right", frameon=False, labelcolor="#d7e9ff", fontsize=8.8)
    fig.tight_layout()
    st.pyplot(fig, width="stretch")
    plt.close(fig)


def render_probexp_special_page(
    conn: sqlite3.Connection,
    *,
    rep_gid: str,
    rep_date: str,
    rep_und: str,
    rep_und_all: bool,
    structs_df: pd.DataFrame,
    prices_df: pd.DataFrame,
    close2_df: pd.DataFrame,
    struct_asof: pd.DataFrame,
    bounds_asof: pd.DataFrame,
) -> None:
    candidate_rows = probexp_build_structure_candidates(
        structs_df=structs_df,
        struct_asof=struct_asof,
        bounds_asof=bounds_asof,
        prices_df=prices_df,
        close2_df=close2_df,
        rep_gid=rep_gid,
        rep_date=rep_date,
        rep_und=rep_und,
        rep_und_all=rep_und_all,
    )
    if not candidate_rows:
        st.info("当前筛选下没有可用于专项计算的累计结构。")
        return

    option_map = {str(row["structure_id"]): row for row in candidate_rows}
    option_ids = [str(row["structure_id"]) for row in candidate_rows]
    default_sid = option_ids[0]
    sid_key = f"probexp_structure_pick__{str(rep_gid)}"
    sid_display_key = f"probexp_structure_pick_label__{str(rep_gid)}"
    if sid_key not in st.session_state or str(st.session_state[sid_key]) not in option_map:
        st.session_state[sid_key] = default_sid
    sid_label_map = {
        sid: (
            f"{sid} | {option_map[str(sid)]['label']} | {option_map[str(sid)]['status_cn']} | "
            f"剩余 {int(pick_first(option_map[str(sid)].get('remaining_days'), 0) or 0)} 天"
        )
        for sid in option_ids
    }
    sid_display_opts = [sid_label_map[sid] for sid in option_ids]
    sid_display_to_sid = {label: sid for sid, label in sid_label_map.items()}
    current_sid = str(st.session_state.get(sid_key, default_sid))
    default_sid_label = sid_label_map.get(current_sid, sid_label_map[default_sid])
    if sid_display_key not in st.session_state or str(st.session_state[sid_display_key]) not in sid_display_to_sid:
        st.session_state[sid_display_key] = default_sid_label
    selected_sid_label = st.selectbox("累计结构", sid_display_opts, key=sid_display_key)
    selected_sid = sid_display_to_sid.get(str(selected_sid_label), default_sid)
    st.session_state[sid_key] = selected_sid
    candidate = option_map[str(selected_sid)]
    snapshot = probexp_build_structure_snapshot(
        candidate=candidate,
        struct_asof=struct_asof,
        prices_df=prices_df,
        close2_df=close2_df,
        rep_date=rep_date,
    )
    resolved = candidate.get("resolved", {}) if isinstance(candidate.get("resolved", {}), dict) else {}
    current_close = float(pick_first(snapshot.get("current_close"), 0.0) or 0.0)
    if current_close <= 1e-12:
        st.warning("当前日期前缺少该结构的收盘价，无法进行概率期望计算。")
        return
    gap_snapshot = snapshot.get("gap_snapshot", {}) if isinstance(snapshot.get("gap_snapshot"), dict) else {}

    market_df = fetch_probexp_market_inputs(conn)
    calc_log_df = fetch_probexp_calc_logs(conn)
    market_sub = (
        market_df[
            market_df["underlying"].astype(str).map(_normalize_underlying_symbol)
            == _normalize_underlying_symbol(resolved.get("underlying"))
        ].copy()
        if not market_df.empty
        else pd.DataFrame()
    )
    log_sub = calc_log_df[calc_log_df["structure_id"].astype(str) == str(selected_sid)].copy() if not calc_log_df.empty else pd.DataFrame()
    same_day_log = log_sub[log_sub["dt"].astype(str) == str(rep_date)].copy() if not log_sub.empty else pd.DataFrame()
    latest_log = log_sub.sort_values(["dt", "updated_at"]).tail(1).iloc[0] if not log_sub.empty else None
    same_day_market = market_sub[market_sub["dt"].astype(str) == str(rep_date)].copy() if not market_sub.empty else pd.DataFrame()
    latest_market = market_sub.sort_values(["dt", "updated_at"]).tail(1).iloc[0] if not market_sub.empty else None
    auto_iv_rec = probexp_fetch_auto_atm_iv(
        underlying=resolved.get("underlying"),
        rep_date=rep_date,
        current_close=current_close,
    )
    auto_iv_value = to_float(auto_iv_rec.get("atm_iv"))
    auto_iv_meta = PROBEXP_AK_OPTION_SYMBOL_MAP.get(probexp_underlying_product_code(resolved.get("underlying")), {})
    auto_iv_reason = probexp_humanize_auto_iv_reason(
        auto_iv_rec.get("reason"),
        exchange=str(pick_first(auto_iv_meta.get("exchange"), "")),
        symbol=str(pick_first(auto_iv_meta.get("symbol"), "")),
    )
    default_iv = 25.0
    default_iv_source = "固定默认值"
    iv_candidates: List[Tuple[str, Any]] = [
        (str(pick_first(auto_iv_rec.get("source"), "自动 IV") or "自动 IV"), auto_iv_value),
        ("已保存当日 IV", to_float(same_day_market.iloc[-1].get("atm_iv")) if not same_day_market.empty else None),
        ("已保存当日计算值", to_float(same_day_log.iloc[-1].get("atm_iv")) if not same_day_log.empty else None),
        ("最近一次保存 IV", to_float(latest_market.get("atm_iv")) if latest_market is not None else None),
        ("最近一次计算值", to_float(latest_log.get("atm_iv")) if latest_log is not None else None),
        ("固定默认值", 25.0),
    ]
    for src, val in iv_candidates:
        iv_num = to_float(val)
        if iv_num is not None and float(iv_num) > 1e-12:
            default_iv = float(iv_num)
            default_iv_source = str(src)
            break

    default_skew = float(
        pick_first(
            to_float(auto_iv_rec.get("skew")),
            to_float(same_day_market.iloc[-1].get("skew")) if not same_day_market.empty else None,
            to_float(latest_market.get("skew")) if latest_market is not None else None,
            to_float(same_day_log.iloc[-1].get("skew")) if not same_day_log.empty else None,
            to_float(latest_log.get("skew")) if latest_log is not None else None,
            0.0,
        )
        or 0.0
    )
    default_current_position = float(
        pick_first(
            snapshot.get("current_position_tons"),
            0.0,
        )
        or 0.0
    )
    default_target_qty = float(
        pick_first(
            snapshot.get("nominal_target_qty"),
            0.0,
        )
        or 0.0
    )
    default_band = float(
        pick_first(
            to_float(same_day_log.iloc[-1].get("no_trade_band_tons")) if not same_day_log.empty else None,
            to_float(latest_log.get("no_trade_band_tons")) if latest_log is not None else None,
            PROBEXP_NO_TRADE_BAND_DEFAULT,
        )
        or 0.0
    )
    default_paths = int(
        pick_first(
            _int_from_any(same_day_log.iloc[-1].get("mc_paths"), PROBEXP_MC_PATHS_DEFAULT) if not same_day_log.empty else None,
            _int_from_any(latest_log.get("mc_paths"), PROBEXP_MC_PATHS_DEFAULT) if latest_log is not None else None,
            PROBEXP_MC_PATHS_DEFAULT,
        )
        or PROBEXP_MC_PATHS_DEFAULT
    )
    default_paths = max(int(default_paths), int(PROBEXP_MC_PATHS_DEFAULT))
    saved_decision_label = str(
        pick_first(
            same_day_log.iloc[-1].get("decision_quantile") if not same_day_log.empty else None,
            latest_log.get("decision_quantile") if latest_log is not None else None,
            "P50",
        )
        or "P50"
    ).strip()
    if saved_decision_label not in PROBEXP_QUANTILE_LOOKUP:
        saved_decision_label = "P50"

    st.markdown("#### 结构快照")
    m1, m2, m3, m4, m5, m6 = st.columns(6)
    with m1:
        st.metric("结构类型", str(snapshot.get("effect_title", "")))
    with m2:
        st.metric("方向", str(snapshot.get("direction_cn", "")))
    with m3:
        st.metric("结构持仓数量", probexp_format_tons(snapshot.get("stock_position_qty")))
    with m4:
        st.metric("期初总规模", probexp_format_tons(snapshot.get("nominal_target_qty")))
    with m5:
        st.metric("今日生成量", probexp_format_tons(snapshot.get("today_qty")))
    with m6:
        st.metric("累计已生成", probexp_format_tons(snapshot.get("observed_qty")))
    n1, n2, n3, n4, n5 = st.columns(5)
    with n1:
        st.metric("剩余天数", f"{int(pick_first(snapshot.get('remaining_days'), 0) or 0)}")
    with n2:
        st.metric("剩余震荡数量", probexp_format_position_tons(gap_snapshot.get("remaining_oscillation_scale"), zero_text="0.00 吨"))
    with n3:
        st.metric("剩余敲入最大数量", probexp_format_position_tons(gap_snapshot.get("remaining_knockin_max_scale"), zero_text="0.00 吨"))
    with n4:
        target_gap_qty = float(pick_first(to_float(snapshot.get("nominal_target_qty")), 0.0) or 0.0) - float(
            pick_first(to_float(snapshot.get("stock_position_qty")), 0.0) or 0.0
        )
        st.metric("目标套保差额", probexp_format_tons(target_gap_qty))
    with n5:
        st.metric("当前收盘价", f"{current_close:,.4f}")
    st.caption(snapshot.get("effect_text", ""))
    st.caption("结构快照中的剩余震荡/敲入口径，直接复用“监控计算-价格完整性监控”的同口径字段。")
    st.caption("结构持仓数量使用“期权头寸仓库管理”里的结构可平数量口径。")
    st.caption("专项口径只跟踪未来“还会生成多少吨”，补贴与现货端不并入目标持仓。")
    st.caption(
        f"当前持仓吨数默认带入当前结构现存头寸：{probexp_format_tons(snapshot.get('stock_position_qty'))}；"
        "如果场外另有手工调整，可直接覆盖。"
    )

    form_key = f"probexp_form__{rep_gid}__{selected_sid}"
    state_key = f"probexp_result__{rep_gid}__{rep_date}__{selected_sid}"
    input_prefix = f"probexp_input__{rep_gid}__{rep_date}__{selected_sid}"
    with st.form(form_key):
        i1, i2, i3 = st.columns([1.05, 1.10, 1.10], gap="medium")
        with i1:
            atm_iv_input = st.number_input(
                "ATM IV（%）",
                min_value=0.0,
                max_value=300.0,
                value=float(default_iv),
                step=0.5,
                format="%.4f",
                key=f"{input_prefix}__atm_iv",
            )
            auto_contract_text = str(pick_first(auto_iv_rec.get("contract"), "") or "").strip()
            if bool(auto_iv_rec.get("ok")):
                st.caption(
                    f"自动带入来源：{default_iv_source}；自动参考 {float(pick_first(auto_iv_value, 0.0) or 0.0):.4f}%"
                    f"{f'（{auto_contract_text}）' if auto_contract_text else ''}。"
                    " 仍可手工覆盖。"
                )
            else:
                st.caption(f"当前默认值来源：{default_iv_source}。自动 IV 暂不可用：{auto_iv_reason}。")
        with i2:
            current_position_input = st.number_input(
                "当前持仓吨数（净值，空头填负）",
                value=float(default_current_position),
                step=1000.0,
                format="%.2f",
                key=f"{input_prefix}__current_position",
            )
        with i3:
            target_hedge_qty_input = st.number_input(
                "目标套保总量（吨）",
                min_value=0.0,
                value=float(default_target_qty),
                step=1000.0,
                format="%.2f",
                key=f"{input_prefix}__target_hedge_qty",
            )
        with st.expander("高级参数", expanded=False):
            a1, a2, a3 = st.columns([1.0, 1.0, 1.0], gap="medium")
            with a1:
                skew_input = st.number_input("skew（正=偏上，负=偏下）", value=float(default_skew), step=0.05, format="%.4f", key=f"{input_prefix}__skew")
            with a2:
                mc_paths_input = st.number_input(
                    "Monte Carlo 路径数",
                    min_value=10000,
                    max_value=PROBEXP_MC_PATHS_MAX,
                    value=int(default_paths),
                    step=10000,
                    format="%d",
                    key=f"{input_prefix}__mc_paths",
                )
            with a3:
                no_trade_band_input = st.number_input(
                    "不调仓阈值（吨）",
                    min_value=0.0,
                    value=float(default_band),
                    step=500.0,
                    format="%.2f",
                    key=f"{input_prefix}__no_trade_band",
                )
            decision_label_input = st.selectbox(
                "目标持仓决策口径",
                list(PROBEXP_QUANTILE_LOOKUP.keys()),
                index=list(PROBEXP_QUANTILE_LOOKUP.keys()).index(saved_decision_label),
                help="默认用 P50；如果你想更保守，可以切到 P80 / P95。",
                key=f"{input_prefix}__decision_label",
            )
        calc_clicked = st.form_submit_button("计算专项结果", use_container_width=True)

    if calc_clicked:
        mc_result = probexp_simulate_future_qty(
            resolved,
            start_price=current_close,
            remaining_days=int(pick_first(snapshot.get("remaining_days"), 0) or 0),
            atm_iv_pct=float(atm_iv_input),
            skew=float(skew_input),
            paths=int(mc_paths_input),
            seed_hint=f"{rep_gid}|{rep_date}|{selected_sid}",
        )
        observed_qty = float(pick_first(snapshot.get("observed_qty"), 0.0) or 0.0)
        direction_sign_val = float(pick_first(snapshot.get("direction_sign"), 1.0) or 1.0)
        decision_q = float(PROBEXP_QUANTILE_LOOKUP.get(str(decision_label_input), 0.5))
        decision_future_qty = float(np.quantile(mc_result["future_qty_paths"], decision_q))
        decision_final_qty = observed_qty + decision_future_qty
        signed_target_total = direction_sign_val * float(target_hedge_qty_input)
        target_position = signed_target_total - direction_sign_val * decision_final_qty
        current_position = float(current_position_input)
        adjust_tons_raw = target_position - current_position
        no_trade_band = max(float(no_trade_band_input), 0.0)
        if abs(adjust_tons_raw) <= no_trade_band:
            adjust_tons = 0.0
            current_after = current_position
            action_text = f"不调整（当前结构头寸与目标持仓偏差 {abs(adjust_tons_raw):,.2f} 吨，小于阈值 {no_trade_band:,.2f} 吨）"
        else:
            adjust_tons = float(adjust_tons_raw)
            current_after = current_position + adjust_tons
            action_text = probexp_describe_adjustment(current_position, target_position)
        target_rows: List[Dict[str, Any]] = []
        quantile_map = mc_result.get("quantiles", {}) if isinstance(mc_result.get("quantiles", {}), dict) else {}
        for label, _, meaning, explain in PROBEXP_QUANTILE_META:
            future_qty = float(pick_first(quantile_map.get(label), 0.0) or 0.0)
            final_qty = observed_qty + future_qty
            target_pos = signed_target_total - direction_sign_val * final_qty
            target_rows.append(
                {
                    "分位数": label,
                    "含义": meaning,
                    "中文解释": explain,
                    "未来剩余生成量(吨)": future_qty,
                    "预计最终生成量(吨)": final_qty,
                    "目标持仓(吨)": target_pos,
                    "目标持仓说明": probexp_format_position_tons(target_pos),
                    "决策口径": "是" if label == str(decision_label_input) else "",
                }
            )
        st.session_state[state_key] = {
            "sid": str(selected_sid),
            "rep_date": str(rep_date),
            "atm_iv": float(atm_iv_input),
            "skew": float(skew_input),
            "mc_paths": int(mc_result.get("path_count", mc_paths_input)),
            "mean_future_qty": float(mc_result.get("mean_future_qty", 0.0)),
            "std_future_qty": float(mc_result.get("std_future_qty", 0.0)),
            "quantiles": quantile_map,
            "observed_qty": observed_qty,
            "today_qty": float(pick_first(snapshot.get("today_qty"), 0.0) or 0.0),
            "remaining_days": int(pick_first(snapshot.get("remaining_days"), 0) or 0),
            "current_close": current_close,
            "current_position": current_position,
            "target_hedge_qty": float(target_hedge_qty_input),
            "decision_label": str(decision_label_input),
            "target_position": float(target_position),
            "adjust_tons_raw": float(adjust_tons_raw),
            "adjust_tons_exec": float(adjust_tons),
            "current_after": float(current_after),
            "no_trade_band": no_trade_band,
            "action_text": action_text,
            "target_rows": pd.DataFrame(target_rows),
            "mc_result": mc_result,
        }

    result = st.session_state.get(state_key)
    if not isinstance(result, dict) or str(result.get("sid", "")) != str(selected_sid):
        st.info("填入参数后点击“计算专项结果”，页面会生成目标持仓、建议调仓吨数和图形。")
        return

    st.markdown("#### 核心结果")
    r1, r2, r3, r4, r5 = st.columns(5)
    with r1:
        st.metric("今日生成量", probexp_format_tons(result.get("today_qty")))
    with r2:
        st.metric("累计已生成", probexp_format_tons(result.get("observed_qty")))
    with r3:
        st.metric("剩余期望 E", probexp_format_tons(result.get("mean_future_qty")))
    with r4:
        st.metric("目标持仓", probexp_format_position_tons(result.get("target_position")))
    with r5:
        st.metric("建议净变动", probexp_format_tons(result.get("adjust_tons_exec"), signed=True))
    st.caption(
        "口径：目标持仓 = 目标套保总量(按方向) - [累计已生成 + 未来剩余生成量的决策分位数]。"
        f" 当前决策口径为 {str(result.get('decision_label', 'P50'))}；多头为正、空头为负，上面的目标持仓已按方向翻译展示。"
    )
    st.info(
        f"建议执行：{str(result.get('action_text', ''))}。"
        f" 调整后持仓约为 {probexp_format_position_tons(result.get('current_after'))}。"
    )

    save_col, hint_col = st.columns([0.32, 0.68], gap="medium")
    with save_col:
        if st.button("保存当日专项结果", key=f"probexp_save_btn__{rep_gid}__{selected_sid}", use_container_width=True):
            try:
                upsert_probexp_market_input(
                    conn,
                    dt=rep_date,
                    underlying=resolved.get("underlying"),
                    atm_iv=result.get("atm_iv"),
                    skew=result.get("skew"),
                    source="manual",
                )
                qmap = result.get("quantiles", {}) if isinstance(result.get("quantiles", {}), dict) else {}
                upsert_probexp_calc_log(
                    conn,
                    dt=rep_date,
                    group_id=rep_gid,
                    structure_id=selected_sid,
                    underlying=resolved.get("underlying"),
                    close_price=result.get("current_close"),
                    target_hedge_qty=result.get("target_hedge_qty"),
                    current_position_tons=result.get("current_position"),
                    current_position_after_tons=result.get("current_after"),
                    target_position_tons=result.get("target_position"),
                    suggested_adjust_tons=result.get("adjust_tons_exec"),
                    no_trade_band_tons=result.get("no_trade_band"),
                    atm_iv=result.get("atm_iv"),
                    skew=result.get("skew"),
                    mc_paths=result.get("mc_paths"),
                    decision_quantile=result.get("decision_label"),
                    realized_qty=result.get("observed_qty"),
                    remaining_days=result.get("remaining_days"),
                    p10=qmap.get("P10", 0.0),
                    p20=qmap.get("P20", 0.0),
                    p50=qmap.get("P50", 0.0),
                    p80=qmap.get("P80", 0.0),
                    p95=qmap.get("P95", 0.0),
                    p975=qmap.get("P97.5", 0.0),
                    model_version=PROBEXP_MODEL_VERSION,
                )
                conn.commit()
                st.success("已保存本日专项输入与计算结果。")
            except Exception as exc:
                conn.rollback()
                st.error(format_db_write_error("保存专项结果", exc))
    with hint_col:
        st.caption(
            f"本次 Monte Carlo 使用 {int(pick_first(result.get('mc_paths'), 0) or 0):,} 条路径，"
            f"采用 ATM IV + skew 非对称波动近似，模型版本 {PROBEXP_MODEL_VERSION}。"
        )

    quantile_df = result.get("target_rows")
    if isinstance(quantile_df, pd.DataFrame) and not quantile_df.empty:
        st.markdown("#### 分位数解释")
        st.dataframe(
            quantile_df,
            width="stretch",
            height=300,
            column_config={
                "分位数": st.column_config.TextColumn("分位数", width="small"),
                "含义": st.column_config.TextColumn("含义", width="medium"),
                "中文解释": st.column_config.TextColumn("中文解释", width="large"),
                "未来剩余生成量(吨)": st.column_config.NumberColumn("未来剩余生成量(吨)", format="%.2f", width="small"),
                "预计最终生成量(吨)": st.column_config.NumberColumn("预计最终生成量(吨)", format="%.2f", width="small"),
                "目标持仓(吨)": st.column_config.NumberColumn("目标持仓(吨)", format="%+.2f", width="small"),
                "目标持仓说明": st.column_config.TextColumn("目标持仓说明", width="small"),
                "决策口径": st.column_config.TextColumn("决策口径", width="small"),
            },
        )

    st.markdown("#### 图形展示")
    g1, g2 = st.columns(2, gap="large")
    with g1:
        probexp_render_price_chart(snapshot)
    with g2:
        probexp_render_distribution_chart(result.get("mc_result", {}))
    probexp_render_target_chart(
        result.get("target_rows") if isinstance(result.get("target_rows"), pd.DataFrame) else pd.DataFrame(),
        float(pick_first(result.get("current_position"), 0.0) or 0.0),
        str(result.get("decision_label", "P50")),
    )
    with st.expander("放大查看图形", expanded=False):
        big_tab1, big_tab2, big_tab3 = st.tabs(["价格路径图", "剩余生成量分布", "目标持仓图"])
