def cn_date_text(d: date) -> str:
    return f"{d.year}年{d.month}月{d.day}日"


def inject_cn_calendar() -> None:
    components.html(
        """
        <script>
        const monthMap = {
          "January":"一月","February":"二月","March":"三月","April":"四月","May":"五月","June":"六月",
          "July":"七月","August":"八月","September":"九月","October":"十月","November":"十一月","December":"十二月",
          "Jan":"一月","Feb":"二月","Mar":"三月","Apr":"四月","Jun":"六月","Jul":"七月","Aug":"八月","Sep":"九月","Oct":"十月","Nov":"十一月","Dec":"十二月"
        };
        const weekMap = {
          "Mon":"周一","Tue":"周二","Wed":"周三","Thu":"周四","Fri":"周五","Sat":"周六","Sun":"周日",
          "Mo":"一","Tu":"二","We":"三","Th":"四","Fr":"五","Sa":"六","Su":"日"
        };
        function cn(t) {
          if (!t) return t;
          const x = String(t).trim();
          if (monthMap[x]) return monthMap[x];
          if (weekMap[x]) return weekMap[x];
          let y = x;
          Object.keys(monthMap).forEach((en) => {
            const reg = new RegExp("\\\\b" + en + "\\\\b", "g");
            y = y.replace(reg, monthMap[en]);
          });
          Object.keys(weekMap).forEach((en) => {
            const reg = new RegExp("\\\\b" + en + "\\\\b", "g");
            y = y.replace(reg, weekMap[en]);
          });
          return y;
        }
        function patchRoot(root) {
          if (!root) return;
          const nodes = root.querySelectorAll("*");
          nodes.forEach((el) => {
            if (!el) return;
            if (el.children && el.children.length > 0) return;
            const txt = (el.textContent || "").trim();
            if (!txt) return;
            const mapped = cn(txt);
            if (mapped !== txt) el.textContent = mapped;
          });
        }
        function patch() {
          let d = null;
          try { d = window.parent.document; } catch (e) { d = document; }
          if (!d) return;
          const roots = d.querySelectorAll("[data-baseweb='calendar'], [data-baseweb='popover'], [role='dialog'], [role='listbox']");
          roots.forEach((r) => patchRoot(r));
        }
        patch();
        try {
          const d = window.parent.document;
          if (d && d.body) {
            const ob = new MutationObserver(() => patch());
            ob.observe(d.body, { childList: true, subtree: true });
          }
        } catch (e) {}
        setInterval(patch, 350);
        </script>
        """,
        height=0,
        width=0,
    )


def _table_preview_frame(data: Any) -> Optional[pd.DataFrame]:
    try:
        if isinstance(data, pd.DataFrame):
            return data
        if isinstance(data, pd.Series):
            return data.to_frame()
        styler_cls = getattr(pd.io.formats.style, "Styler", None)
        if styler_cls is not None and isinstance(data, styler_cls):
            base_df = getattr(data, "data", None)
            return base_df if isinstance(base_df, pd.DataFrame) else None
        if hasattr(data, "to_pandas") and callable(getattr(data, "to_pandas")):
            maybe_df = data.to_pandas()
            return maybe_df if isinstance(maybe_df, pd.DataFrame) else pd.DataFrame(maybe_df)
        return pd.DataFrame(data)
    except Exception:
        return None


def _table_text_width_units(value: Any) -> int:
    s = str(pick_first(value, "") or "").replace("\n", " ").replace("\r", " ").replace("\t", " ")
    s = re.sub(r"\s+", " ", s).strip()
    if not s:
        return 0
    width_units = 0
    for ch in s:
        width_units += 2 if ord(ch) >= 0x2E80 else 1
    return width_units


def _sample_series_for_width(series: pd.Series, limit: int = 48) -> pd.Series:
    if series is None or len(series) <= limit:
        return pd.Series(series)
    pick_idx = sorted({int(round(x)) for x in np.linspace(0, len(series) - 1, num=limit)})
    return series.iloc[pick_idx]


def _table_label_text(key: Any, cfg: Optional[Mapping[str, Any]] = None) -> str:
    if cfg:
        label = cfg.get("label")
        if label is not None and str(label).strip():
            return str(label).strip()
    if isinstance(key, tuple):
        return " / ".join([str(x) for x in key if str(x).strip()])
    return str(key or "").strip()


def _table_value_is_missing(value: Any) -> bool:
    try:
        missing = pd.isna(value)
    except Exception:
        return False
    if isinstance(missing, (np.ndarray, pd.Series, list, tuple)):
        return False
    return bool(missing)


def _infer_table_column_width_px(
    col_key: Any,
    label_text: str,
    series: Optional[pd.Series] = None,
) -> int:
    col_text = str(col_key or "").strip().lower()
    name_text = f"{label_text} {col_key}".strip().lower()
    label_units = max(_table_text_width_units(label_text), _table_text_width_units(col_key), 3)
    focus_units = label_units
    dtype_name = str(getattr(getattr(series, "dtype", None), "name", "")).lower()
    if series is not None:
        sample = _sample_series_for_width(series)
        sample_units: List[int] = []
        for raw in sample.tolist():
            if _table_value_is_missing(raw):
                continue
            width_units = _table_text_width_units(raw)
            if width_units > 0:
                sample_units.append(width_units)
        if sample_units:
            sample_units.sort()
            if len(sample_units) <= 4:
                focus_units = max(label_units, sample_units[-1])
            else:
                pivot_idx = min(len(sample_units) - 1, max(0, int(round((len(sample_units) - 1) * 0.80))))
                pivot_units = sample_units[pivot_idx]
                tail_units = sample_units[-1]
                focus_units = max(label_units, tail_units if tail_units <= pivot_units * 1.18 else pivot_units)

    if col_text == "_index":
        px = 16 + int(max(focus_units, 2) * 5.0)
        return int(max(38, min(px, 52)))

    px = 20 + int(focus_units * 7.2)
    min_px = 62
    max_px = 220
    if "bool" in dtype_name or any(token in name_text for token in ["删除", "选择", "勾选", "启用", "禁用", "锁定", "彻底"]):
        min_px = 56
        max_px = 78
    elif any(token in name_text for token in ["详情", "名称", "备注", "说明", "结构", "路径", "列表", "组合"]):
        px = 18 + int(min(focus_units, 44) * 6.9)
        min_px = 128
        max_px = 340
    elif any(token in name_text for token in ["日期", "时间", "date", "time"]):
        px = 18 + int(focus_units * 6.8)
        min_px = 94
        max_px = 138
    elif any(
        token in name_text
        for token in ["数量", "规模", "金额", "名义", "价格", "盈亏", "交易日", "敞口", "比例", "收益", "票息", "成本", "下界", "上界"]
    ):
        px = 18 + int(focus_units * 6.8)
        min_px = 78
        max_px = 150
    elif any(token in name_text for token in ["结构id", "策略组编号", "group_id", "group id", "编号", "代码", "sid"]):
        px = 16 + int(focus_units * 5.8)
        min_px = 50
        max_px = 90
    elif any(token in name_text for token in ["方向", "状态", "品种", "风控子", "underlying", "kind"]):
        px = 18 + int(focus_units * 6.2)
        min_px = 62
        max_px = 108
    elif any(token in dtype_name for token in ["int", "float", "decimal"]):
        px = 18 + int(focus_units * 6.6)
        min_px = 76
        max_px = 142
    return int(max(min_px, min(px, max_px)))


def _merge_table_auto_width_column_config(
    data: Any,
    column_order: Optional[Iterable[Any]] = None,
    column_config: Optional[Mapping[Any, Any]] = None,
    hide_index: Optional[bool] = None,
) -> Optional[Dict[Any, Any]]:
    preview = _table_preview_frame(data)
    if preview is None:
        return column_config if isinstance(column_config, dict) else dict(column_config or {})
    merged_cfg: Dict[Any, Any] = dict(column_config or {})
    visible_cols: List[Any]
    if column_order:
        visible_cols = [col for col in column_order if col in preview.columns]
    else:
        visible_cols = list(preview.columns)
    for col in visible_cols:
        raw_cfg = merged_cfg.get(col)
        existing_cfg = dict(raw_cfg) if isinstance(raw_cfg, Mapping) else {}
        label_text = _table_label_text(col, existing_cfg)
        width_px = _infer_table_column_width_px(col, label_text, preview[col])
        if existing_cfg:
            existing_cfg["width"] = width_px
            merged_cfg[col] = existing_cfg
        else:
            merged_cfg[col] = st.column_config.Column(label_text or None, width=width_px)
    if hide_index is not True:
        raw_cfg = merged_cfg.get("_index")
        existing_cfg = dict(raw_cfg) if isinstance(raw_cfg, Mapping) else {}
        index_label = _table_label_text(getattr(preview.index, "name", "") or "", existing_cfg)
        index_series = pd.Series(preview.index.to_list(), name=index_label or "_index")
        width_px = _infer_table_column_width_px("_index", index_label or "序号", index_series)
        if existing_cfg:
            existing_cfg["width"] = width_px
            merged_cfg["_index"] = existing_cfg
        else:
            merged_cfg["_index"] = st.column_config.Column(index_label or None, width=width_px)
    if visible_cols:
        last_col = visible_cols[-1]
        raw_cfg = merged_cfg.get(last_col)
        existing_cfg = dict(raw_cfg) if isinstance(raw_cfg, Mapping) else {}
        last_label = _table_label_text(last_col, existing_cfg)
        last_name = f"{last_label} {last_col}".strip().lower()
        base_width = int(to_float(existing_cfg.get("width")) or _infer_table_column_width_px(last_col, last_label, preview[last_col]))
        widen_cap = 320 if any(token in last_name for token in ["详情", "名称", "备注", "说明", "结构", "路径", "列表", "组合"]) else 220
        widened_width = int(min(widen_cap, base_width + 18))
        if existing_cfg:
            existing_cfg["width"] = widened_width
            merged_cfg[last_col] = existing_cfg
        else:
            merged_cfg[last_col] = st.column_config.Column(last_label or None, width=widened_width)
    return merged_cfg


def _install_global_table_auto_sizing() -> None:
    if getattr(st.dataframe, "__otc_auto_width_wrapped__", False) and getattr(st.data_editor, "__otc_auto_width_wrapped__", False):
        return
    if not hasattr(st, "_otc_original_dataframe_method"):
        setattr(st, "_otc_original_dataframe_method", st.dataframe)
    if not hasattr(st, "_otc_original_data_editor_method"):
        setattr(st, "_otc_original_data_editor_method", st.data_editor)

    def _wrapped_dataframe(data: Any = None, *args: Any, **kwargs: Any):
        patched_kwargs = dict(kwargs)
        patched_kwargs["column_config"] = _merge_table_auto_width_column_config(
            data=data,
            column_order=patched_kwargs.get("column_order"),
            column_config=patched_kwargs.get("column_config"),
            hide_index=patched_kwargs.get("hide_index"),
        )
        return getattr(st, "_otc_original_dataframe_method")(data, *args, **patched_kwargs)

    def _wrapped_data_editor(data: Any, *args: Any, **kwargs: Any):
        patched_kwargs = dict(kwargs)
        patched_kwargs["column_config"] = _merge_table_auto_width_column_config(
            data=data,
            column_order=patched_kwargs.get("column_order"),
            column_config=patched_kwargs.get("column_config"),
            hide_index=patched_kwargs.get("hide_index"),
        )
        return getattr(st, "_otc_original_data_editor_method")(data, *args, **patched_kwargs)

    _wrapped_dataframe.__otc_auto_width_wrapped__ = True
    _wrapped_data_editor.__otc_auto_width_wrapped__ = True
    st.dataframe = _wrapped_dataframe
    st.data_editor = _wrapped_data_editor


def _normalize_group_select_options(options: Iterable[Any]) -> List[str]:
    cleaned: List[str] = []
    for raw in options:
        value = str(raw).strip()
        if value and value not in cleaned:
            cleaned.append(value)
    return cleaned


def ensure_global_group_selection(options: Iterable[Any]) -> str:
    group_opts = _normalize_group_select_options(options)
    if not group_opts:
        st.session_state.pop(GLOBAL_GROUP_SELECT_KEY, None)
        return ""
    current_gid = str(st.session_state.get(GLOBAL_GROUP_SELECT_KEY, "") or "").strip()
    if current_gid not in group_opts:
        current_gid = group_opts[0]
        st.session_state[GLOBAL_GROUP_SELECT_KEY] = current_gid
    return current_gid


def render_global_group_selectbox(
    label: str,
    options: Iterable[Any],
    *,
    format_func: Optional[Callable[[str], Any]] = None,
) -> str:
    group_opts = _normalize_group_select_options(options)
    if not group_opts:
        return ""
    current_gid = ensure_global_group_selection(group_opts)
    current_idx = group_opts.index(current_gid) if current_gid in group_opts else 0
    select_kwargs: Dict[str, Any] = {"index": current_idx}
    if format_func is not None:
        select_kwargs["format_func"] = format_func
    gid = st.selectbox(label, group_opts, **select_kwargs)
    gid = str(gid).strip()
    if gid and gid != current_gid:
        st.session_state[GLOBAL_GROUP_SELECT_KEY] = gid
    return gid


