def render_page_banner(title: str, subtitle: str = "") -> None:
    t = str(title or "").strip()
    s = str(subtitle or "").strip()
    if not t:
        return
    sub_html = f'<div class="otc-page-banner-subtitle">{s}</div>' if s else ""
    st.markdown(
        f"""
        <div class="otc-page-banner">
            <div class="otc-page-banner-kicker">Risk Workbench</div>
            <div class="otc-page-banner-title">{t}</div>
            {sub_html}
        </div>
        """,
        unsafe_allow_html=True,
    )


def render_section_header(title: str, subtitle: str = "") -> None:
    t = str(title or "").strip()
    s = str(subtitle or "").strip()
    if not t:
        return
    sub_html = f'<div class="otc-section-head-sub">{s}</div>' if s else ""
    st.markdown(
        f"""
        <div class="otc-section-head">
            <div class="otc-section-head-main">{t}</div>
            {sub_html}
        </div>
        """,
        unsafe_allow_html=True,
    )


def render_hidden_title_sync_widget() -> str:
    """Hidden bridge widget: allows frontend JS to sync title to backend state."""
    raw = st.text_input(TITLE_SYNC_WIDGET_LABEL, key=TITLE_SYNC_WIDGET_KEY, label_visibility="collapsed")
    st.markdown(
        f"""
        <style>
        div[data-testid="stTextInput"]:has(input[aria-label="{TITLE_SYNC_WIDGET_LABEL}"]) {{
            display: none !important;
        }}
        </style>
        """,
        unsafe_allow_html=True,
    )
    return str(raw or "")


def inject_editable_app_title(default_title: str) -> None:
    """Allow double-click editing on the main title and persist to browser/local DB."""
    default_title_json = json.dumps(str(default_title or APP_TITLE_DEFAULT), ensure_ascii=False)
    sync_input_aria_json = json.dumps(TITLE_SYNC_WIDGET_LABEL, ensure_ascii=False)
    components.html(
        f"""
        <script>
        (() => {{
          const STORE_KEY = "otc_app_runtime_title";
          const TITLE_SYNC_PARAM = "otc_title_update";
          const DEFAULT_TITLE = {default_title_json};
          const TITLE_SYNC_INPUT_ARIA = {sync_input_aria_json};
          const ICON_TOKEN_MAP = {{
            keyboard_double_arrow_right: "»",
            keyboard_arrow_right: "›",
            keyboard_arrow_left: "‹",
            keyboard_arrow_down: "▾",
            keyboard_arrow_up: "▴",
            arrow_right_alt: "›",
            arrow_left_alt: "‹",
            arrow_drop_down: "▾",
            arrow_drop_up: "▴",
            chevron_right: "›",
            chevron_left: "‹",
            chevron_down: "▾",
            chevron_up: "▴",
            expand_more: "▾",
            expand_less: "▴",
            search: "⌕",
            download: "↓",
            visibility: "◉",
            visibility_off: "◎",
            more_vert: "⋮",
            close: "×",
          }};
          function rootDoc() {{
            try {{ return window.parent.document; }} catch (e) {{ return document; }}
          }}
          function _safeStorage(winObj) {{
            try {{
              if (!winObj || !winObj.localStorage) return null;
              return winObj.localStorage;
            }} catch (e) {{
              return null;
            }}
          }}
          function _candidateStorages() {{
            const out = [];
            const p = (() => {{ try {{ return window.parent; }} catch (e) {{ return null; }} }})();
            const s1 = _safeStorage(p);
            const s2 = _safeStorage(window);
            if (s1) out.push(s1);
            if (s2 && s2 !== s1) out.push(s2);
            return out;
          }}
          function ensureMaterialFonts(d) {{
            if (!d || !d.head) return;
            const links = [
              {{
                id: "otc-material-symbols",
                href: "https://fonts.googleapis.com/css2?family=Material+Symbols+Rounded:opsz,wght,FILL,GRAD@20..48,100..700,0..1,-50..200",
              }},
              {{
                id: "otc-material-icons",
                href: "https://fonts.googleapis.com/icon?family=Material+Icons",
              }},
            ];
            links.forEach((cfg) => {{
              if (d.getElementById(cfg.id)) return;
              const link = d.createElement("link");
              link.id = cfg.id;
              link.rel = "stylesheet";
              link.href = cfg.href;
              d.head.appendChild(link);
            }});
          }}
          function patchIconTextFallback(d) {{
            if (!d) return;
            const nodes = d.querySelectorAll("span, i");
            const inferIconGlyph = (token) => {{
              const t = String(token || "").toLowerCase();
              if (!t) return "";
              if (t.includes("down")) return "▾";
              if (t.includes("up")) return "▴";
              if (t.includes("left")) return "‹";
              if (t.includes("right")) return "›";
              if (t.includes("search")) return "⌕";
              if (t.includes("download")) return "↓";
              if (t.includes("visibility_off")) return "◎";
              if (t.includes("visibility")) return "◉";
              if (t.includes("more")) return "⋮";
              if (t.includes("close")) return "×";
              return "";
            }};
            nodes.forEach((el) => {{
              if (!el || (el.children && el.children.length > 0)) return;
              const raw = String(el.textContent || "").trim();
              if (!raw || raw.length > 40) return;
              const cls = String(el.className || "");
              const tid = String(el.getAttribute("data-testid") || "");
              const looksLikeIcon =
                /material|icon/i.test(cls) ||
                /stIconMaterial/i.test(tid) ||
                /^[a-z0-9_]+$/i.test(raw) ||
                raw.startsWith("keyboard_");
              if (!looksLikeIcon) return;
              const mapped = ICON_TOKEN_MAP[raw] || inferIconGlyph(raw);
              if (!mapped) return;
              el.textContent = mapped;
              el.style.fontFamily = "\\"Source Han Sans SC\\",\\"PingFang SC\\",\\"Microsoft YaHei\\",sans-serif";
              el.style.fontWeight = "700";
              el.style.letterSpacing = "0";
            }});
          }}
          function readSavedTitle() {{
            const stores = _candidateStorages();
            for (const stg of stores) {{
              try {{
                const v = (stg.getItem(STORE_KEY) || "").trim();
                if (v) return v;
              }} catch (e) {{}}
            }}
            return "";
          }}
          function writeSavedTitle(v) {{
            const stores = _candidateStorages();
            for (const stg of stores) {{
              try {{ stg.setItem(STORE_KEY, v); }} catch (e) {{}}
            }}
          }}
          function syncTitleViaHiddenInput(v) {{
            const clean = String(v || "").trim();
            if (!clean) return false;
            const d = rootDoc();
            if (!d) return false;
            const input = d.querySelector(`input[aria-label="${{TITLE_SYNC_INPUT_ARIA}}"]`);
            if (!input) return false;
            try {{
              const w = d.defaultView || window;
              const setter =
                (w && w.HTMLInputElement && Object.getOwnPropertyDescriptor(w.HTMLInputElement.prototype, "value")?.set) ||
                Object.getOwnPropertyDescriptor(HTMLInputElement.prototype, "value")?.set;
              if (setter) {{
                setter.call(input, clean);
              }} else {{
                input.value = clean;
              }}
              input.dispatchEvent(new Event("input", {{ bubbles: true }}));
              input.dispatchEvent(new Event("change", {{ bubbles: true }}));
              return true;
            }} catch (e) {{
              return false;
            }}
          }}
          function syncTitleToServer(v) {{
            const clean = String(v || "").trim();
            if (!clean) return;
            // 双通道同步：先尝试隐藏输入触发后端，再使用 URL 参数兜底。
            // 某些部署环境里，隐藏输入事件可能不触发重跑，不能提前 return。
            syncTitleViaHiddenInput(clean);
            let loc = null;
            try {{
              loc = window.parent.location;
            }} catch (e) {{
              loc = window.location;
            }}
            if (!loc || !loc.href) return;
            try {{
              const u = new URL(loc.href);
              u.searchParams.set(TITLE_SYNC_PARAM, clean);
              if (typeof loc.replace === "function") {{
                loc.replace(u.toString());
              }} else {{
                loc.href = u.toString();
              }}
            }} catch (e) {{}}
          }}
          function applyTitle() {{
            const d = rootDoc();
            if (!d) return;
            ensureMaterialFonts(d);
            patchIconTextFallback(d);
            const h1 = d.querySelector("[data-testid='stAppViewContainer'] h1");
            if (!h1) return;
            const saved = readSavedTitle();
            const finalTitle = saved || DEFAULT_TITLE;
            if ((h1.textContent || "").trim() !== finalTitle) {{
              h1.textContent = finalTitle;
            }}
            try {{ d.title = finalTitle; }} catch (e) {{}}
            if (saved && saved !== DEFAULT_TITLE && !window.__otcTitleAutoSyncDone) {{
              window.__otcTitleAutoSyncDone = true;
              syncTitleToServer(saved);
            }}
            h1.style.cursor = "text";
            h1.title = "双击可编辑标题";
            if (h1.dataset.dblEditableBound === "1") return;
            h1.dataset.dblEditableBound = "1";
            h1.addEventListener("dblclick", () => {{
              const cur = (h1.textContent || "").trim() || DEFAULT_TITLE;
              const next = window.prompt("请输入系统标题", cur);
              if (next === null) return;
              const clean = String(next || "").trim();
              if (!clean) return;
              writeSavedTitle(clean);
              h1.textContent = clean;
              try {{ d.title = clean; }} catch (e) {{}}
              syncTitleToServer(clean);
            }});
          }}
          applyTitle();
          try {{
            const d = rootDoc();
            if (d && d.body) {{
              const ob = new MutationObserver(() => applyTitle());
              ob.observe(d.body, {{ childList: true, subtree: true }});
            }}
          }} catch (e) {{}}
          setInterval(applyTitle, 700);
        }})();
        </script>
        """,
        height=0,
        width=0,
    )


def inject_structure_quote_numeric_input_polish() -> None:
    target_labels = [
        "交易日数量",
        "每日基准量（吨/交易日）",
        "总量（吨）",
        "TRS头寸（吨）",
        "结构时间期数",
        "锁定前几次敲出观察",
        "名义本金（万）",
        "名义规模（吨）",
        "入场价",
        "行权价",
        "敲入价",
        "障碍价",
        "敲出价",
        "熔断行权价",
        "每吨补贴金额",
        "参与率（%）",
        "票息（%）",
        "A阶段观察次数",
        "B阶段观察次数",
        "A阶段票息（%）",
        "B阶段票息（%）",
        "敲出观察价（%）",
        "敲出观察价（绝对价）",
        "敲入观察价（%）",
        "敲入观察价（绝对价）",
        "折价价（转期货开仓价）",
    ]
    target_labels_json = json.dumps(target_labels, ensure_ascii=False)
    components.html(
        f"""
        <script>
        (() => {{
          const TARGET_LABELS = new Set({target_labels_json});
          function rootDoc() {{
            try {{ return window.parent.document; }} catch (e) {{ return document; }}
          }}
          function onStructureEntryPage(d) {{
            if (!d) return false;
            return Array.from(d.querySelectorAll(".otc-page-banner-title"))
              .some((el) => String(el.textContent || "").trim() === "结构录入");
          }}
          function labelText(widget) {{
            if (!widget) return "";
            const p = widget.querySelector("label[data-testid='stWidgetLabel'] p");
            return String((p && p.textContent) || "").trim();
          }}
          function currentStructureId(d) {{
            if (!d) return "__draft__";
            const widgets = d.querySelectorAll("div[data-testid='stTextInput']");
            for (const widget of widgets) {{
              if (labelText(widget) !== "结构编号") continue;
              const input = widget.querySelector("input:not([type='hidden'])");
              const value = String((input && input.value) || "").trim();
              return value || "__draft__";
            }}
            return "__draft__";
          }}
          function dirtyStoreKey(d, label) {{
            return `otc_quote_input_dirty::${{currentStructureId(d)}}::${{String(label || "").trim()}}`;
          }}
          function selectAll(input) {{
            if (!input) return;
            try {{
              input.focus({{ preventScroll: true }});
              input.select();
              if (typeof input.setSelectionRange === "function") {{
                input.setSelectionRange(0, String(input.value || "").length);
              }}
            }} catch (e) {{}}
          }}
          function bindWidget(widget) {{
            if (!widget) return;
            const d = rootDoc();
            const label = labelText(widget);
            if (!TARGET_LABELS.has(label)) return;
            const input = widget.querySelector("input:not([type='hidden'])");
            if (!input || input.dataset.otcQuoteInputBound === "1") return;
            input.dataset.otcQuoteInputBound = "1";
            input.dataset.otcInitialValue = String(input.value || "");
            try {{
              if (window.sessionStorage && sessionStorage.getItem(dirtyStoreKey(d, label)) === "1") {{
                input.dataset.otcDirty = "1";
              }}
            }} catch (e) {{}}
            const activate = () => {{
              const docNow = rootDoc();
              const currentVal = String(input.value || "");
              const initialVal = String(input.dataset.otcInitialValue || "");
              let alreadyDirty = input.dataset.otcDirty === "1";
              try {{
                alreadyDirty = alreadyDirty || (window.sessionStorage && sessionStorage.getItem(dirtyStoreKey(docNow, label)) === "1");
              }} catch (e) {{}}
              if (!alreadyDirty && currentVal === initialVal && currentVal !== "") {{
                input.dataset.otcAutoCleared = "1";
                input.value = "";
              }}
              window.requestAnimationFrame(() => selectAll(input));
            }};
            input.addEventListener("focus", () => setTimeout(activate, 0));
            input.addEventListener("click", () => setTimeout(activate, 0));
            input.addEventListener("input", () => {{
              const docNow = rootDoc();
              const cur = String(input.value || "");
              const initialVal = String(input.dataset.otcInitialValue || "");
              if (cur !== "" && cur !== initialVal) {{
                input.dataset.otcDirty = "1";
                input.dataset.otcAutoCleared = "0";
                try {{
                  if (window.sessionStorage) {{
                    sessionStorage.setItem(dirtyStoreKey(docNow, label), "1");
                  }}
                }} catch (e) {{}}
              }}
            }});
            input.addEventListener("blur", () => {{
              const docNow = rootDoc();
              const cur = String(input.value || "");
              let alreadyDirty = input.dataset.otcDirty === "1";
              try {{
                alreadyDirty = alreadyDirty || (window.sessionStorage && sessionStorage.getItem(dirtyStoreKey(docNow, label)) === "1");
              }} catch (e) {{}}
              if (!alreadyDirty && input.dataset.otcAutoCleared === "1" && cur === "") {{
                input.value = String(input.dataset.otcInitialValue || "");
              }}
              input.dataset.otcAutoCleared = "0";
            }});
          }}
          function patch() {{
            const d = rootDoc();
            if (!onStructureEntryPage(d)) return;
            const widgets = d.querySelectorAll("div[data-testid='stTextInput'], div[data-testid='stNumberInput']");
            widgets.forEach((widget) => bindWidget(widget));
          }}
          patch();
          try {{
            const d = rootDoc();
            if (d && d.body) {{
              const ob = new MutationObserver(() => patch());
              ob.observe(d.body, {{ childList: true, subtree: true }});
            }}
          }} catch (e) {{}}
          setInterval(patch, 700);
        }})();
        </script>
        """,
        height=0,
        width=0,
    )


def _apply_spec_defaults(spec: StructureSpec, prefix: str) -> None:
    def _f(field_name: str, v: Any, default: float = 0.0) -> float:
        return _resolve_form_field_numeric_value(prefix, field_name, v, default)

    for field, default in spec.defaults.items():
        if field == "meta_json":
            continue
        key = f"{prefix}_{field}"
        manual_key = f"{key}_manual"

        multiple_mode = "manual" if spec.code == "SAFETY_AIRBAG" else str(spec.defaults.get("multiple_mode", "select")).strip().lower()
        # 参与率字段：默认下拉（累计结构），安全气囊使用手工输入。
        if field == "multiple":
            if multiple_mode == "manual":
                if key not in st.session_state:
                    try:
                        st.session_state[key] = float(default)
                    except Exception:
                        st.session_state[key] = 80.0
                else:
                    try:
                        st.session_state[key] = float(st.session_state[key])
                    except Exception:
                        st.session_state[key] = 80.0
            else:
                if key not in st.session_state:
                    try:
                        st.session_state[key] = int(round(float(default)))
                    except Exception:
                        st.session_state[key] = 3
            continue

        if isinstance(default, tuple) and len(default) == 2 and str(default[1]).upper() == "LINK":
            src = str(default[0])
            src_key = f"{prefix}_{src}"
            if src_key in st.session_state:
                src_val = _f(src, st.session_state[src_key], 0.0)
                if key not in st.session_state:
                    st.session_state[key] = f"{src_val:.4f}"
                elif not st.session_state.get(manual_key, False):
                    cur_val = _f(field, st.session_state[key], src_val)
                    prev_key = f"{key}_prev"
                    prev_val = _f(field, st.session_state.get(prev_key), cur_val) if prev_key in st.session_state else cur_val
                    # 仅当“该字段本身”发生变化时，才标记为手工输入。
                    if abs(cur_val - prev_val) > 1e-12:
                        st.session_state[manual_key] = True
                    else:
                        st.session_state[key] = f"{src_val:.4f}"
        else:
            if key not in st.session_state:
                try:
                    st.session_state[key] = f"{float(default):.4f}"
                except Exception:
                    st.session_state[key] = "0.0000"

    # 安全气囊：入场价变动时，行权价始终重新覆盖（即使此前行权价被手改）。
    if spec.code == "SAFETY_AIRBAG":
        entry_key = f"{prefix}_entry_price"
        strike_key = f"{prefix}_strike_price"
        sync_key = f"{prefix}_airbag_entry_last_sync"
        if entry_key in st.session_state and strike_key in st.session_state:
            entry_val = _f("entry_price", st.session_state.get(entry_key), 0.0)
            prev_entry_val = _f("entry_price", st.session_state.get(sync_key), entry_val)
            strike_cur_val = _f("strike_price", st.session_state.get(strike_key), 0.0)
            if sync_key not in st.session_state and abs(strike_cur_val) <= 1e-12 and abs(entry_val) > 1e-12:
                st.session_state[strike_key] = f"{entry_val:.4f}"
            if abs(entry_val - prev_entry_val) > 1e-12:
                st.session_state[strike_key] = f"{entry_val:.4f}"
                st.session_state[f"{strike_key}_manual"] = False
            st.session_state[sync_key] = float(entry_val)

    # FLOAT_KO：障碍价与熔断价同口径，录入页隐藏障碍价，始终跟随熔断价。
    if spec.code == "FLOAT_KO":
        knock_out_key = f"{prefix}_knock_out_price"
        barrier_key = f"{prefix}_barrier_out"
        if knock_out_key in st.session_state:
            knock_out_val = _f("knock_out_price", st.session_state.get(knock_out_key), 0.0)
            st.session_state[barrier_key] = f"{knock_out_val:.4f}"
            st.session_state[f"{barrier_key}_manual"] = False


def _safe_float_from_text(v: Any, default: float = 0.0) -> float:
    try:
        return float(str(v).strip())
    except Exception:
        return float(default)


RELATIVE_PRICE_INPUT_FIELDS: set[str] = {"strike_price", "barrier_in", "barrier_out", "knock_out_price", "ko_strike_price"}
RELATIVE_PRICE_INPUT_HELP = "支持输入绝对价，或输入 +40 / -40 按入场价快捷换算；换算后会自动回填绝对价。"


def _is_relative_price_expression(v: Any) -> bool:
    return bool(re.fullmatch(r"\s*[+-]\s*\d+(?:\.\d+)?\s*", str(v or "").strip()))


def _parse_relative_price_value(v: Any, *, entry_price: Optional[float], default: float = 0.0) -> float:
    txt = str(v or "").strip()
    if not txt:
        return float(default)
    m = re.fullmatch(r"([+-])\s*(\d+(?:\.\d+)?)", txt)
    if m and entry_price is not None:
        delta = float(m.group(2))
        base = float(entry_price)
        return base + delta if m.group(1) == "+" else base - delta
    return _safe_float_from_text(txt, default)


def _relative_price_pending_key(widget_key: str) -> str:
    return f"{str(widget_key)}__resolved_abs_pending"


def _apply_pending_relative_price_value(widget_key: str, *, fmt: str = "%.4f") -> None:
    pending_key = _relative_price_pending_key(widget_key)
    if pending_key not in st.session_state:
        return
    pending_val = st.session_state.pop(pending_key)
    try:
        st.session_state[widget_key] = fmt % float(pending_val)
    except Exception:
        st.session_state[widget_key] = str(pending_val or "")


def _schedule_relative_price_rewrite(widget_key: str, raw_value: Any, resolved_value: Any, *, fmt: str = "%.4f") -> bool:
    if not _is_relative_price_expression(raw_value):
        return False
    try:
        st.session_state[_relative_price_pending_key(widget_key)] = fmt % float(resolved_value)
    except Exception:
        st.session_state[_relative_price_pending_key(widget_key)] = str(pick_first(resolved_value, "") or "")
    return True


def _resolve_form_field_numeric_value(prefix: str, field: str, raw_value: Any, default: float = 0.0) -> float:
    field_s = str(field or "").strip()
    if field_s == "entry_price":
        return _safe_float_from_text(raw_value, default)
    if field_s in RELATIVE_PRICE_INPUT_FIELDS:
        entry_key = f"{prefix}_entry_price"
        entry_price = _safe_float_from_text(st.session_state.get(entry_key), default)
        return _parse_relative_price_value(raw_value, entry_price=entry_price, default=default)
    return _safe_float_from_text(raw_value, default)


def _build_relative_price_ratio_caption(raw_value: Any, resolved_value: Any, entry_price: Any) -> str:
    entry_f = to_float(entry_price)
    resolved_f = to_float(resolved_value)
    if entry_f is None or resolved_f is None or abs(float(entry_f)) <= 1e-12:
        return ""
    ratio_pct = float(resolved_f) / float(entry_f) * 100.0
    raw_txt = str(raw_value or "").strip()
    if raw_txt and (not _is_relative_price_expression(raw_txt)) and to_float(raw_txt) is None:
        return ""
    if _is_relative_price_expression(raw_txt):
        return (
            f"按入场价 {float(entry_f):,.4f} 快速换算后：{float(resolved_f):,.4f}；"
            f"对应比例 {ratio_pct:.2f}%"
        )
    return f"对应比例：{ratio_pct:.2f}%"


def _ensure_text_input_numeric_state(key: str, default_value: Any, *, fmt: str = "%.4f") -> None:
    if key not in st.session_state:
        try:
            st.session_state[key] = fmt % float(default_value)
        except Exception:
            st.session_state[key] = str(pick_first(default_value, "") or "")
        return
    cur = st.session_state.get(key)
    if isinstance(cur, str):
        return
    try:
        st.session_state[key] = fmt % float(cur)
    except Exception:
        st.session_state[key] = str(pick_first(cur, "") or "")


def render_relative_price_text_input(
    label: str,
    key: str,
    *,
    entry_price: Any,
    default_value: Any,
    min_value: Optional[float] = None,
    fmt: str = "%.4f",
    help_text: Optional[str] = None,
) -> float:
    _apply_pending_relative_price_value(key, fmt=fmt)
    _ensure_text_input_numeric_state(key, default_value, fmt=fmt)
    raw_txt = st.text_input(label, key=key, help=help_text or RELATIVE_PRICE_INPUT_HELP)
    value = _parse_relative_price_value(raw_txt, entry_price=to_float(entry_price), default=float(pick_first(to_float(default_value), 0.0) or 0.0))
    if min_value is not None:
        value = max(float(value), float(min_value))
    if _schedule_relative_price_rewrite(key, raw_txt, value, fmt=fmt):
        st.rerun()
    caption_txt = _build_relative_price_ratio_caption(raw_txt, value, entry_price)
    render_aligned_field_hint(caption_txt)
    return float(value)


def render_aligned_field_hint(text: Optional[str] = None) -> None:
    hint = str(text or "").strip()
    hint_html = html.escape(hint) if hint else "&nbsp;"
    title_attr = f' title="{html.escape(hint)}"' if hint else ""
    class_name = "otc-inline-field-hint" if hint else "otc-inline-field-hint otc-inline-field-hint-empty"
    st.markdown(
        f'<div class="{class_name}"{title_attr}>{hint_html}</div>',
        unsafe_allow_html=True,
    )


def next_structure_id_for_group(conn: sqlite3.Connection, group_id: str) -> str:
    # structure_id 在当前库模型下是全局主键，编号需全局递增，避免跨组冲突覆盖。
    df = pd.read_sql_query("SELECT structure_id FROM structure ORDER BY structure_id", conn)
    mx = 0
    for sid in df["structure_id"].astype(str).tolist():
        digits = "".join(ch for ch in sid if ch.isdigit())
        if digits:
            try:
                mx = max(mx, int(digits))
            except Exception:
                pass
    return f"S{mx + 1:03d}"


def next_strategy_group_id(conn: sqlite3.Connection, prefix: str = "G") -> str:
    prefix_txt = str(prefix or "G").strip().upper() or "G"
    try:
        df = pd.read_sql_query("SELECT group_id FROM strategy_group ORDER BY group_id", conn)
    except Exception:
        df = pd.DataFrame(columns=["group_id"])
    used: set[int] = set()
    if not df.empty and "group_id" in df.columns:
        for gid in df["group_id"].astype(str).tolist():
            gid_txt = str(gid or "").strip().upper()
            if not gid_txt.startswith(prefix_txt):
                continue
            suffix = gid_txt[len(prefix_txt):]
            if suffix.isdigit():
                try:
                    used.add(int(suffix))
                except Exception:
                    pass
    nxt = 1
    while nxt in used:
        nxt += 1
    return f"{prefix_txt}{nxt:03d}"


def structure_display_label(structure_id: Any, name: Any, risk_party: Any) -> str:
    sid = str(pick_first(structure_id, "")).strip()
    nm = str(pick_first(name, "")).strip()
    rp = str(pick_first(risk_party, "")).strip()
    if rp:
        return f"{sid}-{nm}-{rp}"
    return f"{sid}-{nm}"


def _fmt_price_for_detail_label(v: Any) -> str:
    fv = to_float(v)
    if fv is None:
        return "-"
    txt = f"{float(fv):.4f}".rstrip("0").rstrip(".")
    return txt if txt else "0"


def build_trs_structure_name(underlying: Any, kind_code: Any, entry_price: Any) -> str:
    und = str(pick_first(underlying, "")).strip().upper() or "UNKNOWN"
    kind_u = normalize_kind_code(kind_code)
    side_cn = "看涨" if kind_u == "ACC" else "看跌" if kind_u == "DEC" else "中性"
    px_txt = _fmt_price_for_detail_label(entry_price)
    return f"{und}-{side_cn}-{px_txt}-TRS"


def upsert_trs_structure_row(
    conn: sqlite3.Connection,
    *,
    structure_id: str,
    group_id: str,
    underlying: str,
    risk_party: str,
    kind_code: str,
    start_date_s: str,
    end_date_s: str,
    entry_price: float,
    trs_qty: float,
) -> None:
    sid = str(structure_id).strip()
    gid = str(group_id).strip()
    und = _normalize_underlying_symbol(underlying)
    risk = str(risk_party or "").strip() or "海证资本"
    kind_u = normalize_kind_code(kind_code)
    ep = float(pick_first(to_float(entry_price), 0.0) or 0.0)
    qty = max(float(pick_first(to_float(trs_qty), 0.0) or 0.0), 0.0)
    params_json = {
        "trs_position_qty": float(qty),
        "multiplier": 1.0,
        "subsidy_per_ton": 0.0,
    }
    meta_json: Dict[str, Any] = {}
    name = build_trs_structure_name(und, kind_u, ep)
    conn.execute(
        """
        INSERT INTO structure(
            structure_id, group_id, name, underlying, risk_party, kind, strategy, strategy_code,
            start_date, end_date, base_qty_per_day,
            gen_price, entry_price, strike_price, barrier_in, barrier_out, knock_out_price, ko_strike_price, multiple,
            barrier_price, melt_price, melt_strike,
            total_cap_qty, daily_cap_qty, params_json, meta_json
        )
        VALUES(?,?,?,?,?,?,?,?,?,?,?,?,?,?,?,?,?,?,?,?,?,?,?,?,?,?)
        ON CONFLICT(structure_id) DO UPDATE SET
            group_id=excluded.group_id,
            name=excluded.name,
            underlying=excluded.underlying,
            risk_party=excluded.risk_party,
            kind=excluded.kind,
            strategy=excluded.strategy,
            strategy_code=excluded.strategy_code,
            start_date=excluded.start_date,
            end_date=excluded.end_date,
            base_qty_per_day=excluded.base_qty_per_day,
            gen_price=excluded.gen_price,
            entry_price=excluded.entry_price,
            strike_price=excluded.strike_price,
            barrier_in=excluded.barrier_in,
            barrier_out=excluded.barrier_out,
            knock_out_price=excluded.knock_out_price,
            ko_strike_price=excluded.ko_strike_price,
            multiple=excluded.multiple,
            barrier_price=excluded.barrier_price,
            melt_price=excluded.melt_price,
            melt_strike=excluded.melt_strike,
            params_json=excluded.params_json,
            meta_json=excluded.meta_json
        """,
        (
            sid,
            gid,
            name,
            und,
            risk,
            kind_u,
            "TRS",
            "TRS",
            str(start_date_s),
            str(end_date_s),
            float(qty),
            float(ep),
            float(ep),
            float(ep),
            None,
            None,
            None,
            None,
            1.0,
            None,
            None,
            None,
            None,
            None,
            json.dumps(params_json, ensure_ascii=False),
            json.dumps(meta_json, ensure_ascii=False),
        ),
    )


def structure_price_detail_label(
    structure_id: Any,
    name: Any,
    risk_party: Any,
    entry_price: Any,
    strike_price: Any,
) -> str:
    sid = str(pick_first(structure_id, "")).strip()
    nm = str(pick_first(name, "")).strip()
    rp = str(pick_first(risk_party, "")).strip()
    ep_txt = _fmt_price_for_detail_label(entry_price)
    sp_txt = _fmt_price_for_detail_label(strike_price)
    head = "-".join([x for x in [sid, nm, rp] if str(x).strip()])
    tail = f"入场价（{ep_txt}）-行权价（{sp_txt}）"
    return f"{head}-{tail}" if head else tail


def resolve_display_barrier_price(
    strategy_value: Any,
    *,
    barrier_out: Any = None,
    barrier_in: Any = None,
    strike_price: Any = None,
) -> Any:
    """统一结构详情中的障碍/敲入价格展示口径。"""
    strategy_code = resolve_strategy_code_for_display(strategy_value)
    if strategy_code == "SNOWBALL":
        return pick_first(barrier_in, barrier_out, strike_price)
    if strategy_code == "SAFETY_AIRBAG":
        return pick_first(barrier_out, barrier_in, strike_price)
    return pick_first(barrier_out, barrier_in, strike_price)


def structure_detail_label_unified(
    structure_id: Any,
    strategy_value: Any,
    kind_value: Any,
    fallback_name: Any,
    risk_party: Any,
    entry_price: Any,
    strike_price: Any,
    knock_in_price: Any = None,
    barrier_price: Any = None,
) -> str:
    strategy_code = resolve_strategy_code_for_display(strategy_value)
    kind_code = normalize_kind_code(kind_value)
    name_norm = default_structure_name(
        strategy_value,
        kind_value,
        fallback_name=str(pick_first(fallback_name, "")),
    )
    # 兜底识别：部分历史流程未透传 strategy_code，但名称中包含“安全气囊”。
    is_airbag = (strategy_code == "SAFETY_AIRBAG") or ("安全气囊" in str(name_norm))
    if is_airbag:
        sid = str(pick_first(structure_id, "")).strip()
        rp = str(pick_first(risk_party, "")).strip()
        ep_txt = _fmt_price_for_detail_label(entry_price)
        # 安全气囊口径：障碍价优先使用 barrier_out（传入 barrier_price），兜底旧数据。
        barrier_txt = _fmt_price_for_detail_label(pick_first(barrier_price, knock_in_price, strike_price))
        if kind_code == "ACC":
            tail = f"障碍价（{barrier_txt}）-入场价（{ep_txt}）"
        else:
            tail = f"入场价（{ep_txt}）-障碍价（{barrier_txt}）"
        head = "-".join([x for x in [sid, name_norm, rp] if str(x).strip()])
        return f"{head}-{tail}" if head else tail
    if strategy_code == "SNOWBALL":
        sid = str(pick_first(structure_id, "")).strip()
        rp = str(pick_first(risk_party, "")).strip()
        ep_txt = _fmt_price_for_detail_label(entry_price)
        ki_txt = _fmt_price_for_detail_label(pick_first(knock_in_price, strike_price))
        if kind_code == "ACC":
            tail = f"敲入价（{ki_txt}）-入场价（{ep_txt}）"
        else:
            tail = f"入场价（{ep_txt}）-敲入价（{ki_txt}）"
        head = "-".join([x for x in [sid, name_norm, rp] if str(x).strip()])
        return f"{head}-{tail}" if head else tail
    if strategy_code == "TRS":
        sid = str(pick_first(structure_id, "")).strip()
        rp = str(pick_first(risk_party, "")).strip()
        ep_txt = _fmt_price_for_detail_label(entry_price)
        head = "-".join([x for x in [sid, name_norm, rp] if str(x).strip()])
        tail = f"入场价（{ep_txt}）"
        return f"{head}-{tail}" if head else tail
    return structure_price_detail_label(
        structure_id=structure_id,
        name=name_norm,
        risk_party=risk_party,
        entry_price=entry_price,
        strike_price=strike_price,
    )


def add_structure_label_column(
    df: pd.DataFrame,
    *,
    id_col: str,
    name_col: str,
    risk_col: str,
    out_col: str = "结构",
    strategy_col: Optional[str] = None,
    kind_col: Optional[str] = None,
    entry_col: Optional[str] = None,
    strike_col: Optional[str] = None,
    barrier_col: Optional[str] = None,
) -> pd.DataFrame:
    """为表格补一列统一结构标签：结构编号-结构名称-风险子。"""
    out = df.copy()
    if out.empty:
        if out_col not in out.columns:
            out[out_col] = ""
        return out
    if id_col not in out.columns:
        if out_col not in out.columns:
            out[out_col] = ""
        return out
    if name_col not in out.columns:
        out[name_col] = ""
    if risk_col not in out.columns:
        out[risk_col] = ""
    if strategy_col and strategy_col not in out.columns:
        out[strategy_col] = ""
    if kind_col and kind_col not in out.columns:
        out[kind_col] = ""
    if entry_col and entry_col not in out.columns:
        out[entry_col] = None
    if strike_col and strike_col not in out.columns:
        out[strike_col] = None
    if barrier_col and barrier_col not in out.columns:
        out[barrier_col] = None

    def _build_label(rr: pd.Series) -> str:
        sid_v = rr.get(id_col, "")
        nm_v = rr.get(name_col, "")
        rp_v = rr.get(risk_col, "")
        strategy_v = rr.get(strategy_col, "") if strategy_col else ""
        kind_v = rr.get(kind_col, "") if kind_col else ""
        name_v = default_structure_name(strategy_v, kind_v, fallback_name=str(nm_v))
        if entry_col or strike_col:
            return structure_detail_label_unified(
                structure_id=sid_v,
                strategy_value=strategy_v,
                kind_value=kind_v,
                fallback_name=nm_v,
                risk_party=rp_v,
                entry_price=rr.get(entry_col, None) if entry_col else None,
                strike_price=rr.get(strike_col, None) if strike_col else None,
                barrier_price=rr.get(barrier_col, None) if barrier_col else None,
            )
        return structure_display_label(sid_v, name_v, rp_v)

    out[out_col] = out.apply(
        _build_label,
        axis=1,
    )
    return out


def drop_structure_name_if_duplicated(
    df: pd.DataFrame,
    *,
    name_col: str = "结构名称",
    detail_cols: Optional[List[str]] = None,
) -> pd.DataFrame:
    out = df.copy()
    detail_cols = detail_cols or ["结构", "结构详情"]
    if name_col not in out.columns:
        return out
    if any(c in out.columns for c in detail_cols):
        out = out.drop(columns=[name_col], errors="ignore")
    return out


def structure_verbose_label(
    structure_id: Any,
    name: Any,
    risk_party: Any,
    kind: Any = None,
    underlying: Any = None,
    entry_price: Any = None,
    strike_price: Any = None,
    strategy_value: Any = None,
    knock_in_price: Any = None,
    barrier_price: Any = None,
) -> str:
    resolved_knock_in = pick_first(knock_in_price, barrier_price, strike_price)
    resolved_barrier = resolve_display_barrier_price(
        strategy_value,
        barrier_out=barrier_price,
        barrier_in=knock_in_price,
        strike_price=strike_price,
    )
    return structure_detail_label_unified(
        structure_id=structure_id,
        strategy_value=strategy_value,
        kind_value=kind,
        fallback_name=name,
        risk_party=risk_party,
        entry_price=entry_price,
        strike_price=strike_price,
        knock_in_price=resolved_knock_in,
        barrier_price=resolved_barrier,
    )


def build_structure_table_view(structs_df: pd.DataFrame) -> pd.DataFrame:
    """构建结构录入页右侧结构表的基础展示视图（存续/终止共用）。"""
    if structs_df is None or structs_df.empty:
        return pd.DataFrame()

    sdf = structs_df.copy()
    if "params_json" not in sdf.columns:
        sdf["params_json"] = "{}"
    sdf["subsidy_per_ton"] = sdf["params_json"].apply(
        lambda x: resolve_subsidy_per_ton_from_legacy(parse_json_obj(x, {}), {})
    )
    sdf["方向"] = sdf.apply(
        lambda rr: kind_cn_for_strategy(rr.get("kind"), pick_first(rr.get("strategy_code"), rr.get("strategy"))),
        axis=1,
    )
    sdf["策略类型"] = sdf.apply(
        lambda r: STRATEGY_CODE_TO_CN.get(
            resolve_strategy_code_for_display(pick_first(r.get("strategy_code"), r.get("strategy"))),
            str(pick_first(r.get("strategy_code"), r.get("strategy"))),
        ),
        axis=1,
    )

    show = sdf.rename(
        columns={
            "structure_id": "结构编号",
            "name": "结构名称",
            "underlying": "品种",
            "risk_party": "风险子",
            "start_date": "开始日期",
            "end_date": "结束日期",
            "base_qty_per_day": "每日基准量",
            "entry_price": "入场价",
            "strike_price": "行权价",
            "barrier_out": "障碍价",
            "knock_out_price": "触发价原值",
            "ko_strike_price": "熔断行权价",
            "multiple": "参与倍数",
            "subsidy_per_ton": "每吨补贴金额",
        }
    )[
        [
            "结构编号",
            "结构名称",
            "风险子",
            "方向",
            "策略类型",
            "品种",
            "开始日期",
            "结束日期",
            "每日基准量",
            "入场价",
            "行权价",
            "障碍价",
            "触发价原值",
            "熔断行权价",
            "参与倍数",
            "每吨补贴金额",
        ]
    ]
    show["名义规模（吨）"] = show.apply(
        lambda rr: structure_display_notional_qty(
            rr.get("策略类型", ""),
            rr.get("每日基准量", 0.0),
            rr.get("开始日期", ""),
            rr.get("结束日期", ""),
            entry_price=rr.get("入场价", None),
            params_value=rr.get("params_json", {}),
        ),
        axis=1,
    )
    show = show.drop(columns=["每日基准量"], errors="ignore")
    show = append_trigger_price_display_columns(
        show,
        strategy_col="策略类型",
        trigger_col="触发价原值",
        knock_out_col="敲出价",
        melt_col="熔断价",
    )
    show = show.drop(columns=["触发价原值"], errors="ignore")
    show = add_structure_label_column(
        show,
        id_col="结构编号",
        name_col="结构名称",
        risk_col="风险子",
        out_col="结构",
        strategy_col="策略类型",
        kind_col="方向",
        entry_col="入场价",
        strike_col="行权价",
        barrier_col="障碍价",
    )
    show = drop_structure_name_if_duplicated(show, name_col="结构名称", detail_cols=["结构"])

    if {"策略类型", "参与倍数"}.issubset(set(show.columns)):
        airbag_mask_show = show["策略类型"].astype(str).str.strip().eq("安全气囊")
        if bool(airbag_mask_show.any()):
            if "参与率（%）" not in show.columns:
                show["参与率（%）"] = pd.NA
            show.loc[airbag_mask_show, "参与率（%）"] = pd.to_numeric(
                show.loc[airbag_mask_show, "参与倍数"],
                errors="coerce",
            )
            show.loc[airbag_mask_show, "参与倍数"] = pd.NA

    preferred_cols = [
        "结构编号",
        "结构",
        "风险子",
        "方向",
        "策略类型",
        "品种",
        "开始日期",
        "结束日期",
        "名义规模（吨）",
        "总量（吨）",
        "入场价",
        "行权价",
        "障碍价",
        "敲出价",
        "熔断价",
        "熔断行权价",
        "参与率（%）",
        "参与倍数",
        "每吨补贴金额",
    ]
    show = show[[c for c in preferred_cols if c in show.columns] + [c for c in show.columns if c not in preferred_cols]]
    show["开始日期"] = pd.to_datetime(show["开始日期"], errors="coerce").dt.date
    show["结束日期"] = pd.to_datetime(show["结束日期"], errors="coerce").dt.date
    show["每吨补贴金额"] = pd.to_numeric(show["每吨补贴金额"], errors="coerce").fillna(0.0)
    return show


