            st.caption("支持整图宽度、左右比例、区块高度、列宽、字号、行高、颜色；可写入代码默认值实现永久生效。")

            def _layout_slider(
                param_key: str,
                label: str,
                min_v: float,
                max_v: float,
                step_v: float,
            ) -> float:
                ss_key = f"{_dbg_prefix}{param_key}"
                if ss_key not in st.session_state:
                    st.session_state[ss_key] = float(report_layout_cfg.get(param_key, REPORT_LAYOUT_DEFAULTS.get(param_key, 0.0)))
                raw_val = st.session_state.get(ss_key, report_layout_cfg.get(param_key, min_v))
                try:
                    safe_val = float(raw_val)
                except Exception:
                    safe_val = float(min_v)
                safe_val = max(float(min_v), min(float(max_v), float(safe_val)))
                st.session_state[ss_key] = float(safe_val)
                report_layout_cfg[param_key] = float(safe_val)
                st.slider(
                    label,
                    min_value=float(min_v),
                    max_value=float(max_v),
                    step=float(step_v),
                    key=ss_key,
                )
                val = float(st.session_state.get(ss_key, report_layout_cfg.get(param_key, min_v)))
                val = max(float(min_v), min(float(max_v), float(val)))
                report_layout_cfg[param_key] = float(val)
                return float(val)

            def _layout_color(param_key: str, label: str) -> str:
                ss_key = f"{_dbg_prefix}{param_key}"
                default_color = str(report_layout_cfg.get(param_key, REPORT_LAYOUT_DEFAULTS.get(param_key, "#ffffff")))
                if re.match(r"^#[0-9a-fA-F]{6}$", default_color) is None and re.match(r"^#[0-9a-fA-F]{3}$", default_color) is None:
                    default_color = "#ffffff"
                if ss_key not in st.session_state:
                    st.session_state[ss_key] = default_color
                st.color_picker(label, key=ss_key)
                val = str(st.session_state.get(ss_key, default_color))
                report_layout_cfg[param_key] = str(val)
                return str(val)

            st.markdown("**全局**")
