            def _sync_layout_param(param_key: str, val: float) -> None:
                report_layout_cfg[param_key] = float(val)
                try:
                    st.session_state[f"{_dbg_prefix}{param_key}"] = float(val)
                except Exception:
                    # Streamlit 对“组件已实例化后改写同key”会报错；此处仅保证配置口径更新。
                    pass

            def _uniform_default(keys: List[str], fallback: float) -> float:
                vals: List[float] = []
                for _k in keys:
                    try:
                        vals.append(float(report_layout_cfg.get(_k, REPORT_LAYOUT_DEFAULTS.get(_k, fallback))))
                    except Exception:
                        continue
                return float(sum(vals) / len(vals)) if vals else float(fallback)

            def _uniform_slider(
                uni_key: str,
                label: str,
                keys: List[str],
                min_v: float,
                max_v: float,
                step_v: float,
                fallback: float,
            ) -> float:
                ss_key = f"{_dbg_prefix}u_{uni_key}"
                if ss_key not in st.session_state:
                    st.session_state[ss_key] = _uniform_default(keys, fallback)
                raw_val = st.session_state.get(ss_key, fallback)
                try:
                    safe_val = float(raw_val)
                except Exception:
                    safe_val = float(fallback)
                safe_val = max(float(min_v), min(float(max_v), float(safe_val)))
                st.session_state[ss_key] = float(safe_val)
                st.slider(
                    label,
                    min_value=float(min_v),
                    max_value=float(max_v),
                    step=float(step_v),
                    key=ss_key,
                )
                out_val = float(st.session_state.get(ss_key, fallback))
                out_val = max(float(min_v), min(float(max_v), float(out_val)))
                return float(out_val)

            st.markdown("**三结构统一联动（推荐）**")
